import Link from '../../components/Link';
const _aballonian_resilience = {title: "Aballonian Resilience", topLink: ["Regional Traits","main/traits_regional"], jsx: <><h2 id="trait-aballonian_resilience-aballonian-resilience">Aballonian Resilience</h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> Aballon</p>
<p>You spent at least part of your youth in Horsethroat and are acclimated to the frigid cold of Aballon's Ice Wells. You gain a +4 trait bonus on saves to avoid nonlethal damage from cold environments. In addition, you begin play with a cold-weather outfit at no cost.</p>
<blockquote>
<p><strong>Sources</strong> <Link to="/source/people_of_the_stars">People of the Stars</Link></p>
</blockquote>
</>};
const _abendego_pilot = {title: "Abendego Pilot", topLink: ["Regional Traits","main/traits_regional"], jsx: <><h2 id="trait-abendego_pilot-abendego-pilot">Abendego Pilot</h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> Eye of Abendego<br/><strong>Requirements:</strong> Slyph</p>
<p>The howling gales of the Eye of Abendego were your lullaby as a child, and you quickly learned to anticipate the winds' danger as well as parse their song. You gain a +2 trait bonus on Profession (sailor) checks, and you treat the wind force of environmental wind effects as one step less powerful for the purposes of determining any penalties on ranged attacks and Fly checks as well as whether you would be checked or blown away.</p>
<blockquote>
<p><strong>Sources</strong> <Link to="/source/blood_of_the_elements">Blood of the Elements</Link></p>
</blockquote>
</>};
const _abendego_spellpiercer = {title: "Abendego Spellpiercer", topLink: ["Regional Traits","main/traits_regional"], jsx: <><h2 id="trait-abendego_spellpiercer-abendego-spellpiercer">Abendego Spellpiercer</h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> The Sodden Lands</p>
<p>You have spent time in the gales of the perpetual hurricane, and can cast spells even when battered by the elements. You gain a +2 trait bonus on <Link to="/rule/concentration">concentration</Link> checks when spellcasting.</p>
<blockquote>
<p><strong>Sources</strong> <Link to="/source/inner_sea_primer">Inner Sea Primer</Link></p>
</blockquote>
</>};
const _aberration_hunter = {title: "Aberration Hunter", topLink: ["Regional Traits","main/traits_regional"], jsx: <><h2 id="trait-aberration_hunter-aberration-hunter">Aberration Hunter</h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> Shenmen</p>
<p>You refuse to give in to the monsters that feast on your people, and hunt them instead. You gain a +1 trait bonus on attacks of opportunity against aberrations.</p>
<blockquote>
<p><strong>Sources</strong> <Link to="/source/dragon_empires_primer">Dragon Empires Primer</Link></p>
</blockquote>
</>};
const _abolitionist_hunter = {title: "Abolitionist Hunter", topLink: ["Regional Traits","main/traits_regional"], jsx: <><h2 id="trait-abolitionist_hunter-abolitionist-hunter">Abolitionist Hunter</h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> Okeno</p>
<p>You hunt those who hunt slavers, whether as one of Captain Bhey's special task forces, or independently. You gain a +1 trait bonus on attack rolls when fighting abolitionists or those you have good reason to believe targeted you because of your slaver activities.</p>
<blockquote>
<p><strong>Sources</strong> <Link to="/source/pirates_of_the_inner_sea">Pirates of the Inner Sea</Link></p>
</blockquote>
</>};
const _absalom_hotspur = {title: "Absalom Hotspur", topLink: ["Regional Traits","main/traits_regional"], jsx: <><h2 id="trait-absalom_hotspur-absalom-hotspur">Absalom Hotspur</h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> Absalom</p>
<p>You grew up on the streets of Absalom and have worked as both guide and bodyguard for visitors to the city. You gain a +1 trait bonus on Initiative checks and Knowledge (local) checks.</p>
<blockquote>
<p><strong>Sources</strong> <Link to="/source/inner_sea_primer">Inner Sea Primer</Link></p>
</blockquote>
</>};
const _abyssal_eavesdropper = {title: "Abyssal Eavesdropper", topLink: ["Regional Traits","main/traits_regional"], jsx: <><h2 id="trait-abyssal_eavesdropper-abyssal-eavesdropper">Abyssal Eavesdropper</h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> Sarkoris or The Worldwound</p>
<p>Having grown up near the Worldwound, you have a rough understanding of the demons' guttural babble. You add Abyssal to your list of languages known, though you take a -2 penalty on Diplomacy, Intimidate, and Bluff checks made while speaking Abyssal, as well as a -2 penalty on Linguistics checks made to read Abyssal text. If you gain Abyssal as a language again at a later time (such as by taking a rank in Linguistics and selecting Abyssal as a learned language), these skill check penalties become +2 trait bonuses instead.</p>
<blockquote>
<p><strong>Sources</strong> <Link to="/source/demon_hunters_handbook">Demon Hunter's Handbook</Link></p>
</blockquote>
</>};
const _accustomed_to_trickery = {title: "Accustomed to Trickery", topLink: ["Regional Traits","main/traits_regional"], jsx: <><h2 id="trait-accustomed_to_trickery-accustomed-to-trickery">Accustomed to Trickery</h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> Darkmoon Wood</p>
<p>You have been exposed to fey magic and know tricks to avoid it. Once per day, when you fail a saving throw against a fey's spell-like or supernatural ability, you may reroll the save. You must take the second result, even if it is worse.</p>
<blockquote>
<p><strong>Sources</strong> <Link to="/source/legacy_of_the_first_world">Legacy of the First World</Link></p>
</blockquote>
</>};
const _acolyte_of_razmir = {title: "Acolyte of Razmir", topLink: ["Regional Traits","main/traits_regional"], jsx: <><h2 id="trait-acolyte_of_razmir-acolyte-of-razmir">Acolyte of Razmir</h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> Razmiran</p>
<p>You are an adherent of the Razmiri faith, or once were and have since renounced it. You gain a +1 trait bonus on Knowledge (local) and Knowledge (religion) checks, and one of these skills is always a class skill for you. This bonus increases to +2 when dealing with specifics of the Razmiri faith.</p>
<blockquote>
<p><strong>Sources</strong> <Link to="/source/inner_sea_primer">Inner Sea Primer</Link></p>
</blockquote>
</>};
const _acupuncturist = {title: "Acupuncturist", topLink: ["Regional Traits","main/traits_regional"], jsx: <><h2 id="trait-acupuncturist-acupuncturist">Acupuncturist</h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> Chu Ye</p>
<p>You have studied the ancient art of acupuncture, and use it to pursue enlightenment and healing. You gain a +2 trait bonus on all Fortitude saves made against poison effects.</p>
<blockquote>
<p><strong>Sources</strong> <Link to="/source/dragon_empires_primer">Dragon Empires Primer</Link></p>
</blockquote>
</>};
const _agent_of_the_sultana = {title: "Agent of the Sultana", topLink: ["Regional Traits","main/traits_regional"], jsx: <><h2 id="trait-agent_of_the_sultana-agent-of-the-sultana">Agent of the Sultana</h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> Plane of Earth</p>
<p>You have learned many adventuring skills - as well as hatred for efreet - during your years of military service to Sultana Ashadieeyah bint Khalid, ruler of the Opaline Vault on the Plane of Earth. You gain a +2 trait bonus on Disable Device checks to disarm any traps that you know deal fire damage, and you gain a +2 trait bonus on attack rolls to confirm critical hits against creatures with the fire subtype.</p>
<blockquote>
<p><strong>Sources</strong> <Link to="/source/blood_of_the_elements">Blood of the Elements</Link></p>
</blockquote>
</>};
const _airship_captain = {title: "Airship Captain", topLink: ["Regional Traits","main/traits_regional"], jsx: <><h2 id="trait-airship_captain-airship-captain">Airship Captain</h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> Plane of Air</p>
<p>Your years of piloting airships on the Plane of Air, dodging angry mephits and protecting your passengers from the depredations of capricious elementals, have taught you how to expertly command your vessel, as well as how to arrest yourself even in the midst of the most turbulent planar storms. You gain a +2 trait bonus on Wisdom checks to move in a plane with subjective directional gravity (see the <Link to="/rule/planar_traits">planar rules</Link>) and a +2 trait bonus on driving checks (see the <Link to="/rule/full_vehicle_rules">vehicle rules</Link>).</p>
<blockquote>
<p><strong>Sources</strong> <Link to="/source/blood_of_the_elements">Blood of the Elements</Link></p>
</blockquote>
</>};
const _akitonian_ferocity = {title: "Akitonian Ferocity", topLink: ["Regional Traits","main/traits_regional"], jsx: <><h2 id="trait-akitonian_ferocity-akitonian-ferocity">Akitonian Ferocity</h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> Akiton</p>
<p>You were raised on Akiton, where you were hardened against the ravages of battle. Once per day, the first time you are brought below 0 hit points but not killed, you can fight on for 1 more round as if disabled. At the end of your next turn, unless brought to above 0 hit points, you immediately fall unconscious and begin dying.</p>
<blockquote>
<p><strong>Sources</strong> <Link to="/source/people_of_the_stars">People of the Stars</Link></p>
</blockquote>
</>};
const _alabaster_odalisque = {title: "Alabaster Odalisque", topLink: ["Regional Traits","main/traits_regional"], jsx: <><h2 id="trait-alabaster_odalisque-alabaster-odalisque">Alabaster Odalisque</h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> Jalmeray<br/><strong>Requirements:</strong> Oread</p>
<p>The rajahs of Jalmeray favored you for your stately physique and flawless skin, and so endorsed your candidacy for tutelage at the Conservatory on the island of Grand Sarret. Trained to be the perfect bard, courtesan, or undercover operative, you gain a +1 trait bonus on two Charisma-based skills of your choice. In addition, once per day as a swift action, you can brush your fingers against a closed door or stone wall up to 1 foot thick. Doing so allows you to ignore penalties on Perception checks to listen through the designated object for 1 minute.</p>
<blockquote>
<p><strong>Sources</strong> <Link to="/source/blood_of_the_elements">Blood of the Elements</Link></p>
</blockquote>
</>};
const _alchemical_fence = {title: "Alchemical Fence", topLink: ["Regional Traits","main/traits_regional"], jsx: <><h2 id="trait-alchemical_fence-alchemical-fence">Alchemical Fence</h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> Katapesh</p>
<p>Growing up in the vast markets of Katapesh, you developed connections to a great many alchemists and poisoners all over the world. You know many of the right people in any given locale as well as how to get in touch with useful contacts. When determining whether a given potion is available in a settlement, there is a 90% chance that it is available if it is within the settlement's base value for available magic items rather than a 75% chance. Additionally, when you use Diplomacy to gather information about a topic related to alchemy or poisons (including making poisons), you gain a +3 trait bonus on the check.</p>
<blockquote>
<p><strong>Sources</strong> <Link to="/source/potions_and_poisons">Potions and Poisons</Link></p>
</blockquote>
</>};
const _alchemical_prodigy = {title: "Alchemical Prodigy", topLink: ["Regional Traits","main/traits_regional"], jsx: <><h2 id="trait-alchemical_prodigy-alchemical-prodigy">Alchemical Prodigy</h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> Thuvia</p>
<p>Early on in your life, you showed significant promise in the sciences and alchemical arts, and received extensive tutoring from those seeking to maximize your potential. If you have the alchemy class feature, your alchemist level is considered 1 higher when calculating the duration of your extracts.</p>
<blockquote>
<p><strong>Sources</strong> <Link to="/source/people_of_the_sands">People of the Sands</Link>, <Link to="/source/qadira_gateway_to_the_east">Qadira, Gateway to the East</Link></p>
</blockquote>
</>};
const _alien_origins = {title: "Alien Origins", topLink: ["Regional Traits","main/traits_regional"], jsx: <><h2 id="trait-alien_origins-alien-origins">Alien Origins</h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> Silver Mount</p>
<p>You are in some way tied to the mysterious alien monument known as Silver Mount in Numeria, but you have forgotten an important piece of your past. Perhaps you were a metallurgist's experiment gone awry, a rediscovered automaton that escaped the mountain's confines, or the result of some equally enigmatic phenomenon. Regardless, your unusual origins mark you as somehow different from others, and you know the gaps in your memory hold the key to your past. You start play with a unique compass that doesn't point north and is riddled with indecipherable alien markings - the only object you have that you know to be tied to your home. In addition, your inscrutable mannerisms give you a +2 trait bonus on opposed Bluff checks.</p>
<p><strong>Suggestion:</strong> Consider being a member of the <Link to="/race/android">android race</Link>.*</p>
<blockquote>
<p><strong>Sources</strong> <Link to="/source/dungeoneers_handbook">Dungeoneer's Handbook</Link></p>
</blockquote>
</>};
const _alkenstar_defender = {title: "Alkenstar Defender", topLink: ["Regional Traits","main/traits_regional"], jsx: <><h2 id="trait-alkenstar_defender-alkenstar-defender">Alkenstar Defender</h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> Mana Wastes</p>
<p>You have lived in Alkenstar and served in its militia. You know just where to aim to do the most damage. You gain a +1 trait bonus on all rolls to confirm critical hits with ranged weapons.</p>
<blockquote>
<p><strong>Sources</strong> <Link to="/source/inner_sea_primer">Inner Sea Primer</Link></p>
</blockquote>
</>};
const _alkenstar_engineer = {title: "Alkenstar Engineer", topLink: ["Regional Traits","main/traits_regional"], jsx: <><h2 id="trait-alkenstar_engineer-alkenstar-engineer">Alkenstar Engineer</h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> Mana Wastes</p>
<p>Your extensive experience with firearms allows you to get the most out of those unique weapons. When you're wielding a broken early firearm, the amount your misfire value increases by is reduced by 1.</p>
<blockquote>
<p><strong>Sources</strong> <Link to="/source/people_of_the_wastes">People of the Wastes</Link></p>
</blockquote>
</>};
const _altruistic_diplomat = {title: "Altruistic Diplomat", topLink: ["Regional Traits","main/traits_regional"], jsx: <><h2 id="trait-altruistic_diplomat-altruistic-diplomat">Altruistic Diplomat</h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> Hwanggot</p>
<p>Your upbringing in Hwanggot has influenced you to be both peaceful and wise, and your arguments are consistently sound. You gain a +2 trait bonus on Diplomacy checks.</p>
<blockquote>
<p><strong>Sources</strong> <Link to="/source/dragon_empires_primer">Dragon Empires Primer</Link></p>
</blockquote>
</>};
const _analytical = {title: "Analytical", topLink: ["Regional Traits","main/traits_regional"], jsx: <><h2 id="trait-analytical-analytical">Analytical</h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> Ustalav</p>
<p>You have been trained in the analytical thought process preferred by the professors of mortal sciences at Lepidstadt University, allowing you to consider a question more carefully when you have time for calm contemplation. When you take 10 on a Knowledge check, add 1 to your result.</p>
<blockquote>
<p><strong>Sources</strong> <Link to="/source/advanced_class_origins">Advanced Class Origins</Link></p>
</blockquote>
</>};
const _ancestral_weapon = {title: "Ancestral Weapon", topLink: ["Regional Traits","main/traits_regional"], jsx: <><h2 id="trait-ancestral_weapon-ancestral-weapon">Ancestral Weapon</h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> Numeria</p>
<p>You have inherited a sacred tribal weapon wielded by your forebears since the days before the Rain of Stars, and you were trained in its use from a young age. Select either <Link to="/eq-material/cold_iron">cold iron</Link> or <Link to="/eq-material/alchemical_silver">silver</Link>. You begin play with a masterwork melee weapon made of the material of your choice. You must be proficient with this weapon, and its combined cost cannot exceed 500 gp. You gain a +1 trait bonus on attack rolls with weapons made of the selected material.</p>
<blockquote>
<p><strong>Sources</strong> <Link to="/source/people_of_the_river">People of the River</Link></p>
</blockquote>
</>};
const _andoren_freedom_fighter = {title: "Andoren Freedom Fighter", topLink: ["Regional Traits","main/traits_regional"], jsx: <><h2 id="trait-andoren_freedom_fighter-andoren-freedom-fighter">Andoren Freedom Fighter</h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> Andoran</p>
<p>You've dedicated your life to fighting against oppression, tyranny, and slavery. You gain a +1 trait bonus on attack and damage rolls against slavers or any creature holding someone against their will.</p>
<blockquote>
<p><strong>Sources</strong> <Link to="/source/inner_sea_primer">Inner Sea Primer</Link></p>
</blockquote>
</>};
const _animal_spirit_vitality = {title: "Animal-Spirit Vitality", topLink: ["Regional Traits","main/traits_regional"], jsx: <><h2 id="trait-animal_spirit_vitality-animal-spirit-vitality">Animal-Spirit Vitality</h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> Kyonin</p>
<p>The elven druids of Kyonin taught you to commune with the natural healing powers of animals. Once per day when you cast a spell that restores hit points, you restore 1 additional hit point for every die rolled as long as a creature of the animal type is within 50 feet. You must decide to use this ability before rolling to determine the number of hit points that your spell restores.</p>
<blockquote>
<p><strong>Sources</strong> <Link to="/source/healers_handbook">Healer's Handbook</Link></p>
</blockquote>
</>};
const _antiquities_smuggler = {title: "Antiquities Smuggler", topLink: ["Regional Traits","main/traits_regional"], jsx: <><h2 id="trait-antiquities_smuggler-antiquities-smuggler">Antiquities Smuggler</h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> Osirion</p>
<p>You have moved contraband relics from Osirion's elder days for years, and have learned some tricks. Choose one of the following skills: Appraise, Bluff, or Sleight of Hand. You gain a +1 trait bonus on that skill, and it is always a class skill for you.</p>
<blockquote>
<p><strong>Sources</strong> <Link to="/source/inner_sea_primer">Inner Sea Primer</Link></p>
</blockquote>
</>};
const _anuli_engineer = {title: "Anuli Engineer", topLink: ["Regional Traits","main/traits_regional"], jsx: <><h2 id="trait-anuli_engineer-anuli-engineer">Anuli Engineer</h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> Anuli</p>
<p>Your family helped to rebuild the ruined city of Anuli, and that tradition runs in your blood. You gain a +2 bonus on Perception checks to notice unusual stonework, traps, and hidden doors in worked stone and artificial constructions. Knowledge (engineering) is always a class skill for you.</p>
<blockquote>
<p><strong>Sources</strong> <Link to="/source/distant_shores">Distant Shores</Link></p>
</blockquote>
</>};
const _aquatic_survivalist = {title: "Aquatic Survivalist", topLink: ["Regional Traits","main/traits_regional"], jsx: <><h2 id="trait-aquatic_survivalist-aquatic-survivalist">Aquatic Survivalist</h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> Plane of Water</p>
<p>For whatever reason, you spent much of your formative years fighting to keep yourself alive amid the fearsome creatures that inhabit the infinite oceans of the Plane of Water, and you learned how to stay hidden even against predators with unusual senses. You gain a +2 trait bonus on Stealth checks while underwater. Once per day, you can attempt a Stealth check to hide in plain sight (as the ranger class feature of the same name) while underwater. This is only effective against creatures that rely on blindsense, blindsight, or tremorsense. Creatures with other senses perceive you normally.</p>
<blockquote>
<p><strong>Sources</strong> <Link to="/source/blood_of_the_elements">Blood of the Elements</Link></p>
</blockquote>
</>};
const _armun_kelisk_scholar = {title: "Armun Kelisk Scholar", topLink: ["Regional Traits","main/traits_regional"], jsx: <><h2 id="trait-armun_kelisk_scholar-armun-kelisk-scholar">Armun Kelisk Scholar</h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> Plane of Air</p>
<p>During your time on the Plane of Air, you visited the libraries of Armun Kelisk frequently and voraciously read the tomes therein. You gain a +1 trait bonus on Knowledge (planes) checks and checks made with one other Knowledge skill of your choice. This bonus increases to +3 when used to identify a creature with the air subtype. Knowledge (planes) becomes a class skill for you, and your bonus language options at 1st level include Auran. This choice is in addition to the bonus languages available to the character because of her race.</p>
<blockquote>
<p><strong>Sources</strong> <Link to="/source/blood_of_the_elements">Blood of the Elements</Link></p>
</blockquote>
</>};
const _artifact_hunter_isp = {title: "Artifact Hunter (ISP)", topLink: ["Regional Traits","main/traits_regional"], jsx: <><h2 id="trait-artifact_hunter_isp-artifact-hunter-isp">Artifact Hunter (ISP)</h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> Mwangi Expanse</p>
<p>You know the legends of the Mwangi Expanse and the places where great treasures were rumored to have fallen. You gain a +1 trait bonus on Knowledge (geography) and Knowledge (history) checks, and one of them is always a class skill for you.</p>
<blockquote>
<p><strong>Sources</strong> <Link to="/source/inner_sea_primer">Inner Sea Primer</Link></p>
</blockquote>
</>};
const _ash_bane = {title: "Ash Bane", topLink: ["Regional Traits","main/traits_regional"], jsx: <><h2 id="trait-ash_bane-ash-bane">Ash Bane</h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> wasteland</p>
<p>You have built up a resistance to the diseases that ash giants and their vermin guardians carry. You gain a +2 trait bonus on Fortitude saving throws to resist the disease abilities of ash giants and creatures with the vermin type. In addition, you gain a +1 trait bonus on melee attack rolls against vermin.</p>
<blockquote>
<p><strong>Sources</strong> <Link to="/source/people_of_the_wastes">People of the Wastes</Link></p>
</blockquote>
</>};
const _aspiring_hellknight = {title: "Aspiring Hellknight", topLink: ["Regional Traits","main/traits_regional"], jsx: <><h2 id="trait-aspiring_hellknight-aspiring-hellknight">Aspiring Hellknight</h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> Cheliax</p>
<p>Your family has a long tradition of service in the <Link to="/rule/hellknights">Hellknights</Link>, and your strict upbringing and training have given you a forceful aura of command. You gain a +1 trait bonus on Intimidate checks, and Intimidate is always a class skill for you.</p>
<blockquote>
<p><strong>Sources</strong> <Link to="/source/inner_sea_primer">Inner Sea Primer</Link></p>
</blockquote>
</>};
const _awakened_from_stasis = {title: "Awakened from Stasis", topLink: ["Regional Traits","main/traits_regional"], jsx: <><h2 id="trait-awakened_from_stasis-awakened-from-stasis">Awakened from Stasis</h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> Apostae</p>
<p>Although you were born and lived on Golarion, you recently awakened in a strange vault with no memory of how you got there, surrounded by sleeping creatures of every shape and size in smooth glass eggs, all watched over by uncommunicative crab-like automatons. As a side effect of your stasis, you gain all the benefits of 8 hours of sleep in only 2 hours. This allows a spellcaster who must rest to prepare spells to do so after only 2 hours, but does not allow a spellcaster to prepare spells more than once per day.</p>
<blockquote>
<p><strong>Sources</strong> <Link to="/source/people_of_the_stars">People of the Stars</Link></p>
</blockquote>
</>};
const _azlanti_scholar_hftf = {title: "Azlanti Scholar (HFtF)", topLink: ["Regional Traits","main/traits_regional"], jsx: <><h2 id="trait-azlanti_scholar_hftf-azlanti-scholar-hftf">Azlanti Scholar (HFtF)</h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> Ironbound Archipelago<br/><strong>Requirements:</strong> Cannot be an elf</p>
<p>Your interactions with the elves of the Mordant Spire have taught you much about Azlanti artifacts, and you now share the Mordant Spire elves' fascination with these relics. You gain Azlanti as a bonus language, and you gain a +2 trait bonus on Appraise and Use Magic Device checks when attempting to identify or use authentic Azlanti artifacts.</p>
<blockquote>
<p><strong>Sources</strong> <Link to="/source/heroes_from_the_fringe">Heroes from the Fringe</Link></p>
</blockquote>
</>};
const _balanced_education = {title: "Balanced Education", topLink: ["Regional Traits","main/traits_regional"], jsx: <><h2 id="trait-balanced_education-balanced-education">Balanced Education</h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> Anuli</p>
<p>Your upbringing focused on strengthening mind and body in equal measure. Once per day, you can draw on this training to apply a physical ability modifier to a skill check instead of its usual mental ability modifier, or apply a mental ability modifier to a skill check instead of its usual physical ability modifier. You can only exchange ability modifiers between the following pairings: Strength with Intelligence, Dexterity with Wisdom, and Constitution with Charisma.</p>
<blockquote>
<p><strong>Sources</strong> <Link to="/source/distant_shores">Distant Shores</Link></p>
</blockquote>
</>};
const _bandit = {title: "Bandit", topLink: ["Regional Traits","main/traits_regional"], jsx: <><h2 id="trait-bandit-bandit">Bandit</h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> River Kingdoms</p>
<p>Since you were young, you've been a member of one River Kingdoms bandit gang or another. Choose one of the following skills: Escape Artist, Intimidate, or Stealth. You gain a +1 trait bonus on that skill, and it is always a class skill for you.</p>
<blockquote>
<p><strong>Sources</strong> <Link to="/source/inner_sea_primer">Inner Sea Primer</Link></p>
</blockquote>
</>};
const _beachcomber = {title: "Beachcomber", topLink: ["Regional Traits","main/traits_regional"], jsx: <><h2 id="trait-beachcomber-beachcomber">Beachcomber</h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> coastal or river</p>
<p>You have a knack for finding what you need as it washes ashore. Once per week, if you spend 8 hours in a single day searching along a shoreline, you can attempt a Survival check. You find any combination of mundane objects whose value in gold pieces is less than or equal to the result of the check, in a usable (if somewhat waterlogged) condition.</p>
<blockquote>
<p><strong>Sources</strong> <Link to="/source/wilderness_origins">Wilderness Origins</Link></p>
</blockquote>
</>};
const _belem_pirate = {title: "Belem Pirate", topLink: ["Regional Traits","main/traits_regional"], jsx: <><h2 id="trait-belem_pirate-belem-pirate">Belem Pirate</h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> Minata</p>
<p>The hidden coves and bays of the island of Belem have been your home throughout most of your career as a pirate, and the winding waterways of Minata have trained you well in the art of sailing. You gain a +1 trait bonus on Knowledge (geography) checks and Profession (sailor) checks, and one of these skills becomes a class skill for you.</p>
<blockquote>
<p><strong>Sources</strong> <Link to="/source/dragon_empires_primer">Dragon Empires Primer</Link></p>
</blockquote>
</>};
const _bellflower_tiller = {title: "Bellflower Tiller", topLink: ["Regional Traits","main/traits_regional"], jsx: <><h2 id="trait-bellflower_tiller-bellflower-tiller">Bellflower Tiller</h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> Cheliax</p>
<p>You are a tiller in the secretive <Link to="/rule/bellflower_network">Bellflower Network</Link> in Cheliax and carefully move slaves from one hideout to the next. You gain a +5 trait bonus on all Survival skill checks made to get along in the wild, travel in severe weather, keep from getting lost, or predict the weather.</p>
<blockquote>
<p><strong>Sources</strong> <Link to="/source/faction_guide">Faction Guide</Link></p>
</blockquote>
</>};
const _bellis_axe_master = {title: "Bellis Axe Master", topLink: ["Regional Traits","main/traits_regional"], jsx: <><h2 id="trait-bellis_axe_master-bellis-axe-master">Bellis Axe Master</h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> Bellis</p>
<p>No one knows how to swing an axe better than a Bellisian! You gain a +2 trait bonus on all rolls made to confirm critical hits with axes (battle axe, hand axe, or greataxe).</p>
<blockquote>
<p><strong>Sources</strong> <Link to="/source/andoran_spirit_of_liberty">Andoran, Spirit of Liberty</Link></p>
</blockquote>
</>};
const _bellis_honey_harvester = {title: "Bellis Honey Harvester", topLink: ["Regional Traits","main/traits_regional"], jsx: <><h2 id="trait-bellis_honey_harvester-bellis-honey-harvester">Bellis Honey Harvester</h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> Bellis</p>
<p>Your frequent exposure to bees - and their stings - makes all such creatures seem more like nuisances than actual threats. You gain DR 3/- against damage dealt by swarms and a +1 trait bonus on saving throws against distraction and poison from swarms.</p>
<blockquote>
<p><strong>Sources</strong> <Link to="/source/andoran_spirit_of_liberty">Andoran, Spirit of Liberty</Link></p>
</blockquote>
</>};
const _bellis_log_roller = {title: "Bellis Log Roller", topLink: ["Regional Traits","main/traits_regional"], jsx: <><h2 id="trait-bellis_log_roller-bellis-log-roller">Bellis Log Roller</h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> Bellis</p>
<p>The time you spent leaping between slippery logs as they whirled down the Sellen River taught you how to keep your footing. You gain a +1 trait bonus on Acrobatics checks and a +1 trait bonus to your CMB when attempting to resist trip attacks.</p>
<blockquote>
<p><strong>Sources</strong> <Link to="/source/andoran_spirit_of_liberty">Andoran, Spirit of Liberty</Link></p>
</blockquote>
</>};
const _betrayed_ex_noble = {title: "Betrayed Ex-Noble", topLink: ["Regional Traits","main/traits_regional"], jsx: <><h2 id="trait-betrayed_ex_noble-betrayed-ex-noble">Betrayed Ex-Noble</h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> City of Brass</p>
<p>You were born a noble in the City of Brass, but were unjustly stripped of your title or exiled. Now, your ire prevents you from brooking any further insult unto your already disgraced name. Whenever an enemy attempts to feint against you in combat, the DC to do so is equal to 10 + your base attack bonus + your Wisdom modifier, or 10 + your Intimidate bonus, whichever is higher.</p>
<blockquote>
<p><strong>Sources</strong> <Link to="/source/blood_of_the_elements">Blood of the Elements</Link></p>
</blockquote>
</>};
const _big_game_hunter = {title: "Big Game Hunter", topLink: ["Regional Traits","main/traits_regional"], jsx: <><h2 id="trait-big_game_hunter-big-game-hunter">Big Game Hunter</h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> Realm of the Mammoth Lords</p>
<p>You have spent long hours hunting giant creatures and have become skilled at bringing them down quickly. You gain a +1 trait bonus on weapon damage rolls against Large or larger creatures of the animal type.</p>
<blockquote>
<p><strong>Sources</strong> <Link to="/source/people_of_the_north">People of the North</Link></p>
</blockquote>
</>};
const _black_eagle_recruit = {title: "Black Eagle Recruit", topLink: ["Regional Traits","main/traits_regional"], jsx: <><h2 id="trait-black_eagle_recruit-black-eagle-recruit">Black Eagle Recruit</h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> Lambreth</p>
<p>You were recruited to serve as one of Lord Arnefax's feared Black Eagles for a time, but you have since left that life. You gain a +1 trait bonus on saves against fear effects; this bonus increases to +3 if an evil outsider caused the effect.</p>
<blockquote>
<p><strong>Sources</strong> <Link to="/source/people_of_the_river">People of the River</Link></p>
</blockquote>
</>};
const _blackthorn_rancher = {title: "Blackthorn Rancher", topLink: ["Regional Traits","main/traits_regional"], jsx: <><h2 id="trait-blackthorn_rancher-blackthorn-rancher">Blackthorn Rancher</h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> Lambreth</p>
<p>Domestic animals from Lambreth are known for their resiliency. You gain a +1 trait bonus on Handle Animal checks and Handle Animal is a class skill for you. Your animal companion or bonded mount gains a permanent +3 trait bonus to its maximum hit point total.</p>
<blockquote>
<p><strong>Sources</strong> <Link to="/source/people_of_the_river">People of the River</Link></p>
</blockquote>
</>};
const _blessed_of_the_norns = {title: "Blessed of the Norns", topLink: ["Regional Traits","main/traits_regional"], jsx: <><h2 id="trait-blessed_of_the_norns-blessed-of-the-norns">Blessed of the Norns</h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> Lands of the Linnorm Kings</p>
<p>You or one of your parents belonged to a coven that honored the norns-powerful fey seers - and you still bear their favor in the form of a subtle sense for danger. You gain a +2 trait bonus on Perception checks to notice traps and ambushes, and a +1 trait bonus to your AC against traps and during any surprise round in which you are caught unaware.</p>
<blockquote>
<p><strong>Sources</strong> <Link to="/source/blood_of_the_coven">Blood of the Coven</Link></p>
</blockquote>
</>};
const _blighted_physiology = {title: "Blighted Physiology", topLink: ["Regional Traits","main/traits_regional"], jsx: <><h2 id="trait-blighted_physiology-blighted-physiology">Blighted Physiology</h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> Numeria</p>
<p>Exposure to the corruption that seeps through every drop of water and grain of dirt in Numeria has altered your body. Horrific growths beneath your skin provide you a +1 natural armor bonus to AC, but your body does not work as a normal creature's would. You become sickened for 1 round anytime you receive magical healing.</p>
<blockquote>
<p><strong>Sources</strong> <Link to="/source/people_of_the_river">People of the River</Link></p>
</blockquote>
</>};
const _blood_potion_brewer = {title: "Blood Potion Brewer", topLink: ["Regional Traits","main/traits_regional"], jsx: <><h2 id="trait-blood_potion_brewer-blood-potion-brewer">Blood Potion Brewer</h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> Belkzen</p>
<p>The orcs of Belkzen routinely mix the blood of their enemies with potions they brew to gain some of their foe's strength. Twice per day when you brew a potion, you can add some of an enemy's blood to the mixture. When you do, the potion's caster level is treated as 1 higher when you drink it for the purpose of determining the duration of the potion's effects. This ability has no effect if another creature drinks the potion. This trait does not grant the ability to brew potions.</p>
<blockquote>
<p><strong>Sources</strong> <Link to="/source/potions_and_poisons">Potions and Poisons</Link></p>
</blockquote>
</>};
const _blooded = {title: "Blooded", topLink: ["Regional Traits","main/traits_regional"], jsx: <><h2 id="trait-blooded-blooded">Blooded</h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> Mindspin Mountains</p>
<p>Desperate battles have honed your fighting skills against the ancient enemies of the dwarves. You receive a +1 trait bonus on weapon damage rolls against giants, goblins, and orcs.</p>
<blockquote>
<p><strong>Sources</strong> <Link to="/source/dwarves_of_golarion">Dwarves of Golarion</Link></p>
</blockquote>
</>};
const _border_guard = {title: "Border Guard", topLink: ["Regional Traits","main/traits_regional"], jsx: <><h2 id="trait-border_guard-border-guard">Border Guard</h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> Kwanlai</p>
<p>You are one of the warriors on the front lines between Kwanlai and Wanshou, and excel at combat against water-dwelling foes. You gain a +2 trait bonus on rolls to confirm critical hits against foes with the aquatic subtype.</p>
<blockquote>
<p><strong>Sources</strong> <Link to="/source/dragon_empires_primer">Dragon Empires Primer</Link></p>
</blockquote>
</>};
const _born_under_the_green_star = {title: "Born under the Green Star", topLink: ["Regional Traits","main/traits_regional"], jsx: <><h2 id="trait-born_under_the_green_star-born-under-the-green-star">Born under the Green Star</h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> Castrovel</p>
<p>You were born on Castrovel and touched by the planet's profound psychic bounty. Treat your caster level as 1 higher when casting spells and spell-like abilities with the mind-affecting descriptor.</p>
<blockquote>
<p><strong>Sources</strong> <Link to="/source/people_of_the_stars">People of the Stars</Link></p>
</blockquote>
</>};
const _bounty_hunter = {title: "Bounty Hunter", topLink: ["Regional Traits","main/traits_regional"], jsx: <><h2 id="trait-bounty_hunter-bounty-hunter">Bounty Hunter</h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> Isger</p>
<p>You have made it your mission to help bring the bandits of Isger to justice. You gain a +1 trait bonus on Survival checks to find or follow tracks, and a +1 trait bonus on Perception checks to avoid being surprised.</p>
<blockquote>
<p><strong>Sources</strong> <Link to="/source/inner_sea_primer">Inner Sea Primer</Link></p>
</blockquote>
</>};
const _brave_words = {title: "Brave Words", topLink: ["Regional Traits","main/traits_regional"], jsx: <><h2 id="trait-brave_words-brave-words">Brave Words</h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> Ninshaburian</p>
<p>You inherit your forebears' ability to fight off terror with bragging or insults. As a swift action, when you have the frightened condition, you can function as if you only have the shaken condition for 1 round by shouting at the source of your fear. You must be able to see the source of the fear condition. You can use this trait only once per fear effect. This trait grants no benefits against the shaken or panicked conditions.</p>
<blockquote>
<p><strong>Sources</strong> <Link to="/source/blood_of_the_ancients">Blood of the Ancients pg. 25</Link></p>
</blockquote>
</>};
const _brevoy_bandit = {title: "Brevoy Bandit", topLink: ["Regional Traits","main/traits_regional"], jsx: <><h2 id="trait-brevoy_bandit-brevoy-bandit">Brevoy Bandit</h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> Mivon</p>
<p>You fled the persecution of Brevoy authorities and wound up in Mivon. Whether or not you are guilty of your alleged crimes, you seek to build a new life amid new neighbors. Choose one Profession skill and one ability score other than Wisdom. You add that ability score's modifier in addition to your Wisdom modifier on checks with the chosen Profession skill.</p>
<blockquote>
<p><strong>Sources</strong> <Link to="/source/people_of_the_river">People of the River</Link></p>
</blockquote>
</>};
const _briar_bandit = {title: "Briar Bandit", topLink: ["Regional Traits","main/traits_regional"], jsx: <><h2 id="trait-briar_bandit-briar-bandit">Briar Bandit</h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> forest</p>
<p>The time you've spent crawling through thorny brambles and other thick underbrush during raids and ambushes taught you how to move without disturbing the dense flora around you. When in overgrown areas, you gain a +2 trait bonus on Stealth checks and a +1 trait bonus on damage rolls with sneak attacks.</p>
<blockquote>
<p><strong>Sources</strong> <Link to="/source/kobolds_of_golarion">Kobolds of Golarion</Link></p>
</blockquote>
</>};
const _call_of_the_longships = {title: "Call of the Longships", topLink: ["Regional Traits","main/traits_regional"], jsx: <><h2 id="trait-call_of_the_longships-call-of-the-longships">Call of the Longships</h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> Lands of the Linnorm Kings</p>
<p>Your blood sings with longing to relive the adventures of one of your ancestors, and you are inexorably drawn to the sea. You gain a +1 trait bonus on Profession (sailor) checks and a +1 trait bonus on attack rolls made onboard ships.</p>
<blockquote>
<p><strong>Sources</strong> <Link to="/source/people_of_the_north">People of the North</Link></p>
</blockquote>
</>};
const _candidate_for_perfection = {title: "Candidate for Perfection", topLink: ["Regional Traits","main/traits_regional"], jsx: <><h2 id="trait-candidate_for_perfection-candidate-for-perfection">Candidate for Perfection</h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> Jalmeray</p>
<p>You have begun training to enter one of the <Link to="/rule/houses_of_perfection">Houses of Perfection</Link>, and have honed your body, mind, and spirit into one well-trained weapon. You gain a +1 trait bonus on attack of opportunity attack rolls made with unarmed strikes.</p>
<blockquote>
<p><strong>Sources</strong> <Link to="/source/inner_sea_primer">Inner Sea Primer</Link></p>
</blockquote>
</>};
const _caravan_nomad = {title: "Caravan Nomad", topLink: ["Regional Traits","main/traits_regional"], jsx: <><h2 id="trait-caravan_nomad-caravan-nomad">Caravan Nomad</h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> Varisia<br/><strong>Requirements:</strong> Kitsune</p>
<p>Your family has lived on the open roads of Varisia for untold generations, impersonating nomadic Varisians. You gain a +1 trait bonus on Bluff and Perform checks, and one of these skills is a class skill for you.</p>
<blockquote>
<p><strong>Sources</strong> <Link to="/source/blood_of_the_beast">Blood of the Beast</Link></p>
</blockquote>
</>};
const _carpenden_lobber = {title: "Carpenden Lobber", topLink: ["Regional Traits","main/traits_regional"], jsx: <><h2 id="trait-carpenden_lobber-carpenden-lobber">Carpenden Lobber</h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> Carpenden</p>
<p>Your regular participation in the moonmelon festival has made you wickedly effective at hurling harmless objects. You gain a +2 trait bonus on attack rolls when throwing items that do not deal normal hit point damage (such as weapons that deal nonlethal damage or items such as tanglefoot bags and thunderstones).</p>
<blockquote>
<p><strong>Sources</strong> <Link to="/source/andoran_spirit_of_liberty">Andoran, Spirit of Liberty</Link></p>
</blockquote>
</>};
const _carpenden_roof_runner = {title: "Carpenden Roof Runner", topLink: ["Regional Traits","main/traits_regional"], jsx: <><h2 id="trait-carpenden_roof_runner-carpenden-roof-runner">Carpenden Roof Runner</h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> Carpenden</p>
<p>Your childhood playing atop Carpenden's buildings has given you a remarkable head for heights. You gain a +2 trait bonus on Acrobatics checks made when you are at least 20 feet above the ground.</p>
<blockquote>
<p><strong>Sources</strong> <Link to="/source/andoran_spirit_of_liberty">Andoran, Spirit of Liberty</Link></p>
</blockquote>
</>};
const _cavern_survivor = {title: "Cavern Survivor", topLink: ["Regional Traits","main/traits_regional"], jsx: <><h2 id="trait-cavern_survivor-cavern-survivor">Cavern Survivor</h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> Nar-Voth</p>
<p>You've regularly traversed Nar-Voth and know how to subsist in that lightless realm better than most surface dwellers. You gain a +2 trait bonus on Survival checks to survive in a subterranean wilderness, and Survival is a class skill for you.</p>
<blockquote>
<p><strong>Sources</strong> <Link to="/source/heroes_of_the_darklands">Heroes of the Darklands</Link></p>
</blockquote>
</>};
const _centaur_vengeance = {title: "Centaur Vengeance", topLink: ["Regional Traits","main/traits_regional"], jsx: <><h2 id="trait-centaur_vengeance-centaur-vengeance">Centaur Vengeance</h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> Iobaria</p>
<p>Your nomadic tribe wanders the Ice Steppes of Iobaria. They live in constant fear of the great white wyrm Sjohvornor and feel helpless to stop the dragon's aggression. Your tribe is filled with wise sages and great warriors, and they resent being cowed by any foe. You vowed that one day you would not have to be afraid of Sjohvornor or any other wyrm. You gain a +2 bonus on saving throws against any dragon's frightful presence.</p>
<blockquote>
<p><strong>Sources</strong> <Link to="/source/dragonslayers_handbook">Dragonslayer's Handbook</Link></p>
</blockquote>
</>};
const _chainbreaker = {title: "Chainbreaker", topLink: ["Regional Traits","main/traits_regional"], jsx: <><h2 id="trait-chainbreaker-chainbreaker">Chainbreaker</h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> Andoran</p>
<p>You're an expert at rescuing slaves. You know that a few slaves freed from their chains can help turn the tide during a boarding action. You gain a +1 trait bonus on Disable Device checks made to open locks, Strength checks made to break chains or bars in order to free slaves, and combat maneuver checks made to sunder chains or bars in order to free slaves.</p>
<blockquote>
<p><strong>Sources</strong> <Link to="/source/pirates_of_the_inner_sea">Pirates of the Inner Sea</Link></p>
</blockquote>
</>};
const _channel_the_earth = {title: "Channel the Earth", topLink: ["Regional Traits","main/traits_regional"], jsx: <><h2 id="trait-channel_the_earth-channel-the-earth">Channel the Earth</h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> Plane of Earth</p>
<p>Perhaps you worship the Elemental Lord of Earth, or perhaps you have gleaned your fated powers via some other means of interacting with the Eternal Delve. Your divine powers are infused with the elemental powers of the Plane of Earth. Whenever you channel positive energy to heal living creatures, affected targets gain a +2 profane bonus to CMD to resist bull rush, reposition, and trip combat maneuvers. Alternately, if you channel negative energy to harm living creatures, affected targets take a -2 penalty to CMD against such combat maneuvers. This effect lasts 1 round.</p>
<blockquote>
<p><strong>Sources</strong> <Link to="/source/blood_of_the_elements">Blood of the Elements</Link></p>
</blockquote>
</>};
const _charau_ka_slayer = {title: "Charau-Ka Slayer", topLink: ["Regional Traits","main/traits_regional"], jsx: <><h2 id="trait-charau_ka_slayer-charau-ka-slayer">Charau-Ka Slayer</h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> Mwangi Expanse</p>
<p>As a native of the Mwangi Jungle, you've had frequent encounters with the charau-ka and learned how to fight against these coldly calculating demon worshipers. You gain a +1 trait bonus to AC against attacks made with thrown weapons.</p>
<blockquote>
<p><strong>Sources</strong> <Link to="/source/demon_hunters_handbook">Demon Hunter's Handbook</Link></p>
</blockquote>
</>};
const _charmed_innocent = {title: "Charmed Innocent", topLink: ["Regional Traits","main/traits_regional"], jsx: <><h2 id="trait-charmed_innocent-charmed-innocent">Charmed Innocent</h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> urban</p>
<p>Your apparent good nature or playful charm makes nonevil creatures want to like you. Once per day, before you roll any Charisma check or Charisma-based skill check against a nonevil creature, you can roll twice and take the better result.</p>
<blockquote>
<p><strong>Sources</strong> <Link to="/source/heroes_of_the_streets">Heroes of the Streets</Link></p>
</blockquote>
</>};
const _cheap_to_feed = {title: "Cheap to Feed", topLink: ["Regional Traits","main/traits_regional"], jsx: <><h2 id="trait-cheap_to_feed-cheap-to-feed">Cheap to Feed</h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> Osirion or Varisia<br/><strong>Requirements:</strong> Halfling</p>
<p>Life in a big city taught the consequences of pride. Now you have no qualms about pointing out how little of a burden your upkeep would prove to potential employers, captors, innkeepers, or anyone else able to provide you with the necessities of life. You gain a +3 trait bonus on Bluff checks made in order to gain food, water, or shelter.</p>
<blockquote>
<p><strong>Sources</strong> <Link to="/source/halflings_of_golarion">Halflings of Golarion</Link></p>
</blockquote>
</>};
const _chelish_guerrilla = {title: "Chelish Guerrilla", topLink: ["Regional Traits","main/traits_regional"], jsx: <><h2 id="trait-chelish_guerrilla-chelish-guerrilla">Chelish Guerrilla</h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> Cheliax</p>
<p>In overthrowing House Thrune, you've spent many years training to face the diabolist nobles and the devils they bind. You gain a +2 trait bonus on Knowledge checks to identify devils (and their special powers and weaknesses) and a +1 trait bonus on weapon damage rolls against devils.</p>
<blockquote>
<p><strong>Sources</strong> <Link to="/source/monster_summoners_handbook">Monster Summoner's Handbook</Link></p>
</blockquote>
</>};
const _child_of_mumia = {title: "Child of Mumia", topLink: ["Regional Traits","main/traits_regional"], jsx: <><h2 id="trait-child_of_mumia-child-of-mumia">Child of Mumia</h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> Osirion</p>
<p>During your childhood, you knew someone who was addicted to <Link to="/drug/mumia">mumia</Link>, a drug made from the flesh of the dead, whether that was a drug-addled parent, an unsavory employer, or a libertine childhood friend. Although you did not indulge in the ghoulish narcotic yourself, your exposure to it grants you a +1 trait bonus on saving throws against curses and diseases, including magical diseases.</p>
<blockquote>
<p><strong>Sources</strong> <Link to="/source/people_of_the_sands">People of the Sands</Link></p>
</blockquote>
</>};
const _child_of_wati = {title: "Child of Wati", topLink: ["Regional Traits","main/traits_regional"], jsx: <><h2 id="trait-child_of_wati-child-of-wati">Child of Wati</h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> Osirion</p>
<p>You were raised near the infamous necropolis of Wati, and even managed to sneak into these hallowed grounds on occasion. Entering the clergy of the Voices of the Spire in Wati was a natural choice as you grew older, and your past experiences made you a particularly well-informed disciple of the church. Your effective cleric level is 1 higher for the purposes of channeling positive energy to damage undead. Your effective cleric level cannot exceed your character level.</p>
<blockquote>
<p><strong>Sources</strong> <Link to="/source/undead_slayers_handbook">Undead Slayer's Handbook</Link></p>
</blockquote>
</>};
const _child_of_the_crusades_isp = {title: "Child of the Crusades (ISP)", topLink: ["Regional Traits","main/traits_regional"], jsx: <><h2 id="trait-child_of_the_crusades_isp-child-of-the-crusades-isp">Child of the Crusades (ISP)</h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> Mendev</p>
<p>Your parents stood strong against the demons of the Worldwound, facing down the worst of this world and the Great Beyond. You have inherited their indomitable spirit, and you gain a +2 trait bonus on all saves against fear.</p>
<blockquote>
<p><strong>Sources</strong> <Link to="/source/inner_sea_primer">Inner Sea Primer</Link></p>
</blockquote>
</>};
const _chillblight_emissary = {title: "Chillblight Emissary", topLink: ["Regional Traits","main/traits_regional"], jsx: <><h2 id="trait-chillblight_emissary-chillblight-emissary">Chillblight Emissary</h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> Irrisen</p>
<p>You have spent considerable time at Chillblight, but have escaped this unearthly fey outpost. You gain DR 1/cold iron but become sickened for 1 round if damaged by a cold iron weapon.</p>
<blockquote>
<p><strong>Sources</strong> <Link to="/source/people_of_the_north">People of the North</Link></p>
</blockquote>
</>};
const _chilled_by_brutality = {title: "Chilled by Brutality", topLink: ["Regional Traits","main/traits_regional"], jsx: <><h2 id="trait-chilled_by_brutality-chilled-by-brutality">Chilled by Brutality</h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> tundra</p>
<p>You were part of a group that was mercilessly attacked by giants of the tundra, who may have gone so far as to eat the dead and dying. After that, little can faze you, but you strongly prefer to finish fights with giants quickly to prevent anything like that from happening again. You gain a +2 trait bonus on attack rolls to confirm critical hits against giants and on saving throws against fear effects.</p>
<p>Likely Regions: Brevoy, Irrisen, Lands of the Linnorm Kings, Mendev, Realm of the Mammoth Lords.</p>
<p>Likely giants: Cloud, Frost, River, Rune, Taiga</p>
<blockquote>
<p><strong>Sources</strong> <Link to="/source/giant_hunters_handbook">Giant Hunter's Handbook</Link></p>
</blockquote>
</>};
const _chivalrous = {title: "Chivalrous", topLink: ["Regional Traits","main/traits_regional"], jsx: <><h2 id="trait-chivalrous-chivalrous">Chivalrous</h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> Taldor</p>
<p>You were raised on tales of heroic knights and benevolent wizards from Taldor's Golden Age, and try to emulate their great deeds. You gain a +1 trait bonus on Diplomacy and Knowledge (history) checks.</p>
<blockquote>
<p><strong>Sources</strong> <Link to="/source/inner_sea_primer">Inner Sea Primer</Link>, <Link to="/source/taldor_echoes_of_glory">Taldor, Echoes of Glory</Link></p>
</blockquote>
</>};
const _chosen_child = {title: "Chosen Child", topLink: ["Regional Traits","main/traits_regional"], jsx: <><h2 id="trait-chosen_child-chosen-child">Chosen Child</h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> Po Li</p>
<p>The oracles of Po Li smiled upon you when your parents claimed you were of divine right, and you were raised with privileges few Po Lians can fathom. Your starting money increases by 900 gp.</p>
<blockquote>
<p><strong>Sources</strong> <Link to="/source/dragon_empires_primer">Dragon Empires Primer</Link></p>
</blockquote>
</>};
const _citizen_of_eleder = {title: "Citizen of Eleder", topLink: ["Regional Traits","main/traits_regional"], jsx: <><h2 id="trait-citizen_of_eleder-citizen-of-eleder">Citizen of Eleder</h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> Eleder</p>
<p>You live and work in Eleder. You gain a +1 trait bonus on all Knowledge (local) and Knowledge (nobility) checks regarding Eleder.</p>
<blockquote>
<p><strong>Sources</strong> <Link to="/source/sargava_the_lost_colony">Sargava, the Lost Colony</Link></p>
</blockquote>
</>};
const _citizen_of_kalabuto = {title: "Citizen of Kalabuto", topLink: ["Regional Traits","main/traits_regional"], jsx: <><h2 id="trait-citizen_of_kalabuto-citizen-of-kalabuto">Citizen of Kalabuto</h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> Kalabuto</p>
<p>You live and work in Kalabuto. You gain a +1 trait bonus on all Knowledge (local) and Knowledge (history) checks regarding Kalabuto.</p>
<blockquote>
<p><strong>Sources</strong> <Link to="/source/sargava_the_lost_colony">Sargava, the Lost Colony</Link></p>
</blockquote>
</>};
const _clan_artisan = {title: "Clan Artisan", topLink: ["Regional Traits","main/traits_regional"], jsx: <><h2 id="trait-clan_artisan-clan-artisan">Clan Artisan</h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> Xa Hoi</p>
<p>You were raised in one of the numerous clans of Xa Hoi, and learned a valuable trade in your early years. Pick one Craft skill. You gain a +2 trait bonus on checks with that skill, and it becomes a class skill for you.</p>
<blockquote>
<p><strong>Sources</strong> <Link to="/source/dragon_empires_primer">Dragon Empires Primer</Link></p>
</blockquote>
</>};
const _cliff_jumper = {title: "Cliff Jumper", topLink: ["Regional Traits","main/traits_regional"], jsx: <><h2 id="trait-cliff_jumper-cliff-jumper">Cliff Jumper</h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> Cliffs of Fury</p>
<p>You spent your early years exploring and foraging along the coastal cliffs. You gain a +1 trait bonus on Acrobatics and Climb checks, and on Reflex saves to avoid falling.</p>
<blockquote>
<p><strong>Sources</strong> <Link to="/source/cheliax_empire_of_devils">Cheliax, Empire of Devils</Link></p>
</blockquote>
</>};
const _cliff_strider = {title: "Cliff Strider", topLink: ["Regional Traits","main/traits_regional"], jsx: <><h2 id="trait-cliff_strider-cliff-strider">Cliff Strider</h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> Arcadia</p>
<p>You grew up along the Grinding Coast of Arcadia, scaling perilous cliffs and dealing with the dangerous creatures that live on these rocky surfaces. As a move action while climbing, you can climb 5 feet without provoking an attack of opportunity, even if you don't have a climb speed.</p>
<blockquote>
<p><strong>Sources</strong> <Link to="/source/heroes_from_the_fringe">Heroes from the Fringe</Link></p>
</blockquote>
</>};
const _cliff_master = {title: "Cliff-Master", topLink: ["Regional Traits","main/traits_regional"], jsx: <><h2 id="trait-cliff_master-cliff-master">Cliff-Master</h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> Varisia<br/><strong>Requirements:</strong> Goblin</p>
<p>You are adept at scavenging along the cliffs by the sea, and have become a skilled climber. You gain a +1 trait bonus on all Climb and Survival checks.</p>
<blockquote>
<p><strong>Sources</strong> <Link to="/source/goblins_of_golarion">Goblins of Golarion</Link></p>
</blockquote>
</>};
const _cloistered_upbringing = {title: "Cloistered Upbringing", topLink: ["Regional Traits","main/traits_regional"], jsx: <><h2 id="trait-cloistered_upbringing-cloistered-upbringing">Cloistered Upbringing</h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> urban</p>
<p>Growing up among acolytes or monks, you were exposed to their supernatural power. You gain a +1 trait bonus on saving throws against the supernatural effects of channeled energy or abilities powered by ki, and regain 1 additional hit point when healed by supernatural effects.</p>
<blockquote>
<p><strong>Sources</strong> <Link to="/source/heroes_of_the_streets">Heroes of the Streets</Link></p>
</blockquote>
</>};
const _clumsy_slave = {title: "Clumsy Slave", topLink: ["Regional Traits","main/traits_regional"], jsx: <><h2 id="trait-clumsy_slave-clumsy-slave">Clumsy Slave</h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> Cheliax or Katapesh<br/><strong>Requirements:</strong> Halfling</p>
<p>As a former slave, you learned how to conceal your malice toward your owner behind a facade of clumsiness. The first time you attack someone with an attack that deals nonlethal damage, your target must make a Sense Motive opposed by your Bluff check minus the damage dealt to realize you actually intended to harm him; failure means he believe the injury was an accident on your part instead (though he may still want to punish you for it).</p>
<blockquote>
<p><strong>Sources</strong> <Link to="/source/halflings_of_golarion">Halflings of Golarion</Link></p>
</blockquote>
</>};
const _coin_hoarder = {title: "Coin Hoarder", topLink: ["Regional Traits","main/traits_regional"], jsx: <><h2 id="trait-coin_hoarder-coin-hoarder">Coin Hoarder</h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> Mindspin Mountains</p>
<p>Everything has a price - and it's your job to know it. Your starting cash increases to 500 gp.</p>
<blockquote>
<p><strong>Sources</strong> <Link to="/source/dwarves_of_golarion">Dwarves of Golarion</Link></p>
</blockquote>
</>};
const _coincunning = {title: "Coincunning", topLink: ["Regional Traits","main/traits_regional"], jsx: <><h2 id="trait-coincunning-coincunning">Coincunning</h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> Janderhoff</p>
<p>Whether from working with dwarven merchants or being one yourself, you've developed a distinctly dwarven business sense. You receive a +2 trait bonus on Perception checks to notice coins, gems, jewelry, and valuable trade goods. You gain a chance to notice such goods whenever you pass within 10 feet of them, whether or not you are actively looking.</p>
<blockquote>
<p><strong>Sources</strong> <Link to="/source/varisia_birthplace_of_legends">Varisia, Birthplace of Legends</Link></p>
</blockquote>
</>};
const _cold_heart = {title: "Cold Heart", topLink: ["Regional Traits","main/traits_regional"], jsx: <><h2 id="trait-cold_heart-cold-heart">Cold Heart</h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> Cheliax</p>
<p>You gain a +2 trait bonus on saving throws against spells and effects with the emotion descriptor.</p>
<blockquote>
<p><strong>Sources</strong> <Link to="/source/knights_of_the_inner_sea">Knights of the Inner Sea</Link></p>
</blockquote>
</>};
const _commercial_savvy = {title: "Commercial Savvy", topLink: ["Regional Traits","main/traits_regional"], jsx: <><h2 id="trait-commercial_savvy-commercial-savvy">Commercial Savvy</h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> Katapesh</p>
<p>You excel at maximizing mercantile contacts and convincing merchants to dig just a bit deeper into their pockets for you. Whenever you buy from or sell to a merchant, you treat a settlement's Base Value and Purchase Limit as 10% higher.</p>
<blockquote>
<p><strong>Sources</strong> <Link to="/source/champions_of_balance">Champions of Balance</Link></p>
</blockquote>
</>};
const _community_minded = {title: "Community-Minded", topLink: ["Regional Traits","main/traits_regional"], jsx: <><h2 id="trait-community_minded-community-minded">Community-Minded</h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> Rahadoum</p>
<p>While some pray to the gods for mercy or prosperity, you follow a different tack-you believe in improving the lives of those around you through earnest labor and the efforts of you and your community. Your hard-earned discipline and the candor of your words affect all who bear witness. Any morale bonuses you confer upon your allies through your own abilities or spells last 2 additional rounds.</p>
<blockquote>
<p><strong>Sources</strong> <Link to="/source/people_of_the_sands">People of the Sands</Link></p>
</blockquote>
</>};
const _confidante_to_the_oppressed = {title: "Confidante to the Oppressed", topLink: ["Regional Traits","main/traits_regional"], jsx: <><h2 id="trait-confidante_to_the_oppressed-confidante-to-the-oppressed">Confidante to the Oppressed</h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> Andoran</p>
<p>Others recognize that you are filled with the Andoren spirit of liberty and equality. You gain a +2 trait bonus on Diplomacy checks to improve the attitude of oppressed, enslaved, or imprisoned subjects, and unless they have reason to distrust you, their starting attitude toward you is at least indifferent, if not better.</p>
<blockquote>
<p><strong>Sources</strong> <Link to="/source/knights_of_the_inner_sea">Knights of the Inner Sea</Link></p>
</blockquote>
</>};
const _conscientious_miner = {title: "Conscientious Miner", topLink: ["Regional Traits","main/traits_regional"], jsx: <><h2 id="trait-conscientious_miner-conscientious-miner">Conscientious Miner</h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> Jinin</p>
<p>You were one of the mithral miners of Jinin, and learned how to extract the delicate ore as well as determine its value. You gain a +1 trait bonus on Appraise checks, and a +1 trait bonus on Profession (miner) checks. In addition, Profession (miner) becomes a class skill for you.</p>
<blockquote>
<p><strong>Sources</strong> <Link to="/source/dragon_empires_primer">Dragon Empires Primer</Link></p>
</blockquote>
</>};
const _corpse_dodger = {title: "Corpse Dodger", topLink: ["Regional Traits","main/traits_regional"], jsx: <><h2 id="trait-corpse_dodger-corpse-dodger">Corpse Dodger</h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> Ustalav</p>
<p>You spent your formative years in the town of Ravengro, where your proximity to both a prominent graveyard and an infamous prison left you no stranger to the occasional zombie or skeleton. As such, you developed unique methods of dodging these pests. Once per day, you can cast <Link to="/spell/hide_from_undead">hide from undead</Link> as a spell-like ability. The casting time is a swift action and the caster level for this effect is always 1st; this ability is otherwise identical to the spell.</p>
<blockquote>
<p><strong>Sources</strong> <Link to="/source/undead_slayers_handbook">Undead Slayer's Handbook</Link></p>
</blockquote>
</>};
const _cosmopolitan = {title: "Cosmopolitan", topLink: ["Regional Traits","main/traits_regional"], jsx: <><h2 id="trait-cosmopolitan-cosmopolitan">Cosmopolitan</h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> Goka</p>
<p>Your exposure to the many peoples intersecting in Goka and the tongues spoken there has given you a particular facility for speech. You gain a +1 trait bonus on Linguistics checks, and Linguistics becomes a class skill for you.</p>
<blockquote>
<p><strong>Sources</strong> <Link to="/source/dragon_empires_primer">Dragon Empires Primer</Link>, <Link to="/source/inner_sea_primer">Inner Sea Primer</Link></p>
</blockquote>
</>};
const _cruel_master = {title: "Cruel Master", topLink: ["Regional Traits","main/traits_regional"], jsx: <><h2 id="trait-cruel_master-cruel-master">Cruel Master</h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> Okeno</p>
<p>You're a master of dominating slaves through body language and inflection, and this ability carries over into other lines of work as well. You gain a +1 trait bonus on Intimidate checks, and it becomes a class skill for you.</p>
<blockquote>
<p><strong>Sources</strong> <Link to="/source/pirates_of_the_inner_sea">Pirates of the Inner Sea</Link></p>
</blockquote>
</>};
const _crusader_road_acolyte = {title: "Crusader Road Acolyte", topLink: ["Regional Traits","main/traits_regional"], jsx: <><h2 id="trait-crusader_road_acolyte-crusader-road-acolyte">Crusader Road Acolyte</h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> Echo Wood or Thornkeep</p>
<p>You trained with the <Link to="/rule/hellknights">Hellknights</Link> at Fort Inevitable or the paladins of Iomedae at Fort Riverwatch. If you trained with the Hellknights, you gain a +1 trait bonus on saving throws against chaotic spells and the spell-like abilities of chaotic outsiders. If you trained with the Iomedaean Paladins, you gain this bonus against evil spells and evil outsiders instead.</p>
<blockquote>
<p><strong>Sources</strong> <Link to="/source/people_of_the_river">People of the River</Link></p>
</blockquote>
</>};
const _crusader_tactician = {title: "Crusader Tactician", topLink: ["Regional Traits","main/traits_regional"], jsx: <><h2 id="trait-crusader_tactician-crusader-tactician">Crusader Tactician</h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> Lastwall</p>
<p>You have studied at Vigil's Crusader War College, and are skilled in both heraldry and siege tactics. You gain a +1 trait bonus on Knowledge (engineering) and Knowledge (nobility) checks, and one of these skills is always a class skill for you.</p>
<blockquote>
<p><strong>Sources</strong> <Link to="/source/inner_sea_primer">Inner Sea Primer</Link></p>
</blockquote>
</>};
const _cultist_lineage = {title: "Cultist Lineage", topLink: ["Regional Traits","main/traits_regional"], jsx: <><h2 id="trait-cultist_lineage-cultist-lineage">Cultist Lineage</h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> Mediogalti</p>
<p>Your parents were both Red Mantis assassins and your family has a long tradition of service in the <Link to="/rule/red_mantis">Red Mantis</Link> cult. Your strict, fanatical upbringing and familiarity with murder have bestowed upon you an air of confidence and menace. This grants you a +1 trait bonus on Intimidate checks. If you act during the surprise round, as a free action during that round you can draw a light weapon (or two if you have the <Link to="/feat/two_weapon_fighting">Two-Weapon Fighting</Link> feat).</p>
<blockquote>
<p><strong>Sources</strong> <Link to="/source/advanced_class_origins">Advanced Class Origins</Link></p>
</blockquote>
</>};
const _cultivated = {title: "Cultivated", topLink: ["Regional Traits","main/traits_regional"], jsx: <><h2 id="trait-cultivated-cultivated">Cultivated</h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> urban</p>
<p>You grew up speaking multiple <Link to="/misc/languages">languages</Link>. You learn one additional language. Additionally, when attempting a Diplomacy check to gather information using this language, you can do so in 1d6 &times; 10 minutes, rather than the normal 1d4 hours.</p>
<blockquote>
<p><strong>Sources</strong> <Link to="/source/heroes_of_the_streets">Heroes of the Streets</Link></p>
</blockquote>
</>};
const _cunning_liar = {title: "Cunning Liar", topLink: ["Regional Traits","main/traits_regional"], jsx: <><h2 id="trait-cunning_liar-cunning-liar">Cunning Liar</h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> urban</p>
<p>You were forced into hiding or willingly went on the run at a young age, and learned to reading others' interests to inform your lies. You can use your Intelligence or Wisdom modifier in place of your Charisma modifier on Bluff checks.</p>
<blockquote>
<p><strong>Sources</strong> <Link to="/source/heroes_of_the_streets">Heroes of the Streets</Link></p>
</blockquote>
</>};
const _curse_queller = {title: "Curse Queller", topLink: ["Regional Traits","main/traits_regional"], jsx: <><h2 id="trait-curse_queller-curse-queller">Curse Queller</h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> Osirion</p>
<p>Whenever a caster level check is required to treat an affliction with magic (such as when casting <Link to="/spell/remove_curse">remove curse</Link> on a cursed creature or object), you gain a +2 trait bonus on your caster level check. Additionally, you gain a +1 trait bonus on your saving throws against curses.</p>
<blockquote>
<p><strong>Sources</strong> <Link to="/source/healers_handbook">Healer's Handbook</Link></p>
</blockquote>
</>};
const _cynic = {title: "Cynic", topLink: ["Regional Traits","main/traits_regional"], jsx: <><h2 id="trait-cynic-cynic">Cynic</h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> Mendev</p>
<p>As a Mendevian native, you have seen all manner of people claiming holy motives, and you have learned to judge them by their deeds, rather than their words. You gain a +1 trait bonus on Sense Motive checks, and Sense Motive is always a class skill for you.</p>
<blockquote>
<p><strong>Sources</strong> <Link to="/source/inner_sea_primer">Inner Sea Primer</Link></p>
</blockquote>
</>};
const _cypher_resistance = {title: "Cypher Resistance", topLink: ["Regional Traits","main/traits_regional"], jsx: <><h2 id="trait-cypher_resistance-cypher-resistance">Cypher Resistance</h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> Riddleport</p>
<p>You have grown up near the Cyphergate, passing under its arch countless times in your lifetime. You can recount the runes from memory, and repeated exposure has imbued you with a faint resistance to runic magic. You gain a +2 trait bonus on saving throws against spells with the word <Link to="/main/spell_groupings">"glyph" or "symbol"</Link> in their name.</p>
<blockquote>
<p><strong>Sources</strong> <Link to="/source/varisia_birthplace_of_legends">Varisia, Birthplace of Legends</Link></p>
</blockquote>
</>};
const _cyphermage_backer = {title: "Cyphermage Backer", topLink: ["Regional Traits","main/traits_regional"], jsx: <><h2 id="trait-cyphermage_backer-cyphermage-backer">Cyphermage Backer</h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> Riddleport</p>
<p>You've sold relics to a <Link to="/rule/cyphermage">Cyphermage</Link> in the past, and she's agreed to assist you with future findings. When in Riddleport, you can use your contact to gain information about artifacts and history. Treat this ability as a single Knowledge (arcana) or Knowledge (history) check with a skill bonus of +15. You may make this check once per day that you spend in Riddleport. You can make a new check every day. Each time you do so, you can choose whether to use Knowledge (arcana) or Knowledge (history).</p>
<blockquote>
<p><strong>Sources</strong> <Link to="/source/pirates_of_the_inner_sea">Pirates of the Inner Sea</Link></p>
</blockquote>
</>};
const _darkblight_survivor = {title: "Darkblight Survivor", topLink: ["Regional Traits","main/traits_regional"], jsx: <><h2 id="trait-darkblight_survivor-darkblight-survivor">Darkblight Survivor</h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> Nirmathas</p>
<p>Your woodland home in Nirmathas struggles against the tenacious Darkblight, forcing you to steel yourself against its poisonous influence. You gain a +2 trait bonus on Fortitude saving throws against diseases and poisons inflicted by fey, plants, and forest-related hazards.</p>
<blockquote>
<p><strong>Sources</strong> <Link to="/source/people_of_the_wastes">People of the Wastes</Link></p>
</blockquote>
</>};
const _darklands_delver = {title: "Darklands Delver", topLink: ["Regional Traits","main/traits_regional"], jsx: <><h2 id="trait-darklands_delver-darklands-delver">Darklands Delver</h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> Darklands beneath Tian Xia</p>
<p>You are familiar with the byways and passages of Tian Xia's underworld. You gain a +1 trait bonus on Knowledge (dungeoneering) checks, and a +1 trait bonus on Survival checks made in the Darklands. One of these skills becomes class skill for you.</p>
<blockquote>
<p><strong>Sources</strong> <Link to="/source/dragon_empires_primer">Dragon Empires Primer</Link></p>
</blockquote>
</>};
const _debt_to_a_witch = {title: "Debt to a Witch", topLink: ["Regional Traits","main/traits_regional"], jsx: <><h2 id="trait-debt_to_a_witch-debt-to-a-witch">Debt to a Witch</h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> Irrisen</p>
<p>Your life was spared in youth by the magic of a White Witch healer who was using your survival to perpetuate her agenda. Her magic was painful, but it made your body stronger. You gain a +2 trait bonus on saving throws against spells with the cold descriptor and against the dangers of cold weather.</p>
<blockquote>
<p><strong>Sources</strong> <Link to="/source/healers_handbook">Healer's Handbook</Link></p>
</blockquote>
</>};
const _demon_eradicator = {title: "Demon Eradicator", topLink: ["Regional Traits","main/traits_regional"], jsx: <><h2 id="trait-demon_eradicator-demon-eradicator">Demon Eradicator</h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> Mendev</p>
<p>Anytime an outsider with the demon subtype must make a Will save against one of your spells, increase the DC of that save by +1.</p>
<blockquote>
<p><strong>Sources</strong> <Link to="/source/knights_of_the_inner_sea">Knights of the Inner Sea</Link></p>
</blockquote>
</>};
const _demon_proof_mind = {title: "Demon-Proof Mind", topLink: ["Regional Traits","main/traits_regional"], jsx: <><h2 id="trait-demon_proof_mind-demon-proof-mind">Demon-Proof Mind</h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> Sarkoris or The Worldwound</p>
<p>You are used to the maddening energy fluctuations emanating from the Worldwound, and have steeled your mind against their influence. You gain a +2 trait bonus on saving throws against the mind-affecting effects of evil outsiders.</p>
<blockquote>
<p><strong>Sources</strong> <Link to="/source/demon_hunters_handbook">Demon Hunter's Handbook</Link></p>
</blockquote>
</>};
const _demonbane_summoner = {title: "Demonbane Summoner", topLink: ["Regional Traits","main/traits_regional"], jsx: <><h2 id="trait-demonbane_summoner-demonbane-summoner">Demonbane Summoner</h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> The Worldwound</p>
<p>Your line is derived directly from the god callers of Sarkoris. You adamantly oppose the demonic forces of the Worldwound in hopes of reclaiming your lost lands. The attacks of creatures you summon are treated as cold iron for the purpose of overcoming damage reduction.</p>
<blockquote>
<p><strong>Sources</strong> <Link to="/source/monster_summoners_handbook">Monster Summoner's Handbook</Link></p>
</blockquote>
</>};
const _desert_child = {title: "Desert Child", topLink: ["Regional Traits","main/traits_regional"], jsx: <><h2 id="trait-desert_child-desert-child">Desert Child</h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> Thuvia, desert</p>
<p>You were born and raised in rocky deserts, and are accustomed to high temperatures. You gain a +4 trait bonus on saving throws made to resist the effects of being in hot conditions and a +1 trait bonus on saving throws against fire effects.</p>
<blockquote>
<p><strong>Sources</strong> <Link to="/source/ultimate_campaign">Ultimate Campaign</Link>, <Link to="/source/advanced_players_guide">Advanced Player's Guide</Link>, <Link to="/source/legacy_of_fire_players_guide">Legacy of Fire Player's Guide</Link>, <Link to="/source/inner_sea_primer">Inner Sea Primer</Link></p>
</blockquote>
</>};
const _destined_for_greatness = {title: "Destined for Greatness", topLink: ["Regional Traits","main/traits_regional"], jsx: <><h2 id="trait-destined_for_greatness-destined-for-greatness">Destined for Greatness</h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> Absalom</p>
<p>Ever since you were a child growing up in one of Absalom's vast city quarters, you've been obsessed with the Starstone Cathedral and the prospect of acquiring true divinity by passing the Test of the Starstone. Though it remains to be seen whether you will ever achieve your long-standing dream, your fascination with the would-be deities who enter the Starstone Cathedral and never come back has granted you no small measure of savvy when it comes to preparing to explore dungeons. You start with a kit worth no more than 300 gp, and the expendable contents of the kit are automatically restored to their original capacity at no cost to you whenever you enter a settlement with a population of at least 2,500.</p>
<p><strong>Suggestion:</strong> Consider playing a character who worships, reveres, or perhaps even envies one of the Ascended: Cayden Cailean, Iomedae, or Norgorber.</p>
<blockquote>
<p><strong>Sources</strong> <Link to="/source/dungeoneers_handbook">Dungeoneer's Handbook</Link></p>
</blockquote>
</>};
const _devilfish_diver = {title: "Devilfish Diver", topLink: ["Regional Traits","main/traits_regional"], jsx: <><h2 id="trait-devilfish_diver-devilfish-diver">Devilfish Diver</h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> Mediogalti</p>
<p>You've swum with the devilfish along the Mediogaltian coast. You gain a +2 trait bonus on saving throws versus poison.</p>
<blockquote>
<p><strong>Sources</strong> <Link to="/source/pirates_of_the_inner_sea">Pirates of the Inner Sea</Link></p>
</blockquote>
</>};
const _devotee_of_kalistrade = {title: "Devotee of Kalistrade", topLink: ["Regional Traits","main/traits_regional"], jsx: <><h2 id="trait-devotee_of_kalistrade-devotee-of-kalistrade">Devotee of Kalistrade</h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> Druma</p>
<p>As an adherent of the <Link to="/rule/prophecies_of_kalistrade">Prophecies of Kalistrade</Link>, you understand the importance of a good deal. You gain a +1 trait bonus on Appraise checks, and a +1 trait bonus on Bluff checks when trying to make a deal with nonbelievers.</p>
<blockquote>
<p><strong>Sources</strong> <Link to="/source/inner_sea_primer">Inner Sea Primer</Link></p>
</blockquote>
</>};
const _diligence = {title: "Diligence", topLink: ["Regional Traits","main/traits_regional"], jsx: <><h2 id="trait-diligence-diligence">Diligence</h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> urban</p>
<p>You grew up helping with a family business or were mentored by an expert in some craft or profession, who taught you diligence. Select one specific Craft or Profession skill. You can take 20 with that skill in half the amount of time normally required to take 20.</p>
<blockquote>
<p><strong>Sources</strong> <Link to="/source/heroes_of_the_streets">Heroes of the Streets</Link></p>
</blockquote>
</>};
const _dinosaur_whisperer = {title: "Dinosaur Whisperer", topLink: ["Regional Traits","main/traits_regional"], jsx: <><h2 id="trait-dinosaur_whisperer-dinosaur-whisperer">Dinosaur Whisperer</h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> Mediogalti</p>
<p>After spending a month in the Mediogaltian jungle, you developed a knack for dealing with dinosaurs. You gain a +1 trait bonus on Knowledge (nature) and Survival checks concerning dinosaurs. You also gain a +1 trait bonus on <Link to="/ability/wild_empathy">wild empathy</Link> checks made to affect dinosaurs.</p>
<blockquote>
<p><strong>Sources</strong> <Link to="/source/pirates_of_the_inner_sea">Pirates of the Inner Sea</Link></p>
</blockquote>
</>};
const _discerning_beliefs = {title: "Discerning Beliefs", topLink: ["Regional Traits","main/traits_regional"], jsx: <><h2 id="trait-discerning_beliefs-discerning-beliefs">Discerning Beliefs</h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> Zi Ha</p>
<p>You helped the samsarans maintain the magical boundaries around valleys in the Enlightened Peaks, and learned the secrets of avoiding such illusions yourself. You gain a +2 trait bonus on saving throws to disbelieve illusions.</p>
<blockquote>
<p><strong>Sources</strong> <Link to="/source/dragon_empires_primer">Dragon Empires Primer</Link></p>
</blockquote>
</>};
const _div_hunter = {title: "Div Hunter", topLink: ["Regional Traits","main/traits_regional"], jsx: <><h2 id="trait-div_hunter-div-hunter">Div Hunter</h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> Thuvia</p>
<p>Divs have tormented you and your loved ones for as long as you can remember. You've improved your skills to better oppose the creatures. You gain a +2 trait bonus on Knowledge checks to identify divs (and their special powers and weaknesses) and a +1 trait bonus on weapon damage rolls against divs.</p>
<blockquote>
<p><strong>Sources</strong> <Link to="/source/monster_summoners_handbook">Monster Summoner's Handbook</Link></p>
</blockquote>
</>};
const _divine_deceiver = {title: "Divine Deceiver", topLink: ["Regional Traits","main/traits_regional"], jsx: <><h2 id="trait-divine_deceiver-divine-deceiver">Divine Deceiver</h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> Razmiran</p>
<p>You are trained in the methods of Razmir's priesthood, and can use your arcana to fuel minor healing powers. Once per day as a full-round action, you can sacrifice a prepared arcane spell or spell slot to manifest healing magic. This acts as cure light wounds, except you heal 1d6 points of damage per level of the spell or spell slot sacrificed (maximum 5d6) and the hit points healed are temporary (lasting 1 hour).</p>
<blockquote>
<p><strong>Sources</strong> <Link to="/source/champions_of_corruption">Champions of Corruption</Link></p>
</blockquote>
</>};
const _dominator = {title: "Dominator", topLink: ["Regional Traits","main/traits_regional"], jsx: <><h2 id="trait-dominator-dominator">Dominator</h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> Belkzen</p>
<p>The blood of dominance runs thick in the savage home of orcs. You receive a +2 trait bonus on all attempts to demoralize an opponent in combat using the Intimidate skill.</p>
<blockquote>
<p><strong>Sources</strong> <Link to="/source/inner_sea_primer">Inner Sea Primer</Link>, <Link to="/source/orcs_of_golarion">Orcs of Golarion</Link></p>
</blockquote>
</>};
const _draconic_vigil = {title: "Draconic Vigil", topLink: ["Regional Traits","main/traits_regional"], jsx: <><h2 id="trait-draconic_vigil-draconic-vigil">Draconic Vigil</h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> Lastwall</p>
<p>As a defender of Lastwall, you have seen the damage the green dragon Zedoran has wrought upon the land. You gain a +1 bonus on initiative rolls when entering combat against creatures of the dragon type or humanoids of the orc subtype.</p>
<blockquote>
<p><strong>Sources</strong> <Link to="/source/dragonslayers_handbook">Dragonslayer's Handbook</Link></p>
</blockquote>
</>};
const _dreadful_forethought = {title: "Dreadful Forethought", topLink: ["Regional Traits","main/traits_regional"], jsx: <><h2 id="trait-dreadful_forethought-dreadful-forethought">Dreadful Forethought</h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> Ustalav</p>
<p>As a minor Ustalavic noble, you have friends linked to Karcau's fiendish cults. Your observations give you a keen insight into the blasphemies of the idle rich. You gain a +1 trait bonus on Knowledge (nobility) and Knowledge (planes) checks.</p>
<blockquote>
<p><strong>Sources</strong> <Link to="/source/demon_hunters_handbook">Demon Hunter's Handbook</Link></p>
</blockquote>
</>};
const _dtang_ma_bloodline = {title: "Dtang Ma Bloodline", topLink: ["Regional Traits","main/traits_regional"], jsx: <><h2 id="trait-dtang_ma_bloodline-dtang-ma-bloodline">Dtang Ma Bloodline</h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> Dtang Ma</p>
<p>As you were born in Dtang Ma and possess one of the favored bloodlines, your sorcerous powers are particularly potent. Select one of the following sorcerer bloodlines: fey, maestro, starsoul, or stormborn. Once per day, you may use one of your bloodline powers as if your sorcerer level were 1 higher than normal. This trait does not give you access to bloodline powers whose level requirements you do not yet meet.</p>
<blockquote>
<p><strong>Sources</strong> <Link to="/source/dragon_empires_primer">Dragon Empires Primer</Link></p>
</blockquote>
</>};
const _dump_salvager = {title: "Dump Salvager", topLink: ["Regional Traits","main/traits_regional"], jsx: <><h2 id="trait-dump_salvager-dump-salvager">Dump Salvager</h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> Westcrown</p>
<p>You grew up in or around Westcrown's rubbish-strewn shores and spent your spare time digging through trash looking for things worth selling. You gain a +3 trait bonus on Perception checks to search for concealed items.</p>
<blockquote>
<p><strong>Sources</strong> <Link to="/source/cheliax_empire_of_devils">Cheliax, Empire of Devils</Link></p>
</blockquote>
</>};
const _dungeon_dweller = {title: "Dungeon Dweller", topLink: ["Regional Traits","main/traits_regional"], jsx: <><h2 id="trait-dungeon_dweller-dungeon-dweller">Dungeon Dweller</h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> underground</p>
<p>Not only are you competent while deep underground, you thrive in these perilous environs. Whether you were born in one of the labyrinthine tunnels that riddle the islands of the Shackles or your mysterious parental figures brought you up in the sand-ridden corridors of some forgotten Osirian pyramid, your emergence on Golarion is somehow tied to one of the world's infamous subterranean dungeons. You start with one additional language chosen from the following list: Aklo, Dark Folk, Draconic, Goblin, Necril, Orc, or Undercommon. In addition, whenever you must attempt a Survival check to avoid getting lost in a dungeon, you may roll the check twice and take the better result.</p>
<p><strong>Suggestion:</strong> Consider playing an uncommon race.</p>
<blockquote>
<p><strong>Sources</strong> <Link to="/source/dungeoneers_handbook">Dungeoneer's Handbook</Link></p>
</blockquote>
</>};
const _dusk_dancer = {title: "Dusk Dancer", topLink: ["Regional Traits","main/traits_regional"], jsx: <><h2 id="trait-dusk_dancer-dusk-dancer">Dusk Dancer</h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> Nidal<br/><strong>Requirements:</strong> Halfling</p>
<p>Growing up in shadowy Nidal has given you the confidence to avoid hazards which you can barely see. You gain a +2 trait bonus on Reflex saves in dim light or darkness.</p>
<blockquote>
<p><strong>Sources</strong> <Link to="/source/halflings_of_golarion">Halflings of Golarion</Link></p>
</blockquote>
</>};
const _duskwalker_agent = {title: "Duskwalker Agent", topLink: ["Regional Traits","main/traits_regional"], jsx: <><h2 id="trait-duskwalker_agent-duskwalker-agent">Duskwalker Agent</h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> Katapesh</p>
<p>You spent a portion of your childhood working for the Duskwalkers, the guild responsible for policing and watching over all trade that takes place in Katapesh's notorious Nightstalls. You have quite a bit more spending cash than most others of your age as a result, and start with twice the normal amount of starting gold. In addition, your reputation remains strong in the Nightstalls, and any transactions you make there are always beneficial to you; items you sell net you an additional 10% profit, and items you purchase there are 10% cheaper than normal. This discount also applies to your starting gear.</p>
<blockquote>
<p><strong>Sources</strong> <Link to="/source/legacy_of_fire_players_guide">Legacy of Fire Player's Guide</Link></p>
</blockquote>
</>};
const _eager_combatant = {title: "Eager Combatant", topLink: ["Regional Traits","main/traits_regional"], jsx: <><h2 id="trait-eager_combatant-eager-combatant">Eager Combatant</h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> Riddleport</p>
<p>You're so excited to board other ships that you're frequently the first one over the rail, regardless of the danger. You gain a +1 trait bonus on attack rolls made while onboard an enemy ship.</p>
<blockquote>
<p><strong>Sources</strong> <Link to="/source/pirates_of_the_inner_sea">Pirates of the Inner Sea</Link></p>
</blockquote>
</>};
const _educated_druggist = {title: "Educated Druggist", topLink: ["Regional Traits","main/traits_regional"], jsx: <><h2 id="trait-educated_druggist-educated-druggist">Educated Druggist</h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> Osibu, Thuvia, Tian Xia, or Ustalav</p>
<p>Any alchemical remedies you administer that provide an alchemical bonus have that bonus increased by 1. These remedies also restore 1 hit point to the target in addition to their usual effects.</p>
<blockquote>
<p><strong>Sources</strong> <Link to="/source/healers_handbook">Healer's Handbook</Link></p>
</blockquote>
</>};
const _egorian_school_apprentice = {title: "Egorian School Apprentice", topLink: ["Regional Traits","main/traits_regional"], jsx: <><h2 id="trait-egorian_school_apprentice-egorian-school-apprentice">Egorian School Apprentice</h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> Egorian</p>
<p>You studied under one of the masters of the Egorian School style of architecture. You gain a +3 trait bonus on Knowledge (engineering) checks and a +2 trait bonus on Perception checks to find secret doors or traps in buildings built in the Egorian School style.</p>
<blockquote>
<p><strong>Sources</strong> <Link to="/source/cheliax_empire_of_devils">Cheliax, Empire of Devils</Link></p>
</blockquote>
</>};
const _elemental_endowment = {title: "Elemental Endowment", topLink: ["Regional Traits","main/traits_regional"], jsx: <><h2 id="trait-elemental_endowment-elemental-endowment">Elemental Endowment</h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> Osirion</p>
<p>You see the interactions between elementals as the epitome of balance; you've studied the traditional elemental bindings of Ancient Osirion and can draw upon their power. As an immediate action, once per day when you cast a spell with the air, earth, fire, or water descriptor, you can gain a number of temporary hit points equal to the spell's level. This effect lasts for 1 minute.</p>
<blockquote>
<p><strong>Sources</strong> <Link to="/source/champions_of_balance">Champions of Balance</Link></p>
</blockquote>
</>};
const _elemental_pupil = {title: "Elemental Pupil", topLink: ["Regional Traits","main/traits_regional"], jsx: <><h2 id="trait-elemental_pupil-elemental-pupil">Elemental Pupil</h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> Qadira</p>
<p>You have studied at the feet of the masters of Katheer's colleges of magic, and so increased your own mastery of the elements. Choose one of the following energy types: acid, cold, electricity, or fire. When casting a spell of 1st level or higher that deals damage of your chosen energy type, the spell deals 1 extra point of damage of this type.</p>
<blockquote>
<p><strong>Sources</strong> <Link to="/source/qadira_gateway_to_the_east">Qadira, Gateway to the East</Link></p>
</blockquote>
</>};
const _elemental_ties = {title: "Elemental Ties", topLink: ["Regional Traits","main/traits_regional"], jsx: <><h2 id="trait-elemental_ties-elemental-ties">Elemental Ties</h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> Osirion</p>
<p>Interactions with elementals are commonplace for you. You gain a +1 trait bonus on Diplomacy checks when dealing with creatures of the elemental type, and you begin play knowing one of the following languages as an additional bonus language: Aquan, Auran, Ignan, or Terran.</p>
<blockquote>
<p><strong>Sources</strong> <Link to="/source/monster_summoners_handbook">Monster Summoner's Handbook</Link></p>
</blockquote>
</>};
const _elven_bitterness = {title: "Elven Bitterness", topLink: ["Regional Traits","main/traits_regional"], jsx: <><h2 id="trait-elven_bitterness-elven-bitterness">Elven Bitterness</h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> Kyonin</p>
<p>Only the most cunning scouts of Kyonin are selected to serve as guards along the border between the elven nation and the dreaded Tanglebriar. Most who are sent to patrol those blighted reaches go with the aid of potent magical items and under the cloak of arcane disguise. You are either close with some who have guarded the elven homeland or know of the magical defenses used by the elves against their demonic foes. When you cast an enchantment spell on a chaotic evil outsider, the DC of that spell is increased by 2.</p>
<blockquote>
<p><strong>Sources</strong> <Link to="/source/demon_hunters_handbook">Demon Hunter's Handbook</Link></p>
</blockquote>
</>};
const _emberkin_imposter = {title: "Emberkin Imposter", topLink: ["Regional Traits","main/traits_regional"], jsx: <><h2 id="trait-emberkin_imposter-emberkin-imposter">Emberkin Imposter</h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> Qadira</p>
<p>You have found it is easier to be mistaken for someone with celestial blood than to reveal your true nature. You gain a +5 trait bonus on Disguise checks when pretending to be an aasimar, and a +2 trait bonus on Diplomacy checks against those you have convinced of your supposed celestial nature.</p>
<blockquote>
<p><strong>Sources</strong> <Link to="/source/qadira_jewel_of_the_east">Qadira, Jewel of the East</Link></p>
</blockquote>
</>};
const _emissary = {title: "Emissary", topLink: ["Regional Traits","main/traits_regional"], jsx: <><h2 id="trait-emissary-emissary">Emissary</h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> Kaer Maga</p>
<p>Accustomed to the strange residents of Kaer Maga, you have few prejudices. You gain a +2 trait bonus on Diplomacy checks when dealing with aberrations, monstrous humanoids, undead, and creatures with the giant subtype.</p>
<blockquote>
<p><strong>Sources</strong> <Link to="/source/varisia_birthplace_of_legends">Varisia, Birthplace of Legends</Link></p>
</blockquote>
</>};
const _empathic_diplomat = {title: "Empathic Diplomat", topLink: ["Regional Traits","main/traits_regional"], jsx: <><h2 id="trait-empathic_diplomat-empathic-diplomat">Empathic Diplomat</h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> Qadira or Osirion</p>
<p>You have long followed the path of common sense and empathic insight when using diplomacy. You modify your Diplomacy checks using your Wisdom modifier, not your Charisma modifier.</p>
<blockquote>
<p><strong>Sources</strong> <Link to="/source/qadira_jewel_of_the_east">Qadira, Jewel of the East</Link></p>
</blockquote>
</>};
const _empyreal_cultist = {title: "Empyreal Cultist", topLink: ["Regional Traits","main/traits_regional"], jsx: <><h2 id="trait-empyreal_cultist-empyreal-cultist">Empyreal Cultist</h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> Magnimar</p>
<p>Your faith in the empyreal lords - a host of good demigods - and your fascination with the legendary Angel of the Arvensoar have you constantly on the hopeful lookout for celestial messengers. Choose an empyreal lord as your patron deity. You gain Celestial as a bonus language and a +1 trait bonus on Diplomacy checks when dealing with good-aligned humanoids.</p>
<blockquote>
<p><strong>Sources</strong> <Link to="/source/varisia_birthplace_of_legends">Varisia, Birthplace of Legends</Link></p>
</blockquote>
</>};
const _enchanted_by_giants = {title: "Enchanted by Giants", topLink: ["Regional Traits","main/traits_regional"], jsx: <><h2 id="trait-enchanted_by_giants-enchanted-by-giants">Enchanted by Giants</h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> forest, jungle, or taiga</p>
<p>You are familiar with the primeval magic of forest-dwelling giants and have witnessed their close attention to the natural world around them, whether because your tribe engaged in trade with those giants or because you stumbled into their territory. The experience opened your eyes to the workings of nature and magic. You gain a +1 trait bonus on Survival checks and Spellcraft checks. You can always take 10 on Spellcraft checks to identify spell-like abilities.</p>
<p>Likely Regions: Kyonin, Lands of the Linnorm Kings, Mwangi Expanse, Nirmathas, River Kingdoms, Taldor.</p>
<blockquote>
<p><strong>Sources</strong> <Link to="/source/giant_hunters_handbook">Giant Hunter's Handbook</Link></p>
</blockquote>
</>};
const _enemy_of_the_undead = {title: "Enemy of the Undead", topLink: ["Regional Traits","main/traits_regional"], jsx: <><h2 id="trait-enemy_of_the_undead-enemy-of-the-undead">Enemy of the Undead</h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> Geb</p>
<p>Your disgust at the way the undead aristocracy of Geb treats the living has inspired hatred in you. You gain a +2 trait bonus on saving throws against any spells or spell-like abilities from an undead creature.</p>
<blockquote>
<p><strong>Sources</strong> <Link to="/source/inner_sea_primer">Inner Sea Primer</Link></p>
</blockquote>
</>};
const _eoxian_experiment = {title: "Eoxian Experiment", topLink: ["Regional Traits","main/traits_regional"], jsx: <><h2 id="trait-eoxian_experiment-eoxian-experiment">Eoxian Experiment</h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> Eox</p>
<p>You were raised on Eox, where you were overseen by alien forces and subjected to horrifying experimentation. You gain a +1 trait bonus on saving throws against pain effects and the spell-like abilities of undead.</p>
<blockquote>
<p><strong>Sources</strong> <Link to="/source/people_of_the_stars">People of the Stars</Link></p>
</blockquote>
</>};
const _equality_for_all = {title: "Equality for All", topLink: ["Regional Traits","main/traits_regional"], jsx: <><h2 id="trait-equality_for_all-equality-for-all">Equality for All</h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> Andoran<br/><strong>Requirements:</strong> Halfling</p>
<p>Even when facing foes much larger than yourself, you still embody the Andoran ethos of liberty. You gain a +2 trait bonus to your CMB and your CMD when facing opponents who are at least two sizes larger than you.</p>
<blockquote>
<p><strong>Sources</strong> <Link to="/source/halflings_of_golarion">Halflings of Golarion</Link></p>
</blockquote>
</>};
const _erutaki_sky_reader = {title: "Erutaki Sky Reader", topLink: ["Regional Traits","main/traits_regional"], jsx: <><h2 id="trait-erutaki_sky_reader-erutaki-sky-reader">Erutaki Sky Reader</h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> Crown of the World</p>
<p>Born in the Crown of the World, you learned to read the aurora and the night sky for portents. Once per day, you gain a +2 luck bonus on a single saving throw. You can apply this bonus after the saving throw is rolled but before the results are revealed.</p>
<blockquote>
<p><strong>Sources</strong> <Link to="/source/advanced_class_origins">Advanced Class Origins</Link></p>
</blockquote>
</>};
const _evident_supporter = {title: "Evident Supporter", topLink: ["Regional Traits","main/traits_regional"], jsx: <><h2 id="trait-evident_supporter-evident-supporter">Evident Supporter</h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> Galt</p>
<p>You know how best to appear supportive of the current regime despite the vagaries of a shifting government. The Sense Motive DC needed for a city guard, a politician, or other governmental functionary in a large town or larger settlement to gain a hunch about your trustworthiness is 25 (instead of 20). On a failed check, you're seen as trustworthy regardless of the situation.</p>
<blockquote>
<p><strong>Sources</strong> <Link to="/source/champions_of_balance">Champions of Balance</Link></p>
</blockquote>
</>};
const _exhibition_fighter = {title: "Exhibition Fighter", topLink: ["Regional Traits","main/traits_regional"], jsx: <><h2 id="trait-exhibition_fighter-exhibition-fighter">Exhibition Fighter</h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> Lung Wa</p>
<p>You fight at your best in martial arts tournaments, such as those once popular in Lung Wa and still common in Quain. While others may attempt to cheat or chafe against the constraints placed upon them, you thrive under such limitations. You gain a +1 bonus on attack and damage rolls when fighting as part of a tournament or other structured setting with rules and restrictions, so long as you do not break these rules.</p>
<blockquote>
<p><strong>Sources</strong> <Link to="/source/blood_of_the_ancients">Blood of the Ancients pg. 23</Link></p>
</blockquote>
</>};
const _exiled_scholar = {title: "Exiled Scholar", topLink: ["Regional Traits","main/traits_regional"], jsx: <><h2 id="trait-exiled_scholar-exiled-scholar">Exiled Scholar</h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> Nex</p>
<p>Since you were young, you've always been interested in the process of lichdom and what drives people to desire such a fate. Nexian officials marked you as a traitor and exiled you when they discovered your morbid fascination with the consummate undead, but you still benefit from your forbidden studies. You gain a +1 trait bonus on Knowledge (arcana) and (religion) checks. In addition, choose one Knowledge skill; you can attempt untrained checks with this skill as long as the DC is lower than 15.</p>
<blockquote>
<p><strong>Sources</strong> <Link to="/source/undead_slayers_handbook">Undead Slayer's Handbook</Link></p>
</blockquote>
</>};
const _expert_smuggler = {title: "Expert Smuggler", topLink: ["Regional Traits","main/traits_regional"], jsx: <><h2 id="trait-expert_smuggler-expert-smuggler">Expert Smuggler</h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> Erages</p>
<p>Years of smuggling and other unsavory work have trained you to hide your assets even when being actively searched. Other creatures never gain the +4 bonus on their Perception checks (opposed by your Sleight of Hand check) while frisking you.</p>
<blockquote>
<p><strong>Sources</strong> <Link to="/source/bastards_of_golarion">Bastards of Golarion</Link></p>
</blockquote>
</>};
const _expert_swimmer = {title: "Expert Swimmer", topLink: ["Regional Traits","main/traits_regional"], jsx: <><h2 id="trait-expert_swimmer-expert-swimmer">Expert Swimmer</h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> River Kingdoms</p>
<p>Most pirates on the ocean view falling overboard as a death sentence, but in the River Kingdoms, it's often a key part of the strategy. You gain a +1 trait bonus on Swim checks, and it becomes a class skill for you.</p>
<blockquote>
<p><strong>Sources</strong> <Link to="/source/pirates_of_the_inner_sea">Pirates of the Inner Sea</Link></p>
</blockquote>
</>};
const _eye_of_the_falcon = {title: "Eye of the Falcon", topLink: ["Regional Traits","main/traits_regional"], jsx: <><h2 id="trait-eye_of_the_falcon-eye-of-the-falcon">Eye of the Falcon</h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> Andoran</p>
<p>You have a way of seeing right to the heart of things. You gain a +1 trait bonus on saving throws against illusion (phantasm) spells and a +1 trait bonus on Sense Motive checks to know when you are being lied to, so long as you are face to face with the speaker in question.</p>
<blockquote>
<p><strong>Sources</strong> <Link to="/source/knights_of_the_inner_sea">Knights of the Inner Sea</Link></p>
</blockquote>
</>};
const _fangwood_diplomat = {title: "Fangwood Diplomat", topLink: ["Regional Traits","main/traits_regional"], jsx: <><h2 id="trait-fangwood_diplomat-fangwood-diplomat">Fangwood Diplomat</h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> Nirmathas</p>
<p>You've lived and worked among the disparate guerrilla groups of the Fangwood. You gain a +1 trait bonus on Diplomacy checks, and Diplomacy is always a class skill for you.</p>
<blockquote>
<p><strong>Sources</strong> <Link to="/source/inner_sea_primer">Inner Sea Primer</Link></p>
</blockquote>
</>};
const _fangwood_insurgent = {title: "Fangwood Insurgent", topLink: ["Regional Traits","main/traits_regional"], jsx: <><h2 id="trait-fangwood_insurgent-fangwood-insurgent">Fangwood Insurgent</h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> Nirmathas</p>
<p>You have spent many years living under the canopy of the Southern Fangwood, during which you and your comrades clashed regularly with the soldiers of imperialist Molthune. After years of guerrilla warfare, you've learned to interpret the sounds of the forest to detect signs of enemies. You gain a +1 trait bonus on initiative checks when in a forest. Once per day when in a forest, you can designate yourself or an ally to roll twice for initiative and take either result.</p>
<blockquote>
<p><strong>Sources</strong> <Link to="/source/advanced_class_origins">Advanced Class Origins</Link></p>
</blockquote>
</>};
const _fey_hex = {title: "Fey Hex", topLink: ["Regional Traits","main/traits_regional"], jsx: <><h2 id="trait-fey_hex-fey-hex">Fey Hex</h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> Irrisen</p>
<p>You have learned to incorporate fey enchantments into your hexes to snare victims that shake off your curses. Once per day as a free action, when a creature succeeds at its saving throw against your hex that cannot target the same creature more than once per day, you can declare that creature to be subject to your fey hex. You can attempt the failed hex against the creature a second time, so long as you do so within 1 minute.</p>
<blockquote>
<p><strong>Sources</strong> <Link to="/source/legacy_of_the_first_world">Legacy of the First World</Link></p>
</blockquote>
</>};
const _fey_mediator = {title: "Fey Mediator", topLink: ["Regional Traits","main/traits_regional"], jsx: <><h2 id="trait-fey_mediator-fey-mediator">Fey Mediator</h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> Grungir Forest</p>
<p>You gain Sylvan as a bonus language. Additionally, choose Bluff, Diplomacy, or Knowledge (nature). That skill is a class skill for you.</p>
<blockquote>
<p><strong>Sources</strong> <Link to="/source/legacy_of_the_first_world">Legacy of the First World</Link></p>
</blockquote>
</>};
const _fey_wise = {title: "Fey-Wise", topLink: ["Regional Traits","main/traits_regional"], jsx: <><h2 id="trait-fey_wise-fey-wise">Fey-Wise</h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> Sevenarches</p>
<p>You grew up around fey and are accustomed to their tricks. You gain a +1 trait bonus on saving throws against the spell-like and supernatural abilities of fey and a +1 trait bonus on Sense Motive checks against fey.</p>
<blockquote>
<p><strong>Sources</strong> <Link to="/source/people_of_the_river">People of the River</Link></p>
</blockquote>
</>};
const _fiery_dominance = {title: "Fiery Dominance", topLink: ["Regional Traits","main/traits_regional"], jsx: <><h2 id="trait-fiery_dominance-fiery-dominance">Fiery Dominance</h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> Plane of Fire</p>
<p>Raised among the efreet of the Plane of Fire, you developed a similarly assured sense of superiority over people from other backgrounds. You gain a +1 trait bonus on Intimidate checks against humanoids of a subtype different from your own (or all non-human humanoids, if you are not a humanoid), and the DC for such creatures to demoralize you with Intimidate is 2 higher than usual.</p>
<blockquote>
<p><strong>Sources</strong> <Link to="/source/blood_of_the_elements">Blood of the Elements</Link></p>
</blockquote>
</>};
const _fight_for_liberty = {title: "Fight for Liberty", topLink: ["Regional Traits","main/traits_regional"], jsx: <><h2 id="trait-fight_for_liberty-fight-for-liberty">Fight for Liberty</h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> Andoran</p>
<p>You inspire slaves to fight for freedom with a rousing battle cry. As a standard action, you may make a rallying cry with a DC 15 Perform (oratory) check. On a successful check, any unarmed ally within 30 feet who is able to hear you gains a +2 trait bonus on attack rolls with improvised weapons and unarmed strikes. This bonus lasts for 1 round per level.</p>
<blockquote>
<p><strong>Sources</strong> <Link to="/source/pirates_of_the_inner_sea">Pirates of the Inner Sea</Link></p>
</blockquote>
</>};
const _flotsam = {title: "Flotsam", topLink: ["Regional Traits","main/traits_regional"], jsx: <><h2 id="trait-flotsam-flotsam">Flotsam</h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> The Shackles</p>
<p>You were one of only a few that survived the destruction of the merchant vessel Vantage. Your crew was more than able to hold off the blundering pirate attackers, but their red dragon ally proved too much for your defenses. As you watched the sharks and eels feast on the bodies of your fallen comrades, you vowed to see Aashaq slain. You gain a +2 bonus on Reflex saves against spells and effects with the fire descriptor.</p>
<blockquote>
<p><strong>Sources</strong> <Link to="/source/dragonslayers_handbook">Dragonslayer's Handbook</Link></p>
</blockquote>
</>};
const _footsteps_of_aganhei = {title: "Footsteps of Aganhei", topLink: ["Regional Traits","main/traits_regional"], jsx: <><h2 id="trait-footsteps_of_aganhei-footsteps-of-aganhei">Footsteps of Aganhei</h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> Crown of the World</p>
<p>You are one of the brave travelers who have traversed the Path of Aganhei, a lucrative trade route from Tian Xia to Avistan that crosses the frigid Crown of the World. These voyages have left you hardier, granting you a +1 trait bonus on Fortitude saving throws to resist the effects of cold weather. Survival is a class skill for you, and you gain Hallit, Hon-La, Minkaian, Skald, or Tien as a bonus language.</p>
<blockquote>
<p><strong>Sources</strong> <Link to="/source/merchants_manifest">Merchant's Manifest</Link></p>
</blockquote>
</>};
const _forbidden_knowledge = {title: "Forbidden Knowledge", topLink: ["Regional Traits","main/traits_regional"], jsx: <><h2 id="trait-forbidden_knowledge-forbidden-knowledge">Forbidden Knowledge</h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> Geb</p>
<p>As a child, you somehow got your hands on a lurid, forbidden text written by a now-forgotten Blood Lord of ages past. You studied the details within intently, learning much about extraplanar undead from beyond this reality, and you developed a strange, almost macabre way of thinking because of this book's influence. Anytime you would roll a Knowledge (planes) check, you may roll a Knowledge (history) or Knowledge (religion) check instead.</p>
<blockquote>
<p><strong>Sources</strong> <Link to="/source/undead_slayers_handbook">Undead Slayer's Handbook</Link></p>
</blockquote>
</>};
const _fortune_found = {title: "Fortune Found", topLink: ["Regional Traits","main/traits_regional"], jsx: <><h2 id="trait-fortune_found-fortune-found">Fortune Found</h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> Katapesh<br/><strong>Requirements:</strong> Vanara</p>
<p>You have learned a great many tricks and techniques for bartering with humans. You gain a +1 trait bonus on Appraise and Diplomacy checks, and one of these skills (your choice) is a class skill for you.</p>
<blockquote>
<p><strong>Sources</strong> <Link to="/source/blood_of_the_beast">Blood of the Beast</Link></p>
</blockquote>
</>};
const _free_agent = {title: "Free Agent", topLink: ["Regional Traits","main/traits_regional"], jsx: <><h2 id="trait-free_agent-free-agent">Free Agent</h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> River Kingdoms</p>
<p>You embody the independent spirit of the River Kingdoms and do best when sailing under your own flag, in every sense. You gain a +2 trait bonus on Will saves to avoid charm and compulsion effects.</p>
<blockquote>
<p><strong>Sources</strong> <Link to="/source/pirates_of_the_inner_sea">Pirates of the Inner Sea</Link></p>
</blockquote>
</>};
const _free_people = {title: "Free People", topLink: ["Regional Traits","main/traits_regional"], jsx: <><h2 id="trait-free_people-free-people">Free People</h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> Realm of the Mammoth Lords<br/><strong>Requirements:</strong> Kellid</p>
<p>The independent tribes from the Realm of the Mammoth Lords hold little regard for the control others wield over free people. Their willful, independent streak makes them suspicious of any attempt to guide their behavior. You gain a +1 trait bonus on Sense Motive checks and on Will saves against mind-affecting effects.</p>
<blockquote>
<p><strong>Sources</strong> <Link to="/source/heroes_from_the_fringe">Heroes from the Fringe</Link></p>
</blockquote>
</>};
const _freed_slave_andoran = {title: "Freed Slave (Andoran)", topLink: ["Regional Traits","main/traits_regional"], jsx: <><h2 id="trait-freed_slave_andoran-freed-slave-andoran">Freed Slave (Andoran)</h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> Andoran</p>
<p>You were either born or sold into slavery, but were freed by Andoren abolitionists. Your strong will helped you persevere in captivity, and gave you strength to start again from nothing in your new life in Andoran. You gain a +1 trait bonus on Will saves.</p>
<blockquote>
<p><strong>Sources</strong> <Link to="/source/inner_sea_primer">Inner Sea Primer</Link></p>
</blockquote>
</>};
const _freed_slave_katapesh = {title: "Freed Slave (Katapesh)", topLink: ["Regional Traits","main/traits_regional"], jsx: <><h2 id="trait-freed_slave_katapesh-freed-slave-katapesh">Freed Slave (Katapesh)</h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> Katapesh</p>
<p>You spent a significant portion of your childhood as a slave, but were freed from slavery several years ago by a benevolent master who purchased you from an auction after your previous master's death. Yet while the memories of your difficult childhood still haunt you, the hard life did toughen you. You gain a +1 trait bonus on Fortitude saves.</p>
<blockquote>
<p><strong>Sources</strong> <Link to="/source/legacy_of_fire_players_guide">Legacy of Fire Player's Guide</Link></p>
</blockquote>
</>};
const _freedom_fighter_andoran = {title: "Freedom Fighter (Andoran)", topLink: ["Regional Traits","main/traits_regional"], jsx: <><h2 id="trait-freedom_fighter_andoran-freedom-fighter-andoran">Freedom Fighter (Andoran)</h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> Andoran</p>
<p>You've developed a reputation as a privateer who fights for freedom. You gain a +2 trait bonus on Diplomacy checks. This bonus becomes a -2 penalty when dealing with slavers or those who support the slave trade. Diplomacy becomes a class skill for you.</p>
<blockquote>
<p><strong>Sources</strong> <Link to="/source/pirates_of_the_inner_sea">Pirates of the Inner Sea</Link></p>
</blockquote>
</>};
const _freedom_fighter_shokuro = {title: "Freedom Fighter (Shokuro)", topLink: ["Regional Traits","main/traits_regional"], jsx: <><h2 id="trait-freedom_fighter_shokuro-freedom-fighter-shokuro">Freedom Fighter (Shokuro)</h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> Shokuro</p>
<p>You come from a family of farmers, but are determined to fight for your rights. You gain a +1 trait bonus on attacks made with improvised weapons. If you do not possess the <Link to="/feat/catch_off_guard">Catch Off-Guard</Link> or <Link to="/feat/throw_anything">Throw Anything</Link> feats, you still take penalties on these attack rolls as normal.</p>
<blockquote>
<p><strong>Sources</strong> <Link to="/source/dragon_empires_primer">Dragon Empires Primer</Link></p>
</blockquote>
</>};
const _friend_of_the_dead = {title: "Friend of the Dead", topLink: ["Regional Traits","main/traits_regional"], jsx: <><h2 id="trait-friend_of_the_dead-friend-of-the-dead">Friend of the Dead</h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> Geb</p>
<p>Your close association with the intelligent undead of Geb has imparted some of their otherworldly essence to you, and this essence helps you in your dealings with the undead. You gain a +2 trait bonus on Diplomacy checks against sentient undead.</p>
<blockquote>
<p><strong>Sources</strong> <Link to="/source/inner_sea_primer">Inner Sea Primer</Link></p>
</blockquote>
</>};
const _friend_of_the_fey = {title: "Friend of the Fey", topLink: ["Regional Traits","main/traits_regional"], jsx: <><h2 id="trait-friend_of_the_fey-friend-of-the-fey">Friend of the Fey</h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> Lands of the Linnorm Kings</p>
<p>You have a special relationship with the fey, having grown up in close proximity to them. You gain a +2 trait bonus on Diplomacy checks against fey creatures.</p>
<blockquote>
<p><strong>Sources</strong> <Link to="/source/inner_sea_primer">Inner Sea Primer</Link></p>
</blockquote>
</>};
const _frontier_forged = {title: "Frontier-Forged", topLink: ["Regional Traits","main/traits_regional"], jsx: <><h2 id="trait-frontier_forged-frontier-forged">Frontier-Forged</h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> frontier</p>
<p>A hard life on the edge of civilization has made you resourceful but has also given you a streak of self-preservation bordering on paranoia. You receive a +1 trait bonus on Perception checks and a +1 bonus on Survival checks made to get along in the wild.</p>
<blockquote>
<p><strong>Sources</strong> <Link to="/source/ultimate_campaign">Ultimate Campaign</Link></p>
</blockquote>
</>};
const _frostborn = {title: "Frostborn", topLink: ["Regional Traits","main/traits_regional"], jsx: <><h2 id="trait-frostborn-frostborn">Frostborn</h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> Lands of the Linnorm Kings</p>
<p>Long nights in the frigid winters of the north have inured you to cold. You gain a +4 trait bonus on any savings throws made to resist the effects of cold environments, as well as a +1 trait bonus on all saving throws against cold effects.</p>
<blockquote>
<p><strong>Sources</strong> <Link to="/source/dwarves_of_golarion">Dwarves of Golarion</Link></p>
</blockquote>
</>};
const _fruit_merchant = {title: "Fruit Merchant", topLink: ["Regional Traits","main/traits_regional"], jsx: <><h2 id="trait-fruit_merchant-fruit-merchant">Fruit Merchant</h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> jungle</p>
<p>When bartering for mundane items like food, water, and clothing, you can purchase supplies for 10% less and sell them for 10% more.</p>
<blockquote>
<p><strong>Sources</strong> <Link to="/source/wilderness_origins">Wilderness Origins</Link></p>
</blockquote>
</>};
const _gallant_imposter = {title: "Gallant Imposter", topLink: ["Regional Traits","main/traits_regional"], jsx: <><h2 id="trait-gallant_imposter-gallant-imposter">Gallant Imposter</h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> Mendev</p>
<p>You gain a +1 trait bonus on Knowledge (nobility) and Knowledge (religion) checks. In addition, you gain a +2 trait bonus on both Disguise and Bluff checks while attempting to impersonate a knight.</p>
<blockquote>
<p><strong>Sources</strong> <Link to="/source/knights_of_the_inner_sea">Knights of the Inner Sea</Link></p>
</blockquote>
</>};
const _genie_caller = {title: "Genie-Caller", topLink: ["Regional Traits","main/traits_regional"], jsx: <><h2 id="trait-genie_caller-genie-caller">Genie-Caller</h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> Qadira</p>
<p>Your exploration of the magic for calling genies has increased your overall aptitude for summoning. Once per day, you may cast one conjuration (summoning) spell as if your caster level were 2 higher than normal.</p>
<blockquote>
<p><strong>Sources</strong> <Link to="/source/inner_sea_primer">Inner Sea Primer</Link>, <Link to="/source/qadira_gateway_to_the_east">Qadira, Gateway to the East</Link></p>
</blockquote>
</>};
const _ghost_survivor = {title: "Ghost Survivor", topLink: ["Regional Traits","main/traits_regional"], jsx: <><h2 id="trait-ghost_survivor-ghost-survivor">Ghost Survivor</h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> Ustalav</p>
<p>You spent a single night in Harrowstone and managed to survive the terrifying ordeal, though you bore witness to ghosts and numerous other horrors during your short stay. You gain a +2 trait bonus on Knowledge (religion) checks to identify incorporeal undead and a +2 trait bonus on Fortitude saving throws against effects that inflict negative levels.</p>
<blockquote>
<p><strong>Sources</strong> <Link to="/source/undead_slayers_handbook">Undead Slayer's Handbook</Link></p>
</blockquote>
</>};
const _ghoulish_affinity = {title: "Ghoulish Affinity", topLink: ["Regional Traits","main/traits_regional"], jsx: <><h2 id="trait-ghoulish_affinity-ghoulish-affinity">Ghoulish Affinity</h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> Darklands</p>
<p>Ever since you recovered from ghoul fever, the scars on your arms and hands itch whenever one of these vile creatures is nearby. You gain a +2 trait bonus on Perception checks to notice undead disguised as living creatures, and a +2 trait bonus on Fortitude saves against diseases and poisons inflicted by undead.</p>
<blockquote>
<p><strong>Sources</strong> <Link to="/source/undead_slayers_handbook">Undead Slayer's Handbook</Link></p>
</blockquote>
</>};
const _giant_ambivalence = {title: "Giant Ambivalence", topLink: ["Regional Traits","main/traits_regional"], jsx: <><h2 id="trait-giant_ambivalence-giant-ambivalence">Giant Ambivalence</h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> temperate highlands</p>
<p>You witnessed or were otherwise strongly influenced by two separate acts by giants, one of great beneficence and one of great violence. You reflexively gauge the intentions of powerful creatures in case they turn to violence. You gain a +1 trait bonus on initiative checks. You also gain a +1 trait bonus on Sense Motive checks, and a +2 trait bonus on Perception checks to not be surprised in a surprise round of combat.</p>
<p>Likely Regions: Isger, Molthune, Numeria, Realm of the Mammoth Lords, Varisia.</p>
<p>Likely giants: Cloud, Hill, River, Stone</p>
<blockquote>
<p><strong>Sources</strong> <Link to="/source/giant_hunters_handbook">Giant Hunter's Handbook</Link></p>
</blockquote>
</>};
const _giant_dodger = {title: "Giant Dodger", topLink: ["Regional Traits","main/traits_regional"], jsx: <><h2 id="trait-giant_dodger-giant-dodger">Giant Dodger</h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> desert</p>
<p>In your youth, you were chased by giants for trespassing - or for sport - and you have learned to evade the reach of your opponents. You gain a +3 bonus on Acrobatics checks to avoid provoking an attack of opportunity when moving out of a threatened space.</p>
<p>Likely Regions: Katapesh, Osirion, Qadira, Rahadoum, Thuvia.</p>
<p>Likely giants: Cliff, Desert, River</p>
<blockquote>
<p><strong>Sources</strong> <Link to="/source/giant_hunters_handbook">Giant Hunter's Handbook</Link></p>
</blockquote>
</>};
const _giant_investigator = {title: "Giant Investigator", topLink: ["Regional Traits","main/traits_regional"], jsx: <><h2 id="trait-giant_investigator-giant-investigator">Giant Investigator</h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> coastal</p>
<p>As a result of your attempts to understand a rare encounter with the unearthly divine magic or secretive movements of coast-dwelling giants, you have learned to carefully consider all facts related to a mystery and form deductions after taking time to mull over an unanswered question. Whenever you fail a Knowledge (local) or Knowledge (religion) check, you can attempt the check again in 24 hours with a +2 bonus to represent your careful formation of a new deduction. Additionally, you can attempt such skill checks untrained when the checks involve giants.</p>
<p>Likely Regions: Katapesh, Lands of the Linnorm Kings, Mwangi Expanse, Rahadoum, the Shackles, Varisia.</p>
<p>Likely giants: Marsh, Ocean, River, Storm, Taiga</p>
<blockquote>
<p><strong>Sources</strong> <Link to="/source/giant_hunters_handbook">Giant Hunter's Handbook</Link></p>
</blockquote>
</>};
const _giant_harried = {title: "Giant-Harried", topLink: ["Regional Traits","main/traits_regional"], jsx: <><h2 id="trait-giant_harried-giant-harried">Giant-Harried</h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> wasteland</p>
<p>You were robbed by giants or nearly killed by a giant's prank, and the experience gave you a keen instinct for outmaneuvering bigger creatures. You gain a +1 trait bonus on combat maneuver checks against creatures larger than you and a +1 trait bonus to CMD against such creatures.</p>
<p>Likely Regions: Geb, Mana Wastes, Nex, Nidal, Numeria.</p>
<p>Likely giants: Ash, Hill, River, Shadow</p>
<blockquote>
<p><strong>Sources</strong> <Link to="/source/giant_hunters_handbook">Giant Hunter's Handbook</Link></p>
</blockquote>
</>};
const _glory_of_old = {title: "Glory of Old", topLink: ["Regional Traits","main/traits_regional"], jsx: <><h2 id="trait-glory_of_old-glory-of-old">Glory of Old</h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> Five Kings Mountains</p>
<p>In your veins flows the blood of dwarven heroes from Tar Taargadth. You receive a +1 trait bonus on saving throws against spells, spell-like abilities, and poison.</p>
<blockquote>
<p><strong>Sources</strong> <Link to="/source/dwarves_of_golarion">Dwarves of Golarion</Link></p>
</blockquote>
</>};
const _goblin_pirate = {title: "Goblin Pirate", topLink: ["Regional Traits","main/traits_regional"], jsx: <><h2 id="trait-goblin_pirate-goblin-pirate">Goblin Pirate</h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> The Shackles<br/><strong>Requirements:</strong> Goblin</p>
<p>Although you might prefer life on board a ship, you often end up in the water for some odd reason. You gain a +1 trait bonus on Profession (sailor) and Swim checks, and Swim is always a class skill for you. You might also have a peg leg or a hook for a hand, but that's not so helpful.</p>
<blockquote>
<p><strong>Sources</strong> <Link to="/source/goblins_of_golarion">Goblins of Golarion</Link></p>
</blockquote>
</>};
const _godless_resolve = {title: "Godless Resolve", topLink: ["Regional Traits","main/traits_regional"], jsx: <><h2 id="trait-godless_resolve-godless-resolve">Godless Resolve</h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> Bachuan, Rahadoum or Touvette</p>
<p>Some brilliant and earnest speech or other performance inspired you to take charge of your own health rather than begging indifferent or outlawed deities for deliverance. Heal is a class skill for you, and you gain a +2 trait bonus on Heal checks to stabilize dying creatures and stop bleeding.</p>
<blockquote>
<p><strong>Sources</strong> <Link to="/source/healers_handbook">Healer's Handbook</Link></p>
</blockquote>
</>};
const _gold_goblin_regular = {title: "Gold Goblin Regular", topLink: ["Regional Traits","main/traits_regional"], jsx: <><h2 id="trait-gold_goblin_regular-gold-goblin-regular">Gold Goblin Regular</h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> Riddleport</p>
<p>You're a frequent customer at the Gold Goblin Gambling Hall and enjoy some popularity within its walls. You gain a +1 trait bonus on Profession (gambling) checks and a +2 trait bonus on Diplomacy checks made to gather information when in Riddleport.</p>
<blockquote>
<p><strong>Sources</strong> <Link to="/source/pirates_of_the_inner_sea">Pirates of the Inner Sea</Link></p>
</blockquote>
</>};
const _good_folk = {title: "Good Folk", topLink: ["Regional Traits","main/traits_regional"], jsx: <><h2 id="trait-good_folk-good-folk">Good Folk</h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> urban</p>
<p>People's faith in you tends to run deeper than their trust of others. You gain a +2 bonus on Charisma checks and Charisma-based skill checks with creatures that have a friendly or helpful attitude towards you.</p>
<blockquote>
<p><strong>Sources</strong> <Link to="/source/heroes_of_the_streets">Heroes of the Streets</Link></p>
</blockquote>
</>};
const _gravelwalker = {title: "Gravelwalker", topLink: ["Regional Traits","main/traits_regional"], jsx: <><h2 id="trait-gravelwalker-gravelwalker">Gravelwalker</h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> Darklands</p>
<p>Having grown up navigating rockslides and picking your way through partially collapsed tunnels, you are able to determine the most stable path across difficult terrain caused by rubble or other debris. You can move normally through such obstructed spaces, and can run or charge though them with a successful Acrobatics check.</p>
<blockquote>
<p><strong>Sources</strong> <Link to="/source/kobolds_of_golarion">Kobolds of Golarion</Link></p>
</blockquote>
</>};
const _greenskin_stalker = {title: "Greenskin Stalker", topLink: ["Regional Traits","main/traits_regional"], jsx: <><h2 id="trait-greenskin_stalker-greenskin-stalker">Greenskin Stalker</h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> Isger, River Kingdoms, or Varisia</p>
<p>You're a member of the Greenskin Stalkers. Due to your affiliation with this brotherhood of goblin slayers, you've learned to think and act like a goblin, as disturbing as that sounds. You receive a +1 trait bonus on Bluff, Knowledge, Perception, Sense Motive, and Survival checks against or concerning goblinoids. You can also attempt Knowledge checks concerning goblinoids untrained.</p>
<blockquote>
<p><strong>Sources</strong> <Link to="/source/advanced_class_origins">Advanced Class Origins</Link></p>
</blockquote>
</>};
const _grit_goggles = {title: "Grit Goggles", topLink: ["Regional Traits","main/traits_regional"], jsx: <><h2 id="trait-grit_goggles-grit-goggles">Grit Goggles</h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> Darklands</p>
<p>Exposure to the constant hazards of airborne particles (such as during a sandstorm or cave-in) has made your eyes less susceptible to irritants, such as sand, dust, and even liquids and gases. You gain a +2 trait bonus against being blinded by foreign objects (such as from a Dirty Trick combat maneuver) and you halve any reductions in visibility from the environment (such as from certain storms) and their corresponding penalties. For example, if you were in a sandstorm that normally reduces visibility to 25 feet and imparts a -4 penalty on Perception checks, you reduce visibility to 50 feet and take only a -2 penalty on Perception checks.</p>
<blockquote>
<p><strong>Sources</strong> <Link to="/source/kobolds_of_golarion">Kobolds of Golarion</Link></p>
</blockquote>
</>};
const _guerilla = {title: "Guerilla", topLink: ["Regional Traits","main/traits_regional"], jsx: <><h2 id="trait-guerilla-guerilla">Guerilla</h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> Dtang Ma</p>
<p>You have spent much time in the rainforests of Dtang Ma, and know its secrets. You gain a +1 trait bonus on Knowledge (nature) checks as well as Survival checks made in the rainforest. One of these skills becomes a class skill for you.</p>
<blockquote>
<p><strong>Sources</strong> <Link to="/source/dragon_empires_primer">Dragon Empires Primer</Link></p>
</blockquote>
</>};
const _guerrilla_mender = {title: "Guerrilla Mender", topLink: ["Regional Traits","main/traits_regional"], jsx: <><h2 id="trait-guerrilla_mender-guerrilla-mender">Guerrilla Mender</h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> Nirmathas</p>
<p>With the help of a druidic healer, you narrowly escaped death by disease or poisoning while on the run from Molthuni militias, whether contracting the ailment was an accident or you were the victim of more sinister forces. Whenever you successfully use the Heal skill to treat an ally's poison or disease, you grant the ally an additional +1 trait bonus on the saving throw against the disease or poison. Heal is a class skill for you.</p>
<blockquote>
<p><strong>Sources</strong> <Link to="/source/healers_handbook">Healer's Handbook</Link></p>
</blockquote>
</>};
const _heart_of_clay = {title: "Heart of Clay", topLink: ["Regional Traits","main/traits_regional"], jsx: <><h2 id="trait-heart_of_clay-heart-of-clay">Heart of Clay</h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> Lingshen</p>
<p>You believe you are destined for an afterlife of service as part of King Huang's terra-cotta army, so you do not fear death as others do. You gain a +1 trait bonus on Fortitude saves.</p>
<blockquote>
<p><strong>Sources</strong> <Link to="/source/dragon_empires_primer">Dragon Empires Primer</Link></p>
</blockquote>
</>};
const _heavenly_touch = {title: "Heavenly Touch", topLink: ["Regional Traits","main/traits_regional"], jsx: <><h2 id="trait-heavenly_touch-heavenly-touch">Heavenly Touch</h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> Tianjing</p>
<p>Growing up, you were exposed to everyday miracles performed by your half-celestial friends, and some of this magic rubbed off. At will, you can touch a dying creature to stabilize it as a standard action.</p>
<blockquote>
<p><strong>Sources</strong> <Link to="/source/dragon_empires_primer">Dragon Empires Primer</Link></p>
</blockquote>
</>};
const _heir_of_chu_ye = {title: "Heir of Chu Ye", topLink: ["Regional Traits","main/traits_regional"], jsx: <><h2 id="trait-heir_of_chu_ye-heir-of-chu-ye">Heir of Chu Ye</h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> Tian Xia</p>
<p>If you would take a penalty for using the Heal skill to treat deadly wounds without one or more uses of a healer's kit, that penalty is reduced by 2 (minimum no penalty). Additionally, a creature can benefit from you treating its deadly wounds if you do so within 48 hours of its injury instead of within 24 hours.</p>
<blockquote>
<p><strong>Sources</strong> <Link to="/source/healers_handbook">Healer's Handbook</Link></p>
</blockquote>
</>};
const _hermean_paragon = {title: "Hermean Paragon", topLink: ["Regional Traits","main/traits_regional"], jsx: <><h2 id="trait-hermean_paragon-hermean-paragon">Hermean Paragon</h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> The Steaming Sea</p>
<p>You are a product of Hermea's breeding programs - either your parents were chosen to be citizens, or you were, but later failed to live up to the island's high standards. Whatever the case, you are quicker than normal members of your race, and gain a +2 trait bonus on Initiative checks.</p>
<blockquote>
<p><strong>Sources</strong> <Link to="/source/inner_sea_primer">Inner Sea Primer</Link></p>
</blockquote>
</>};
const _highlander = {title: "Highlander", topLink: ["Regional Traits","main/traits_regional"], jsx: <><h2 id="trait-highlander-highlander">Highlander</h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> hills or mountains</p>
<p>You were born and raised in rugged badlands or hills, and you've become something of an expert at evading the predators, monsters, and worse that haunt the highlands. You gain a +1 trait bonus on Stealth checks, and Stealth is always a class skill for you. This trait bonus increases to +2 in hilly or rocky areas.</p>
<blockquote>
<p><strong>Sources</strong> <Link to="/source/ultimate_campaign">Ultimate Campaign</Link>, <Link to="/source/advanced_players_guide">Advanced Player's Guide</Link></p>
</blockquote>
</>};
const _holy_tattoo = {title: "Holy Tattoo", topLink: ["Regional Traits","main/traits_regional"], jsx: <><h2 id="trait-holy_tattoo-holy-tattoo">Holy Tattoo</h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> Varisia</p>
<p>When you had your deity's holy symbol tattooed on your body by a Sczarni tattooist years ago, you never imagined it would save your life. Your holy symbol tattoo functions in all ways as a holy symbol. When you use your holy symbol tattoo to keep a vampire at bay, the DC for the vampire to overcome its revulsion is 28 (rather than the normal 25).</p>
<blockquote>
<p><strong>Sources</strong> <Link to="/source/undead_slayers_handbook">Undead Slayer's Handbook</Link></p>
</blockquote>
</>};
const _home_port = {title: "Home Port", topLink: ["Regional Traits","main/traits_regional"], jsx: <><h2 id="trait-home_port-home-port">Home Port</h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> The Shackles</p>
<p>You have a fondness for a particular port, and the people who live and do business there return the sentiment. You gain a +2 trait bonus on Diplomacy checks to gather information in your chosen home port.</p>
<blockquote>
<p><strong>Sources</strong> <Link to="/source/pirates_of_the_inner_sea">Pirates of the Inner Sea</Link></p>
</blockquote>
</>};
const _honeyed_tongue = {title: "Honeyed Tongue", topLink: ["Regional Traits","main/traits_regional"], jsx: <><h2 id="trait-honeyed_tongue-honeyed-tongue">Honeyed Tongue</h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> Amanandar</p>
<p>Having matured in the melting pot of New Oppara, you know the customs of the Tian-Shus as well as those of the Taldans, and you utilize this knowledge to create peace between rival groups. You gain a +1 trait bonus on Diplomacy checks, and Diplomacy becomes a class skill for you.</p>
<blockquote>
<p><strong>Sources</strong> <Link to="/source/dragon_empires_primer">Dragon Empires Primer</Link></p>
</blockquote>
</>};
const _hongal_bloodrider = {title: "Hongal Bloodrider", topLink: ["Regional Traits","main/traits_regional"], jsx: <><h2 id="trait-hongal_bloodrider-hongal-bloodrider">Hongal Bloodrider</h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> Hongal</p>
<p>You belong to one of the nomadic groups of horseback riders that range throughout Hongal. You gain a +1 trait bonus on Handle Animal and Ride checks.</p>
<blockquote>
<p><strong>Sources</strong> <Link to="/source/dragon_empires_primer">Dragon Empires Primer</Link></p>
</blockquote>
</>};
const _huldras_luck = {title: "Huldra's Luck", topLink: ["Regional Traits","main/traits_regional"], jsx: <><h2 id="trait-huldras_luck-huldras-luck">Huldra's Luck</h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> Lands of the Linnorm Kings</p>
<p>At some point in your life, you were touched by a fey creature called a huldra and inherited a bit of its luck. Once per day, you may choose to gain a +1 luck bonus on a single saving throw, attack roll, or skill check.</p>
<blockquote>
<p><strong>Sources</strong> <Link to="/source/people_of_the_north">People of the North</Link></p>
</blockquote>
</>};
const _humble_beginnings = {title: "Humble Beginnings", topLink: ["Regional Traits","main/traits_regional"], jsx: <><h2 id="trait-humble_beginnings-humble-beginnings">Humble Beginnings</h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> Varisia</p>
<p>You didn't have any intention of becoming an adventurer, but a single, unexpected confrontation changed everything. Choose one of the following: boot, bucket, frying pan, mug, rolling pin, spade, or stool. You are treated as having the Catch Off-Guard feat when wielding the chosen item. (These items should all be considered improvised melee weapons that deal 1d4 points of bludgeoning damage.)</p>
<blockquote>
<p><strong>Sources</strong> <Link to="/source/varisia_birthplace_of_legends">Varisia, Birthplace of Legends</Link></p>
</blockquote>
</>};
const _hurricane_savvy = {title: "Hurricane Savvy", topLink: ["Regional Traits","main/traits_regional"], jsx: <><h2 id="trait-hurricane_savvy-hurricane-savvy">Hurricane Savvy</h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> The Shackles</p>
<p>You are used to sailing in the terrible winds that roll out from the Eye of Abendego, and can apply the skills you've learned to any storm. You treat wind effects as one wind force category less than they actually are, both for any personal checks you must make and for any you make to captain or steer a ship.</p>
<blockquote>
<p><strong>Sources</strong> <Link to="/source/pirates_of_the_inner_sea">Pirates of the Inner Sea</Link></p>
</blockquote>
</>};
const _hwan_artist = {title: "Hwan Artist", topLink: ["Regional Traits","main/traits_regional"], jsx: <><h2 id="trait-hwan_artist-hwan-artist">Hwan Artist</h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> Hwanggot</p>
<p>You grew up in Hwanggot, and your artistic talents were cherished and honed from an early age. You have been nurtured on the artistic spirit of Hwanggot. Choose one Perform skill. You gain a +1 trait bonus on checks with that skill, and it becomes a class skill for you.</p>
<blockquote>
<p><strong>Sources</strong> <Link to="/source/dragon_empires_primer">Dragon Empires Primer</Link></p>
</blockquote>
</>};
const _iadaran_illusionist = {title: "Iadaran Illusionist", topLink: ["Regional Traits","main/traits_regional"], jsx: <><h2 id="trait-iadaran_illusionist-iadaran-illusionist">Iadaran Illusionist</h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> Kyonin</p>
<p>You have lived in Iadara for so long that you are very familiar with illusions. You gain a +1 trait bonus on caster level checks with illusion spells and a +1 trait bonus on Will saves to disbelieve illusions.</p>
<blockquote>
<p><strong>Sources</strong> <Link to="/source/inner_sea_primer">Inner Sea Primer</Link>, <Link to="/source/elves_of_golarion">Elves of Golarion</Link></p>
</blockquote>
</>};
const _imperial_soldier = {title: "Imperial Soldier", topLink: ["Regional Traits","main/traits_regional"], jsx: <><h2 id="trait-imperial_soldier-imperial-soldier">Imperial Soldier</h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> Molthune</p>
<p>You've served in the Imperial Army of Molthune. Choose one of the following skills: Heal, Intimidate, or Ride. You gain a +1 trait bonus on that skill, and it is always a class skill for you.</p>
<blockquote>
<p><strong>Sources</strong> <Link to="/source/inner_sea_primer">Inner Sea Primer</Link></p>
</blockquote>
</>};
const _indentured_blacksmith = {title: "Indentured Blacksmith", topLink: ["Regional Traits","main/traits_regional"], jsx: <><h2 id="trait-indentured_blacksmith-indentured-blacksmith">Indentured Blacksmith</h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> Kaoling</p>
<p>As a former slave of the hobgoblins, you were forced to make many of the weapons and shields that your captors used in war. Choose either Craft (armor) or Craft (weapons). You gain a +1 trait bonus on the chosen skill, and it becomes a class skill for you.</p>
<blockquote>
<p><strong>Sources</strong> <Link to="/source/dragon_empires_primer">Dragon Empires Primer</Link></p>
</blockquote>
</>};
const _inspiring_speaker = {title: "Inspiring Speaker", topLink: ["Regional Traits","main/traits_regional"], jsx: <><h2 id="trait-inspiring_speaker-inspiring-speaker">Inspiring Speaker</h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> Galt</p>
<p>You have learned the arts of oratory, and know how to speak to crowds to rile them up or to calm them down. You gain a +1 trait bonus on Bluff and Diplomacy checks when addressing crowds of 10 people or more.</p>
<blockquote>
<p><strong>Sources</strong> <Link to="/source/inner_sea_primer">Inner Sea Primer</Link></p>
</blockquote>
</>};
const _instigator_of_rebellion = {title: "Instigator of Rebellion", topLink: ["Regional Traits","main/traits_regional"], jsx: <><h2 id="trait-instigator_of_rebellion-instigator-of-rebellion">Instigator of Rebellion</h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> Minkai</p>
<p>Your rage over the political repositioning within Minkai has led you to incite rage within your compatriots. You have become adept at organizing rallies in opposition to the government. You gain a +1 trait bonus on Diplomacy and Intimidate checks.</p>
<blockquote>
<p><strong>Sources</strong> <Link to="/source/dragon_empires_primer">Dragon Empires Primer</Link></p>
</blockquote>
</>};
const _intrepid_delver = {title: "Intrepid Delver", topLink: ["Regional Traits","main/traits_regional"], jsx: <><h2 id="trait-intrepid_delver-intrepid-delver">Intrepid Delver</h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> Jinin</p>
<p>One of the elder elves in Ayajinbo told you many stories of the Darklands beneath the city, and your nerves have hardened to horrors others can hardly fathom. You gain a +2 trait bonus on saving throws against fear effects.</p>
<blockquote>
<p><strong>Sources</strong> <Link to="/source/dragon_empires_primer">Dragon Empires Primer</Link></p>
</blockquote>
</>};
const _iobarian_survivor = {title: "Iobarian Survivor", topLink: ["Regional Traits","main/traits_regional"], jsx: <><h2 id="trait-iobarian_survivor-iobarian-survivor">Iobarian Survivor</h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> Iobaria</p>
<p>Whenever you are exposed to a disease while you are trying to treat an afflicted creature, you gain a +4 trait bonus on your Fortitude saving throw to resist contracting the disease yourself.</p>
<blockquote>
<p><strong>Sources</strong> <Link to="/source/healers_handbook">Healer's Handbook</Link></p>
</blockquote>
</>};
const _iron_lungs = {title: "Iron Lungs", topLink: ["Regional Traits","main/traits_regional"], jsx: <><h2 id="trait-iron_lungs-iron-lungs">Iron Lungs</h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> Darklands</p>
<p>Due to the constant intrusion of marsh gases seeping into the tunnels and chambers of your lair, you can <Link to="/misc/hold_your_breath">hold your breath</Link> for twice as long and gain a +2 trait bonus on saving throws against the effects of inhaled poisons.</p>
<blockquote>
<p><strong>Sources</strong> <Link to="/source/kobolds_of_golarion">Kobolds of Golarion</Link></p>
</blockquote>
</>};
const _iron_mind = {title: "Iron Mind", topLink: ["Regional Traits","main/traits_regional"], jsx: <><h2 id="trait-iron_mind-iron-mind">Iron Mind</h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> Cheliax</p>
<p>You gain a +2 trait bonus on saving throws against spells and effects that would reduce your Intelligence score or cause you to forget something.</p>
<blockquote>
<p><strong>Sources</strong> <Link to="/source/knights_of_the_inner_sea">Knights of the Inner Sea</Link></p>
</blockquote>
</>};
const _isger_fixer = {title: "Isger Fixer", topLink: ["Regional Traits","main/traits_regional"], jsx: <><h2 id="trait-isger_fixer-isger-fixer">Isger Fixer</h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> Isger<br/><strong>Requirements:</strong> Halfling</p>
<p>Everyone in Isger knows how to make do with substandard equipment, and you can improvise tools and materials in order to keep a damaged object working for just a little bit longer. Once per day, you can tinker with a broken object to allow anyone who uses it to ignore the penalties for its broken condition for 24 hours (this does not affect the object's hit points). At the end of this time, it regains the broken condition (but you can use this trait on it over and over again).</p>
<blockquote>
<p><strong>Sources</strong> <Link to="/source/halflings_of_golarion">Halflings of Golarion</Link></p>
</blockquote>
</>};
const _isgeri_orphan = {title: "Isgeri Orphan", topLink: ["Regional Traits","main/traits_regional"], jsx: <><h2 id="trait-isgeri_orphan-isgeri-orphan">Isgeri Orphan</h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> Isger</p>
<p>You grew up in one of the many Asmodean orphanages that dot the Isgeri countryside. Whether or not you took to their teachings, your strict indoctrination at the hands of the "devil nuns" has toughened your body to punishment. You gain a +1 trait bonus on Fortitude saves.</p>
<blockquote>
<p><strong>Sources</strong> <Link to="/source/inner_sea_primer">Inner Sea Primer</Link></p>
</blockquote>
</>};
const _issian_noble = {title: "Issian Noble", topLink: ["Regional Traits","main/traits_regional"], jsx: <><h2 id="trait-issian_noble-issian-noble">Issian Noble</h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> Brevoy</p>
<p>You are a scion of one of the warring noble houses of Brevoy, and are well versed in maneuvering though the cutthroat world of Brevic politics. You gain a +1 trait bonus on Knowledge (nobility) and Sense Motive checks.</p>
<blockquote>
<p><strong>Sources</strong> <Link to="/source/inner_sea_primer">Inner Sea Primer</Link></p>
</blockquote>
</>};
const _jadwiga_medicine = {title: "Jadwiga Medicine", topLink: ["Regional Traits","main/traits_regional"], jsx: <><h2 id="trait-jadwiga_medicine-jadwiga-medicine">Jadwiga Medicine</h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> Irrisen</p>
<p>Once per day as an immediate action when you cast a spell of the healing subschool or a hex that produces the effect of such a spell, you can attempt an Intimidate check to demoralize your target or anyone who can see you within 30 feet. You gain a +2 trait bonus on this check.</p>
<blockquote>
<p><strong>Sources</strong> <Link to="/source/healers_handbook">Healer's Handbook</Link></p>
</blockquote>
</>};
const _jungle_diplomat = {title: "Jungle Diplomat", topLink: ["Regional Traits","main/traits_regional"], jsx: <><h2 id="trait-jungle_diplomat-jungle-diplomat">Jungle Diplomat</h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> Valashmai Jungle</p>
<p>You know the ways and mores of the tribes of the Valashmai Jungle, and how to handle delicate communications with different groups of people. You gain a +1 trait bonus on Diplomacy and Sense Motive checks.</p>
<blockquote>
<p><strong>Sources</strong> <Link to="/source/dragon_empires_primer">Dragon Empires Primer</Link></p>
</blockquote>
</>};
const _jungle_guide = {title: "Jungle Guide", topLink: ["Regional Traits","main/traits_regional"], jsx: <><h2 id="trait-jungle_guide-jungle-guide">Jungle Guide</h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> Sargava</p>
<p>You've made your living outfitting and guiding expeditions deep into the Mwangi interior in search of ancient ruins and lost cities. You gain a +1 trait bonus on Handle Animal checks, and a +1 trait bonus on Survival checks in jungle terrain. One of these skills is a class skill for you.</p>
<blockquote>
<p><strong>Sources</strong> <Link to="/source/inner_sea_primer">Inner Sea Primer</Link></p>
</blockquote>
</>};
const _jungle_native = {title: "Jungle Native", topLink: ["Regional Traits","main/traits_regional"], jsx: <><h2 id="trait-jungle_native-jungle-native">Jungle Native</h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> Mwangi Expanse<br/><strong>Requirements:</strong> Grippli</p>
<p>Your people have called the jungles home for generations, and they are extremely proficient in moving about in that terrain. You gain a +1 trait bonus on saving throws against diseases and poisons, a +1 trait bonus on initiative checks attempted in jungle terrain, and Survival is a class skill for you.</p>
<blockquote>
<p><strong>Sources</strong> <Link to="/source/blood_of_the_beast">Blood of the Beast</Link></p>
</blockquote>
</>};
const _jungle_resilience = {title: "Jungle Resilience", topLink: ["Regional Traits","main/traits_regional"], jsx: <><h2 id="trait-jungle_resilience-jungle-resilience">Jungle Resilience</h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> Nagajor</p>
<p>Having grown up in Nagajor, you are used to the myriad poisons of its people, and have developed a strong immune system. You gain a +2 trait bonus on Fortitude saves against poison effects.</p>
<blockquote>
<p><strong>Sources</strong> <Link to="/source/dragon_empires_primer">Dragon Empires Primer</Link></p>
</blockquote>
</>};
const _jungle_walker = {title: "Jungle Walker", topLink: ["Regional Traits","main/traits_regional"], jsx: <><h2 id="trait-jungle_walker-jungle-walker">Jungle Walker</h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> Mwangi Expanse</p>
<p>You have learned how to navigate the darkest jungles of the Mwangi Expanse, and how to avoid the most dangerous hazards of the land. You gain a +2 trait bonus on Survival checks in jungle terrain.</p>
<blockquote>
<p><strong>Sources</strong> <Link to="/source/inner_sea_primer">Inner Sea Primer</Link></p>
</blockquote>
</>};
const _justiciar = {title: "Justiciar", topLink: ["Regional Traits","main/traits_regional"], jsx: <><h2 id="trait-justiciar-justiciar">Justiciar</h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> Rahadoum</p>
<p>You are experienced in interpreting and applying legal doctrine, notably the Laws of Man, independent of any divine mandates. You gain a +1 trait bonus on Diplomacy and Knowledge (local) checks to settle disputes or arbitrate laws. Once per day if you succeed at an Intimidate check to demoralize a foe who has repudiated or ignored a pronounced judgment you've made, you may choose to cause the creature to be sickened instead of shaken. The duration of the effect remains the same.</p>
<blockquote>
<p><strong>Sources</strong> <Link to="/source/champions_of_balance">Champions of Balance</Link></p>
</blockquote>
</>};
const _kami_talker = {title: "Kami Talker", topLink: ["Regional Traits","main/traits_regional"], jsx: <><h2 id="trait-kami_talker-kami-talker">Kami Talker</h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> Forest of Spirits</p>
<p>You have traversed the Forest of Spirits numerous times, and have learned how best to communicate with its otherworldly inhabitants. You gain a +2 trait bonus on Diplomacy and Intimidate checks made against outsiders that have the native subtype.</p>
<blockquote>
<p><strong>Sources</strong> <Link to="/source/dragon_empires_primer">Dragon Empires Primer</Link></p>
</blockquote>
</>};
const _keeper_of_the_veil = {title: "Keeper of the Veil", topLink: ["Regional Traits","main/traits_regional"], jsx: <><h2 id="trait-keeper_of_the_veil-keeper-of-the-veil">Keeper of the Veil</h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> Qadira</p>
<p>Even when not cloaked in magic, your training has taught you how to conceal your true nature. You gain a +1 competence bonus on Bluff and Disguise checks, and one of these skills (your choice) is always a class skill for you.</p>
<blockquote>
<p><strong>Sources</strong> <Link to="/source/qadira_gateway_to_the_east">Qadira, Gateway to the East</Link></p>
</blockquote>
</>};
const _keleshite_trader = {title: "Keleshite Trader", topLink: ["Regional Traits","main/traits_regional"], jsx: <><h2 id="trait-keleshite_trader-keleshite-trader">Keleshite Trader</h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> Kelesh or Qadira</p>
<p>Your cosmopolitan upbringing has given you familiarity with many cultures. You gain two bonus languages and a +2 trait bonus on Knowledge (local) checks.</p>
<blockquote>
<p><strong>Sources</strong> <Link to="/source/qadira_jewel_of_the_east">Qadira, Jewel of the East</Link></p>
</blockquote>
</>};
const _kobolds_neighbor = {title: "Kobold's Neighbor", topLink: ["Regional Traits","main/traits_regional"], jsx: <><h2 id="trait-kobolds_neighbor-kobolds-neighbor">Kobold's Neighbor</h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> Andoran</p>
<p>You grew up in wilderness where kobolds make their homes. You learned early on how to find traps before they find you, how to disable them, and when you should just walk away. You gain a +2 trait bonus to Perception checks to discover traps and a +1 trait bonus to Disable Device checks.</p>
<blockquote>
<p><strong>Sources</strong> <Link to="/source/andoran_spirit_of_liberty">Andoran, Spirit of Liberty</Link></p>
</blockquote>
</>};
const _kwanlai_believer = {title: "Kwanlai Believer", topLink: ["Regional Traits","main/traits_regional"], jsx: <><h2 id="trait-kwanlai_believer-kwanlai-believer">Kwanlai Believer</h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> Kwanlai</p>
<p>You were raised in Kwanlai in one of the devout tengu churches, and your dedication to your cause makes your divine abilities particularly potent. You gain a +2 trait bonus on <Link to="/rule/concentration">concentration</Link> checks made while casting divine spells.</p>
<blockquote>
<p><strong>Sources</strong> <Link to="/source/dragon_empires_primer">Dragon Empires Primer</Link></p>
</blockquote>
</>};
const _kyonin_gatekeeper = {title: "Kyonin Gatekeeper", topLink: ["Regional Traits","main/traits_regional"], jsx: <><h2 id="trait-kyonin_gatekeeper-kyonin-gatekeeper">Kyonin Gatekeeper</h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> Kyonin<br/><strong>Requirements:</strong> Elf</p>
<p>You helped maintain the elf gates and are familiar with the operation of teleportation magic. You gain a +1 trait bonus on Spellcraft checks to identify teleportation magic and a +1 trait bonus to caster level checks when casting teleportation spells. You know the proper commands to operate a particular elf gate (most likely an often-used elf gate, but at the GM's discretion it may be a less popular or out-of-the-way elf gate).</p>
<blockquote>
<p><strong>Sources</strong> <Link to="/source/elves_of_golarion">Elves of Golarion</Link></p>
</blockquote>
</>};
const _lair_snake = {title: "Lair Snake", topLink: ["Regional Traits","main/traits_regional"], jsx: <><h2 id="trait-lair_snake-lair-snake">Lair Snake</h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> dragon's lair</p>
<p>You spent your formative years bowing and scraping in the presence of a dragon, witnessing the glory of the vast hoard... and squirreling away a few bits of coin for yourself. You gain a +1 trait bonus on Appraise checks, and your starting wealth increases by 200 gp.</p>
<blockquote>
<p><strong>Sources</strong> <Link to="/source/kobolds_of_golarion">Kobolds of Golarion</Link></p>
</blockquote>
</>};
const _lamasaran_performer = {title: "Lamasaran Performer", topLink: ["Regional Traits","main/traits_regional"], jsx: <><h2 id="trait-lamasaran_performer-lamasaran-performer">Lamasaran Performer</h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> Thuvia</p>
<p>You are one of the famed performers of Lamasara, and your skill is known throughout Thuvia. Once per day when you start a bardic performance, you can increase the DC of the saving throw to resist your performance's effects by 1. This effect lasts until you switch performances or end your performance.</p>
<blockquote>
<p><strong>Sources</strong> <Link to="/source/people_of_the_sands">People of the Sands</Link></p>
</blockquote>
</>};
const _lastwall_cavalry_rider = {title: "Lastwall Cavalry Rider", topLink: ["Regional Traits","main/traits_regional"], jsx: <><h2 id="trait-lastwall_cavalry_rider-lastwall-cavalry-rider">Lastwall Cavalry Rider</h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> Lastwall</p>
<p>From the moment you were old enough to walk, you learned how to ride the mighty warhorses of Lastwall. You gain a +1 trait bonus on Ride checks, and Ride is always a class skill for you.</p>
<blockquote>
<p><strong>Sources</strong> <Link to="/source/inner_sea_primer">Inner Sea Primer</Link></p>
</blockquote>
</>};
const _left_behind = {title: "Left Behind", topLink: ["Regional Traits","main/traits_regional"], jsx: <><h2 id="trait-left_behind-left-behind">Left Behind</h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> Mwangi Expanse or Varisia<br/><strong>Requirements:</strong> Elf</p>
<p>Having been born to those who chose to remain on Golarion during the Age of Darkness in the Mwangi Expanse, you understand the people of this world better than most elves. You gain a +1 trait bonus on Diplomacy checks when interacting with Forlorn elves and non-elf races.</p>
<blockquote>
<p><strong>Sources</strong> <Link to="/source/elves_of_golarion">Elves of Golarion</Link></p>
</blockquote>
</>};
const _legalistic_liberation = {title: "Legalistic Liberation", topLink: ["Regional Traits","main/traits_regional"], jsx: <><h2 id="trait-legalistic_liberation-legalistic-liberation">Legalistic Liberation</h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> Molthune or Osirion<br/><strong>Requirements:</strong> Halfling</p>
<p>You followed - or some might say exploited - the rules and earned your freedom by finding the loopholes within your homeland's labyrinthine codes regulating slavery and indentured servitude. You gain a +1 bonus on all Knowledge checks to find a legitimate way to avoid, negate, or escape an existing obligation.</p>
<blockquote>
<p><strong>Sources</strong> <Link to="/source/halflings_of_golarion">Halflings of Golarion</Link></p>
</blockquote>
</>};
const _lepidstadt_scar = {title: "Lepidstadt Scar", topLink: ["Regional Traits","main/traits_regional"], jsx: <><h2 id="trait-lepidstadt_scar-lepidstadt-scar">Lepidstadt Scar</h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> Ustalav</p>
<p>You engaged in nonlethal duels at Fifthstones Hill so often that you gained a visible (though minor) scar on your face. Because of this experience, you're unflinching in the heat of combat, calmly analyzing how to lessen the impact of a foe's best attacks. You gain a +1 dodge bonus to AC against attack rolls made to confirm a critical threat against you.</p>
<blockquote>
<p><strong>Sources</strong> <Link to="/source/advanced_class_origins">Advanced Class Origins</Link></p>
</blockquote>
</>};
const _lichblood = {title: "Lichblood", topLink: ["Regional Traits","main/traits_regional"], jsx: <><h2 id="trait-lichblood-lichblood">Lichblood</h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> Belkzen<br/><strong>Requirements:</strong> Orc, undead bloodrager bloodline</p>
<p>You are among the fabled lichblood orcs, and so you command respect among the orcs of Belkzen. You gain a +2 trait bonus on Diplomacy and Intimidate checks made against orcs of Belkzen. You must have the undead bloodrager bloodline to select this trait.</p>
<blockquote>
<p><strong>Sources</strong> <Link to="/source/advanced_class_origins">Advanced Class Origins</Link></p>
</blockquote>
</>};
const _linebreaker = {title: "Linebreaker", topLink: ["Regional Traits","main/traits_regional"], jsx: <><h2 id="trait-linebreaker-linebreaker">Linebreaker</h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> Belkzen</p>
<p>Growing up along the border between Belkzen and Lastwall has taught you how to storm enemy battle lines and quickly overwhelm them. When charging, add 10 feet to your base speed.</p>
<blockquote>
<p><strong>Sources</strong> <Link to="/source/inner_sea_primer">Inner Sea Primer</Link>, <Link to="/source/orcs_of_golarion">Orcs of Golarion</Link></p>
</blockquote>
</>};
const _lingshens_finest = {title: "Lingshen's Finest", topLink: ["Regional Traits","main/traits_regional"], jsx: <><h2 id="trait-lingshens_finest-lingshens-finest">Lingshen's Finest</h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> Lingshen</p>
<p>You are an elite soldier in one of Lingshen's numerous armies, and your discipline has made you a truly deadly foe. You gain a +1 trait bonus on all rolls to confirm critical hits.</p>
<blockquote>
<p><strong>Sources</strong> <Link to="/source/dragon_empires_primer">Dragon Empires Primer</Link></p>
</blockquote>
</>};
const _lions_audacity = {title: "Lion's Audacity", topLink: ["Regional Traits","main/traits_regional"], jsx: <><h2 id="trait-lions_audacity-lions-audacity">Lion's Audacity</h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> Taldor</p>
<p>You attack life with the ferocity of a charging lion and inspire others with your audacious deeds. Once per day when you make a charge attack, you can inspire allies within 30 feet. They gain an additional +2 trait bonus on attack and damage rolls when they make a charge attack before the beginning of your next turn.</p>
<blockquote>
<p><strong>Sources</strong> <Link to="/source/advanced_class_origins">Advanced Class Origins</Link></p>
</blockquote>
</>};
const _liquid_healing = {title: "Liquid Healing", topLink: ["Regional Traits","main/traits_regional"], jsx: <><h2 id="trait-liquid_healing-liquid-healing">Liquid Healing</h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> Rahadoum</p>
<p>Growing up in Rahadoum, you did not have access to clerics and other divine magic for healing, so you relied heavily on potions to cure your wounds. As a result, potions heal you more effectively. Whenever you consume a potion that heals any number of hit points, you heal 2 additional hit points.</p>
<blockquote>
<p><strong>Sources</strong> <Link to="/source/potions_and_poisons">Potions and Poisons</Link></p>
</blockquote>
</>};
const _local_know_it_all = {title: "Local Know-It-All", topLink: ["Regional Traits","main/traits_regional"], jsx: <><h2 id="trait-local_know_it_all-local-know-it-all">Local Know-It-All</h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> Varisia</p>
<p>Choose a community that you've lived in for at least 5 years. You gain a +2 trait bonus on Knowledge (local) checks related to that community.</p>
<blockquote>
<p><strong>Sources</strong> <Link to="/source/varisia_birthplace_of_legends">Varisia, Birthplace of Legends</Link></p>
</blockquote>
</>};
const _log_roller = {title: "Log Roller", topLink: ["Regional Traits","main/traits_regional"], jsx: <><h2 id="trait-log_roller-log-roller">Log Roller</h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> forest</p>
<p>The time you spent leaping between slippery logs as they whirled down the river to market taught you how to keep your footing. You gain a +1 trait bonus on Acrobatics checks and a +1 trait bonus to your CMB when attempting to resist trip attacks.</p>
<blockquote>
<p><strong>Sources</strong> <Link to="/source/ultimate_campaign">Ultimate Campaign</Link>, <Link to="/source/advanced_players_guide">Advanced Player's Guide</Link></p>
</blockquote>
</>};
const _lost_origins = {title: "Lost Origins", topLink: ["Regional Traits","main/traits_regional"], jsx: <><h2 id="trait-lost_origins-lost-origins">Lost Origins</h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> urban</p>
<p>You are disconnected from your heritage and do what you can to learn more about where your family is or where your people came from. Knowledge (local) is always a class skill for you, and you can always take 10 on Knowledge (local) checks, even when stress or distractions would normally prevent you from doing so.</p>
<blockquote>
<p><strong>Sources</strong> <Link to="/source/heroes_of_the_streets">Heroes of the Streets</Link></p>
</blockquote>
</>};
const _lost_role_model = {title: "Lost Role Model", topLink: ["Regional Traits","main/traits_regional"], jsx: <><h2 id="trait-lost_role_model-lost-role-model">Lost Role Model</h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> settlement near a famous dungeon</p>
<p>As a youth, you marveled at the crusaders, spelunkers, and lore seekers who came through your town on their way to the nearby dungeon, tomb, or ruins. One such intrepid role model in particular was of great import to you. On the last day you ever saw your hero, the adventurer gave you a unique dungeon guide worth no more than 750 gp and with an accuracy modifier of no greater than +2.</p>
<p><strong>Suggestion:</strong> With the help of your GM and using the <Link to="/main/equipment_misc">example dungeon guides</Link>, construct a unique dungeon guide tied to the dungeon near where you grew up.</p>
<blockquote>
<p><strong>Sources</strong> <Link to="/source/dungeoneers_handbook">Dungeoneer's Handbook</Link></p>
</blockquote>
</>};
const _mammoth_master = {title: "Mammoth Master", topLink: ["Regional Traits","main/traits_regional"], jsx: <><h2 id="trait-mammoth_master-mammoth-master">Mammoth Master</h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> Realm of the Mammoth Lords</p>
<p>You have experience trapping and training large creatures such as mammoths, mastodons, woolly rhinoceroses, and other megafauna. You gain a +4 trait bonus on Handle Animal checks related to these creatures.</p>
<blockquote>
<p><strong>Sources</strong> <Link to="/source/inner_sea_primer">Inner Sea Primer</Link>, <Link to="/source/orcs_of_golarion">Orcs of Golarion</Link></p>
</blockquote>
</>};
const _mana_wastes_medic = {title: "Mana Wastes Medic", topLink: ["Regional Traits","main/traits_regional"], jsx: <><h2 id="trait-mana_wastes_medic-mana-wastes-medic">Mana Wastes Medic</h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> Mana Wastes</p>
<p>After witnessing a terrible disaster result from an attempt at magical healing in the Mana Wastes, you are careful and methodical when crafting your own healing tinctures. The amount of hit points restored by your Heal checks to treat deadly wounds and your extracts of the healing subschool is increased by 1.</p>
<blockquote>
<p><strong>Sources</strong> <Link to="/source/healers_handbook">Healer's Handbook</Link></p>
</blockquote>
</>};
const _mana_wastes_survivalist = {title: "Mana Wastes Survivalist", topLink: ["Regional Traits","main/traits_regional"], jsx: <><h2 id="trait-mana_wastes_survivalist-mana-wastes-survivalist">Mana Wastes Survivalist</h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> Mana Wastes</p>
<p>You grew up in the blasted badlands of the Mana Wastes, or have spent a lot of time there, and the harsh land has toughened your body. You gain a +1 trait bonus on Fortitude saves.</p>
<blockquote>
<p><strong>Sources</strong> <Link to="/source/inner_sea_primer">Inner Sea Primer</Link></p>
</blockquote>
</>};
const _master_of_peaks = {title: "Master of Peaks", topLink: ["Regional Traits","main/traits_regional"], jsx: <><h2 id="trait-master_of_peaks-master-of-peaks">Master of Peaks</h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> Wall of Heaven</p>
<p>You have made it to the summits of a number of the Wall of Heaven's peaks, and your body is used to the effects of both extreme cold and high altitude. You gain a +2 trait bonus on Fortitude saving throws made against the effects of <Link to="/rule/cold_dangers">cold dangers</Link> and <Link to="/rule/altitude_sickness">altitude sickness</Link>.</p>
<blockquote>
<p><strong>Sources</strong> <Link to="/source/dragon_empires_primer">Dragon Empires Primer</Link></p>
</blockquote>
</>};
const _mechanical_expertise = {title: "Mechanical Expertise", topLink: ["Regional Traits","main/traits_regional"], jsx: <><h2 id="trait-mechanical_expertise-mechanical-expertise">Mechanical Expertise</h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> Alkenstar</p>
<p>Growing up bordering the Mana Wastes and living within the Grand Duchy of Alkenstar has made you familiar with tools and practical objects. You rely on mechanics to solve problems and are familiar with basic engineering concepts. Select one of the following skills: Craft (any), Disable Device, or Knowledge (engineering). You gain a +1 trait bonus on checks with that skill, and it is always a class skill for you.</p>
<blockquote>
<p><strong>Sources</strong> <Link to="/source/heroes_from_the_fringe">Heroes from the Fringe</Link></p>
</blockquote>
</>};
const _merabian_mentorship = {title: "Merabian Mentorship", topLink: ["Regional Traits","main/traits_regional"], jsx: <><h2 id="trait-merabian_mentorship-merabian-mentorship">Merabian Mentorship</h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> Thuvia<br/><strong>Requirements:</strong> Suli</p>
<p>You were apprenticed to a renowned alchemist of Merab, and she taught you how to recognize elemental reagents by taste. Upon imbibing a potion containing a spell on your formula list of a spell level you are capable of casting, you can attempt a Spellcraft check (DC 15 + extract level). On a success, you can immediately add the spell to your formula book.</p>
<blockquote>
<p><strong>Sources</strong> <Link to="/source/blood_of_the_elements">Blood of the Elements</Link></p>
</blockquote>
</>};
const _merchant_of_katheer = {title: "Merchant of Katheer", topLink: ["Regional Traits","main/traits_regional"], jsx: <><h2 id="trait-merchant_of_katheer-merchant-of-katheer">Merchant of Katheer</h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> Qadira</p>
<p>You grew up among the market stalls of the greatest trading post in all the world, and can almost smell the value of an item before you touch it. You gain a +1 trait bonus to Appraise checks, and Appraise is always a class skill for you.</p>
<blockquote>
<p><strong>Sources</strong> <Link to="/source/qadira_gateway_to_the_east">Qadira, Gateway to the East</Link></p>
</blockquote>
</>};
const _merchants_child = {title: "Merchant's Child", topLink: ["Regional Traits","main/traits_regional"], jsx: <><h2 id="trait-merchants_child-merchants-child">Merchant's Child</h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> Katapesh</p>
<p>One of your close relatives was a gifted merchant in the bustling bazaars of Katapesh, and taught you early in life how to see the innate value in any object. You gain a +1 trait bonus on Appraise checks, and Appraise is always a class skill for you.</p>
<blockquote>
<p><strong>Sources</strong> <Link to="/source/inner_sea_primer">Inner Sea Primer</Link>, <Link to="/source/legacy_of_fire_players_guide">Legacy of Fire Player's Guide</Link></p>
</blockquote>
</>};
const _militia = {title: "Militia", topLink: ["Regional Traits","main/traits_regional"], jsx: <><h2 id="trait-militia-militia">Militia</h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> Amanandar</p>
<p>As part of Amanandar's militia, you have trained extensively with groups. You gain a +1 trait bonus on attacks made while flanking an opponent.</p>
<blockquote>
<p><strong>Sources</strong> <Link to="/source/dragon_empires_primer">Dragon Empires Primer</Link></p>
</blockquote>
</>};
const _militia_veteran = {title: "Militia Veteran", topLink: ["Regional Traits","main/traits_regional"], jsx: <><h2 id="trait-militia_veteran-militia-veteran">Militia Veteran</h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> Taldor or any town or village</p>
<p>Your first job was serving in a civilian militia in your hometown. The skills you learned through daily drilling and protecting your fellow townsfolk gave you special insight into military life. Select one of the following skills: Profession (soldier), Ride, or Survival. You gain a +1 trait bonus on checks with that skill, and it is always a class skill for you.</p>
<blockquote>
<p><strong>Sources</strong> <Link to="/source/ultimate_campaign">Ultimate Campaign</Link>, <Link to="/source/advanced_players_guide">Advanced Player's Guide</Link>, <Link to="/source/taldor_echoes_of_glory">Taldor, Echoes of Glory</Link></p>
</blockquote>
</>};
const _minkai_advocate = {title: "Minkai Advocate", topLink: ["Regional Traits","main/traits_regional"], jsx: <><h2 id="trait-minkai_advocate-minkai-advocate">Minkai Advocate</h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> Minkai</p>
<p>You possess strong ties to Minkai, and spread flattering words regarding your empire. You gain a +1 trait bonus on Bluff checks, and Bluff becomes a class skill for you.</p>
<blockquote>
<p><strong>Sources</strong> <Link to="/source/dragon_empires_primer">Dragon Empires Primer</Link></p>
</blockquote>
</>};
const _mivoni_duelist = {title: "Mivoni Duelist", topLink: ["Regional Traits","main/traits_regional"], jsx: <><h2 id="trait-mivoni_duelist-mivoni-duelist">Mivoni Duelist</h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> Mivon</p>
<p>Your training in Aldori sword fighting included several bouts in the Sevier, which has taught you how to inflict further punishment in one-on-one fights. You gain a +1 trait bonus on damage rolls when you are the only one threatening your opponent.</p>
<blockquote>
<p><strong>Sources</strong> <Link to="/source/people_of_the_river">People of the River</Link></p>
</blockquote>
</>};
const _mizu_ki_hikari_rebel = {title: "Mizu Ki Hikari Rebel", topLink: ["Regional Traits","main/traits_regional"], jsx: <><h2 id="trait-mizu_ki_hikari_rebel-mizu-ki-hikari-rebel">Mizu Ki Hikari Rebel</h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> Chu Ye</p>
<p>You have trained in martial arts under the banner of Mizu Ki Hikari rebels. You gain a +1 trait bonus on damage rolls made with unarmed attacks.</p>
<blockquote>
<p><strong>Sources</strong> <Link to="/source/dragon_empires_primer">Dragon Empires Primer</Link></p>
</blockquote>
</>};
const _monkey_goblin = {title: "Monkey Goblin", topLink: ["Regional Traits","main/traits_regional"], jsx: <><h2 id="trait-monkey_goblin-monkey-goblin">Monkey Goblin</h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> Mediogalti<br/><strong>Requirements:</strong> Goblin</p>
<p>You are adept at arboreal activity, and are more at home in the branches of a tree than you are on the ground. You gain a +2 trait bonus on Acrobatics and Climb checks while climbing trees.</p>
<blockquote>
<p><strong>Sources</strong> <Link to="/source/goblins_of_golarion">Goblins of Golarion</Link></p>
</blockquote>
</>};
const _mordant_heritage = {title: "Mordant Heritage", topLink: ["Regional Traits","main/traits_regional"], jsx: <><h2 id="trait-mordant_heritage-mordant-heritage">Mordant Heritage</h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> The Steaming Sea</p>
<p>You have lived among the Mordant Spire elves and know their strange ways. You gain a +1 trait bonus on Swim checks and a +1 trait bonus on saving throws against enchantment effects.</p>
<blockquote>
<p><strong>Sources</strong> <Link to="/source/inner_sea_primer">Inner Sea Primer</Link>, <Link to="/source/elves_of_golarion">Elves of Golarion</Link></p>
</blockquote>
</>};
const _mountain_guide = {title: "Mountain Guide", topLink: ["Regional Traits","main/traits_regional"], jsx: <><h2 id="trait-mountain_guide-mountain-guide">Mountain Guide</h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> Five Kings Mountains</p>
<p>You are skilled at getting along in the mountains, enabling you to find hidden trails and secret entrances into the caverns beneath mountains. You gain a +1 trait bonus on Knowledge (geography) and Survival checks when in mountainous areas, and Knowledge (geography) is always a class skill for you.</p>
<blockquote>
<p><strong>Sources</strong> <Link to="/source/inner_sea_primer">Inner Sea Primer</Link></p>
</blockquote>
</>};
const _mutabi_qi_explorer = {title: "Mutabi-qi Explorer", topLink: ["Regional Traits","main/traits_regional"], jsx: <><h2 id="trait-mutabi_qi_explorer-mutabi-qi-explorer">Mutabi-qi Explorer</h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> Shanguang</p>
<p>You belong to one of the nomadic Mutabi-qi tribes that wander the wastes of Shaguang, and you are adept at navigating the seemingly endless desert wastes. You gain a +1 trait bonus on Knowledge (geography) checks and Survival checks made in the desert.</p>
<blockquote>
<p><strong>Sources</strong> <Link to="/source/dragon_empires_primer">Dragon Empires Primer</Link></p>
</blockquote>
</>};
const _mwangi_herbal_tradition = {title: "Mwangi Herbal Tradition", topLink: ["Regional Traits","main/traits_regional"], jsx: <><h2 id="trait-mwangi_herbal_tradition-mwangi-herbal-tradition">Mwangi Herbal Tradition</h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> Mwangi Expanse</p>
<p>You are trained in a Mwangi tradition of herbalism dating back to the Age of Darkness and therefore have great insight into how to use the natural ingredients at your disposal to nurse an ailing body. You gain a +4 trait bonus on Heal checks when providing long-term care, and Heal is a class skill for you.</p>
<blockquote>
<p><strong>Sources</strong> <Link to="/source/healers_handbook">Healer's Handbook</Link></p>
</blockquote>
</>};
const _mwangi_linguist = {title: "Mwangi Linguist", topLink: ["Regional Traits","main/traits_regional"], jsx: <><h2 id="trait-mwangi_linguist-mwangi-linguist">Mwangi Linguist</h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> Mwangi Expanse</p>
<p>The Mwangi Expanse is a land of dozens of languages, and you grew up speaking most of them. You gain Polyglot as a bonus language. In addition, you gain a +1 trait bonus on Linguistics checks when trying to communicate with someone who does not share a common language with you.</p>
<blockquote>
<p><strong>Sources</strong> <Link to="/source/heroes_from_the_fringe">Heroes from the Fringe</Link></p>
</blockquote>
</>};
const _naga_emissary = {title: "Naga Emissary", topLink: ["Regional Traits","main/traits_regional"], jsx: <><h2 id="trait-naga_emissary-naga-emissary">Naga Emissary</h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> Jalmeray<br/><strong>Requirements:</strong> Naga</p>
<p>You were groomed from childhood to act as an emissary to Nagajor's allies in Jalmeray, and you understand much about the Jalmeri people as a result. You gain a +1 trait bonus on Diplomacy checks, and Diplomacy is a class skill for you. In addition, you gain Vudrani as a bonus language.</p>
<blockquote>
<p><strong>Sources</strong> <Link to="/source/blood_of_the_beast">Blood of the Beast</Link></p>
</blockquote>
</>};
const _narrow_escape = {title: "Narrow Escape", topLink: ["Regional Traits","main/traits_regional"], jsx: <><h2 id="trait-narrow_escape-narrow-escape">Narrow Escape</h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> The Shackles</p>
<p>You were captured by kuru cannibals and nearly devoured in a sacrificial ritual. At the last second you wriggled free from your bonds and escaped into the jungle. Your narrow escape has left you with a paranoid fear of capture. You secretly conduct regular sessions in which you slip out of different types of knots. You gain a +1 trait bonus on Escape Artist checks, and Escape Artist becomes a class skill for you.</p>
<blockquote>
<p><strong>Sources</strong> <Link to="/source/pirates_of_the_inner_sea">Pirates of the Inner Sea</Link></p>
</blockquote>
</>};
const _narrows_survivor = {title: "Narrows Survivor", topLink: ["Regional Traits","main/traits_regional"], jsx: <><h2 id="trait-narrows_survivor-narrows-survivor">Narrows Survivor</h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> Taldor</p>
<p>You spent your childhood in the infamous Narrows district of Oppara. Years of living in violent squalor have sharpened your senses and given you an ardent distrust of humanity. You gain a +1 trait bonus to Initiative and Sense Motive checks. Sense Motive is always a class skill for you.</p>
<blockquote>
<p><strong>Sources</strong> <Link to="/source/taldor_echoes_of_glory">Taldor, Echoes of Glory</Link></p>
</blockquote>
</>};
const _naturalist = {title: "Naturalist", topLink: ["Regional Traits","main/traits_regional"], jsx: <><h2 id="trait-naturalist-naturalist">Naturalist</h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> Yamasa</p>
<p>Your ancestors taught you the importance of using what nature provides. You gain a +3 trait bonus on Survival checks when attempting to survive in the wilderness.</p>
<blockquote>
<p><strong>Sources</strong> <Link to="/source/blood_of_the_ancients">Blood of the Ancients pg. 11</Link></p>
</blockquote>
</>};
const _near_death_experience = {title: "Near-Death Experience", topLink: ["Regional Traits","main/traits_regional"], jsx: <><h2 id="trait-near_death_experience-near-death-experience">Near-Death Experience</h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> Belkzen</p>
<p>You had a close brush with death that you survived only thanks to one of the witch doctors of Belkzen, and your body has learned to cling to life in dire situations. You gain a +1 trait bonus on Constitution checks to stabilize, and you don't die until your hit points drop to a negative amount equal to 2 + your Constitution score.</p>
<blockquote>
<p><strong>Sources</strong> <Link to="/source/healers_handbook">Healer's Handbook</Link></p>
</blockquote>
</>};
const _necrotoxin_resistance = {title: "Necrotoxin Resistance", topLink: ["Regional Traits","main/traits_regional"], jsx: <><h2 id="trait-necrotoxin_resistance-necrotoxin-resistance">Necrotoxin Resistance</h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> Geb</p>
<p>As a resident of the undead lands of Geb, you know well that the walking dead often carry deadly poisons and diseases within them. You gain a +3 trait bonus on saving throws against disease and poison abilities and effects inflicted by creatures of the undead type (such as ghoul fever or a vargouille's poison).</p>
<blockquote>
<p><strong>Sources</strong> <Link to="/source/potions_and_poisons">Potions and Poisons</Link></p>
</blockquote>
</>};
const _nexian_corpse_hunter = {title: "Nexian Corpse Hunter", topLink: ["Regional Traits","main/traits_regional"], jsx: <><h2 id="trait-nexian_corpse_hunter-nexian-corpse-hunter">Nexian Corpse Hunter</h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> Nex</p>
<p>After years spent fighting the undead legions of Geb, you have developed a knack for killing undead creatures with magic. You gain a +1 bonus on damage rolls from your spells against undead.</p>
<blockquote>
<p><strong>Sources</strong> <Link to="/source/advanced_class_origins">Advanced Class Origins</Link></p>
</blockquote>
</>};
const _nidalese_shadowcaster = {title: "Nidalese Shadowcaster", topLink: ["Regional Traits","main/traits_regional"], jsx: <><h2 id="trait-nidalese_shadowcaster-nidalese-shadowcaster">Nidalese Shadowcaster</h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> Nidal</p>
<p>You have studied with the feared shadowcasters of Nidal. Choose one spell with the shadow descriptor - from this point on, whenever you cast this spell, its effect manifest at +1 caster level.</p>
<blockquote>
<p><strong>Sources</strong> <Link to="/source/inner_sea_primer">Inner Sea Primer</Link></p>
</blockquote>
</>};
const _nightstall_urchin = {title: "Nightstall Urchin", topLink: ["Regional Traits","main/traits_regional"], jsx: <><h2 id="trait-nightstall_urchin-nightstall-urchin">Nightstall Urchin</h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> Katapesh</p>
<p>You grew up an orphan on the streets of Katapesh, and spent many years of childhood in the Nightstalls, Katapesh's most infamous market. The strange and often horrific sights you saw there forced you to grow up fast-there's little that can shock or unsettle you. You gain a +2 trait bonus on saves against fear effects, and when you do make a successful save against a fear effect, the resulting rush of bravado grants you a +1 trait bonus on attack rolls and all skill checks for the next minute.</p>
<blockquote>
<p><strong>Sources</strong> <Link to="/source/legacy_of_fire_players_guide">Legacy of Fire Player's Guide</Link></p>
</blockquote>
</>};
const _nightstalls_escapee = {title: "Nightstalls Escapee", topLink: ["Regional Traits","main/traits_regional"], jsx: <><h2 id="trait-nightstalls_escapee-nightstalls-escapee">Nightstalls Escapee</h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> Katapesh<br/><strong>Requirements:</strong> Ifrit</p>
<p>The slavers of Katapesh were determined to sell you as living property, but you had other plans. You know not whether your slavers hunt you still, but you are careful about whom you trust and you always sleep with one eye open. You need to sleep only 4 hours to get <Link to="/rule/healing">a full night's rest</Link> (restoring 1 hit point per character level). You do not receive extra benefits for sleeping additional hours, and you must still rest for 24 hours to receive the benefits of complete bed rest.</p>
<blockquote>
<p><strong>Sources</strong> <Link to="/source/blood_of_the_elements">Blood of the Elements</Link></p>
</blockquote>
</>};
const _nirmathi_militia = {title: "Nirmathi Militia", topLink: ["Regional Traits","main/traits_regional"], jsx: <><h2 id="trait-nirmathi_militia-nirmathi-militia">Nirmathi Militia</h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> Nirmathas</p>
<p>You have served in one of the militia bands of Nirmathas, and have learned valuable skills. Select one of the following skills: Profession (soldier), Ride, or Survival. You gain a +1 trait bonus on that skill, and it is always a class skill for you.</p>
<blockquote>
<p><strong>Sources</strong> <Link to="/source/inner_sea_primer">Inner Sea Primer</Link></p>
</blockquote>
</>};
const _noble_in_exile = {title: "Noble-in-Exile", topLink: ["Regional Traits","main/traits_regional"], jsx: <><h2 id="trait-noble_in_exile-noble-in-exile">Noble-in-Exile</h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> Gralton</p>
<p>Though forced to live in the River Kingdoms, you never forget you're a Galtan noble. You gain a +1 trait bonus on Diplomacy checks while interacting with aristocrats and nobles, and a +1 trait bonus on Intimidate checks while interacting with commoners.</p>
<blockquote>
<p><strong>Sources</strong> <Link to="/source/people_of_the_river">People of the River</Link></p>
</blockquote>
</>};
const _numerologist = {title: "Numerologist", topLink: ["Regional Traits","main/traits_regional"], jsx: <><h2 id="trait-numerologist-numerologist">Numerologist</h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> Osirion</p>
<p>Having studied the sciences and other formal academics in your formative years, you swiftly became interested in the esoteric numerological practices of the ancient Osirian mathematicians, and know how to apply this science to dungeons. Once per day, you can attempt a Perception check while studying a trap (a standard action). The DC of this check is equal to the Disable Device DC of the trap - 5. If you succeed, you identify the DC necessary to disable the trap, as well as the DC of the Reflex save (if any) to avoid its effects.</p>
<blockquote>
<p><strong>Sources</strong> <Link to="/source/people_of_the_sands">People of the Sands</Link></p>
</blockquote>
</>};
const _oagan_diver = {title: "Oagan Diver", topLink: ["Regional Traits","main/traits_regional"], jsx: <><h2 id="trait-oagan_diver-oagan-diver">Oagan Diver</h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> The Sodden Lands</p>
<p>You know how to operate the diving bells of Oagon at the mouth of the Black Flow. You've dived the streets of sunken Lirgen yourself, and you know what to expect. You gain a +1 trait bonus on Swim checks, and Swim is always a class skill for you.</p>
<blockquote>
<p><strong>Sources</strong> <Link to="/source/inner_sea_primer">Inner Sea Primer</Link></p>
</blockquote>
</>};
const _obsequious_morsel = {title: "Obsequious Morsel", topLink: ["Regional Traits","main/traits_regional"], jsx: <><h2 id="trait-obsequious_morsel-obsequious-morsel">Obsequious Morsel</h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> Geb</p>
<p>Survival in Geb requires convincing your betters that you would be of more service to them if they let you live another day than if they turn you into an unliving thrall, and you have mastered the art of buying time against undead attacks. Once per day as a swift action, you can use <Link to="/spell/sanctuary">sanctuary</Link> as a spell-like ability (caster level = your highest caster level, or 1st if you have no caster level), with a DC equal to 10 + 1/2 your caster level (minimum 0) + your Charisma modifier. Only undead must save to attack you (other creature types are not affected). The effect ends as soon as you attack a creature, as normal.</p>
<blockquote>
<p><strong>Sources</strong> <Link to="/source/champions_of_corruption">Champions of Corruption</Link></p>
</blockquote>
</>};
const _observant_archer = {title: "Observant Archer", topLink: ["Regional Traits","main/traits_regional"], jsx: <><h2 id="trait-observant_archer-observant-archer">Observant Archer</h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> aquatic</p>
<p>Growing up in an aquatic environment, where three-dimensional movement and perception were necessary, has given you keen observational skills and the ability to notice and target unusual positions with ranged attacks. You gain a +1 trait bonus on ranged attack rolls when your target is at least 10 feet above or below you.</p>
<blockquote>
<p><strong>Sources</strong> <Link to="/source/heroes_from_the_fringe">Heroes from the Fringe</Link></p>
</blockquote>
</>};
const _oenopion_alchemist = {title: "Oenopion Alchemist", topLink: ["Regional Traits","main/traits_regional"], jsx: <><h2 id="trait-oenopion_alchemist-oenopion-alchemist">Oenopion Alchemist</h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> Nex</p>
<p>You studied with the alchemists of Oenopion, perfecting your craft in the homunculus factories, golemworks, and ooze colony. You gain a +1 trait bonus on Craft (alchemy) checks.</p>
<blockquote>
<p><strong>Sources</strong> <Link to="/source/inner_sea_primer">Inner Sea Primer</Link></p>
</blockquote>
</>};
const _offspring_of_the_ascension = {title: "Offspring of the Ascension", topLink: ["Regional Traits","main/traits_regional"], jsx: <><h2 id="trait-offspring_of_the_ascension-offspring-of-the-ascension">Offspring of the Ascension</h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> Osirion</p>
<p>You are descended from one of Ancient Osirion's pharaohs, and a sliver of her otherworldly power has been passed onto you. You gain a +1 trait bonus on Will saves against fear effects. Any time you become confused, reduce the duration of the effect by a number of rounds equal to your Wisdom modifier (to a minimum of 1 round of confusion).</p>
<blockquote>
<p><strong>Sources</strong> <Link to="/source/people_of_the_stars">People of the Stars</Link></p>
</blockquote>
</>};
const _open_minded_explorer = {title: "Open-Minded Explorer", topLink: ["Regional Traits","main/traits_regional"], jsx: <><h2 id="trait-open_minded_explorer-open-minded-explorer">Open-Minded Explorer</h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> Averaka</p>
<p>You grew up constantly interacting with people who speak unfamiliar languages and have diverse customs; your manners may not be polished, but your acceptance of others is genuine. You gain a +1 trait bonus on Diplomacy checks. This bonus increases to +2 when you're speaking the racial or ethnic language of the target creature.</p>
<blockquote>
<p><strong>Sources</strong> <Link to="/source/bastards_of_golarion">Bastards of Golarion</Link></p>
</blockquote>
</>};
const _orc_impaler = {title: "Orc Impaler", topLink: ["Regional Traits","main/traits_regional"], jsx: <><h2 id="trait-orc_impaler-orc-impaler">Orc Impaler</h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> Lastwall<br/><strong>Requirements:</strong> Knight of Ozem</p>
<p>You gain a +2 trait bonus on rolls to confirm critical hits made as part of a charge. This bonus increases to +3 if the critical hit is made against a creature with the orc subtype.</p>
<blockquote>
<p><strong>Sources</strong> <Link to="/source/knights_of_the_inner_sea">Knights of the Inner Sea</Link></p>
</blockquote>
</>};
const _oregent_desperation = {title: "Oregent Desperation", topLink: ["Regional Traits","main/traits_regional"], jsx: <><h2 id="trait-oregent_desperation-oregent-desperation">Oregent Desperation</h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> Oregent</p>
<p>Your instinct to survive easily overpowers your intellect, and you consider this a more than fair trade. Once per day you can improve your condition from dying to disabled by taking 4 points of Intelligence damage.</p>
<blockquote>
<p><strong>Sources</strong> <Link to="/source/andoran_spirit_of_liberty">Andoran, Spirit of Liberty</Link></p>
</blockquote>
</>};
const _oregent_timing = {title: "Oregent Timing", topLink: ["Regional Traits","main/traits_regional"], jsx: <><h2 id="trait-oregent_timing-oregent-timing">Oregent Timing</h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> Oregent</p>
<p>After years of soul-numbing obedience to the schedules of others, you find synchronizing your actions with an ally second nature. Once per day when you take a readied action in combat, you gain a +3 trait bonus on the d20 roll for that action if it was triggered by an ally's action.</p>
<blockquote>
<p><strong>Sources</strong> <Link to="/source/andoran_spirit_of_liberty">Andoran, Spirit of Liberty</Link></p>
</blockquote>
</>};
const _oregent_vandal = {title: "Oregent Vandal", topLink: ["Regional Traits","main/traits_regional"], jsx: <><h2 id="trait-oregent_vandal-oregent-vandal">Oregent Vandal</h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> Oregent</p>
<p>You find it quite easy to apply your carefully honed instincts for building and repairing to destruction instead. You gain a +2 trait bonus on damage rolls made against targets with hardness. This bonus does not apply to attacks that ignore hardness.</p>
<blockquote>
<p><strong>Sources</strong> <Link to="/source/andoran_spirit_of_liberty">Andoran, Spirit of Liberty</Link></p>
</blockquote>
</>};
const _osirionologist = {title: "Osirionologist", topLink: ["Regional Traits","main/traits_regional"], jsx: <><h2 id="trait-osirionologist-osirionologist">Osirionologist</h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> Osirion</p>
<p>You have studied the history of ancient Osirion, and may have even ventured inside one of the great pyramids. You gain a +1 trait bonus on Knowledge (engineering) and Knowledge (history) checks, and one of them is always a class skill for you. In addition, you may choose Ancient Osiriani as one of your bonus languages.</p>
<blockquote>
<p><strong>Sources</strong> <Link to="/source/inner_sea_primer">Inner Sea Primer</Link></p>
</blockquote>
</>};
const _outsea_native = {title: "Outsea Native", topLink: ["Regional Traits","main/traits_regional"], jsx: <><h2 id="trait-outsea_native-outsea-native">Outsea Native</h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> River Kingdoms<br/><strong>Requirements:</strong> Undine</p>
<p>Raised amid or near the transitive aquatic kingdom known as Outsea, your predilection for watery environs has been strong since birth and you know the types of creatures who call the ocean home. You gain a +2 trait bonus on Knowledge checks to identify aquatic monsters. Anytime you are looking through water and would take a penalty on vision-based Perception checks due to murkiness or other natural circumstances, reduce the penalty by 2.</p>
<blockquote>
<p><strong>Sources</strong> <Link to="/source/blood_of_the_elements">Blood of the Elements</Link></p>
</blockquote>
</>};
const _palm_potion = {title: "Palm Potion", topLink: ["Regional Traits","main/traits_regional"], jsx: <><h2 id="trait-palm_potion-palm-potion">Palm Potion</h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> Razmiran</p>
<p>Priests of Razmiran often make subtle use of potions to hide the fact that they do not receive spells from their deity, and they have become quite adept at imbibing potions surreptitiously. You have mastered these techniques; whenever you consume a potion, you can attempt a Sleight of Hand check with a +2 trait bonus opposed by onlookers' Perception checks to hide the fact that you are drinking a potion (as if you were using Sleight of Hand to hide an object). The observer's success doesn't prevent you from drinking the potion, just from doing so unnoticed. This does not hide any visible effects that the potion might have on you, only the physical act of drinking the potion.</p>
<blockquote>
<p><strong>Sources</strong> <Link to="/source/potions_and_poisons">Potions and Poisons</Link></p>
</blockquote>
</>};
const _paraheen_weaponsmith = {title: "Paraheen Weaponsmith", topLink: ["Regional Traits","main/traits_regional"], jsx: <><h2 id="trait-paraheen_weaponsmith-paraheen-weaponsmith">Paraheen Weaponsmith</h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> Qadira</p>
<p>You are a descendant of a long line of skilled dwarven weapon makers or have apprenticed under such artisans. Either way, you learned their long-held secrets relating to the production of magical arms and armor. You treat your caster level as 1 higher for purposes of creating magical weapons, and gain a +1 trait bonus on Craft checks to create magical armor, shields, or weapons.</p>
<blockquote>
<p><strong>Sources</strong> <Link to="/source/qadira_jewel_of_the_east">Qadira, Jewel of the East</Link></p>
</blockquote>
</>};
const _passionate_believer = {title: "Passionate Believer", topLink: ["Regional Traits","main/traits_regional"], jsx: <><h2 id="trait-passionate_believer-passionate-believer">Passionate Believer</h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> Po Li</p>
<p>Your faith was stifled while you lived in the religiously oppressive slums of Changdo, and the persecutions against you only spurred your own beliefs and made your convictions stronger. You gain a +1 trait bonus on saving throws against divine spells.</p>
<blockquote>
<p><strong>Sources</strong> <Link to="/source/dragon_empires_primer">Dragon Empires Primer</Link></p>
</blockquote>
</>};
const _patrons_boon = {title: "Patron's Boon", topLink: ["Regional Traits","main/traits_regional"], jsx: <><h2 id="trait-patrons_boon-patrons-boon">Patron's Boon</h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> Rahadoum</p>
<p>In your youth, a Rahadoumi witch granted you a boon promoting your continued health and long life. The DCs of any Heal checks to stop bleed damage you are suffering are reduced by 4.</p>
<blockquote>
<p><strong>Sources</strong> <Link to="/source/healers_handbook">Healer's Handbook</Link></p>
</blockquote>
</>};
const _pearl_diver_xidao = {title: "Pearl Diver (Xidao)", topLink: ["Regional Traits","main/traits_regional"], jsx: <><h2 id="trait-pearl_diver_xidao-pearl-diver-xidao">Pearl Diver (Xidao)</h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> Xidao</p>
<p>You were a pearl harvester for a nation bordering Xidao, and you know just what clues to look for when searching for a worthwhile haul in the briny shallows. You gain a +1 trait bonus on Appraise and Swim checks.</p>
<blockquote>
<p><strong>Sources</strong> <Link to="/source/dragon_empires_primer">Dragon Empires Primer</Link></p>
</blockquote>
</>};
const _perseverance = {title: "Perseverance", topLink: ["Regional Traits","main/traits_regional"], jsx: <><h2 id="trait-perseverance-perseverance">Perseverance</h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> Five Kings Mountains</p>
<p>Your time in the Five Kings Mountains has taught you that any obstacle can be endured and overcome. When you have more than one Will saving throw to overcome an effect (such as from greater command or hold person, or by using the good fortune ability of the Luck domain), you receive a +3 trait bonus on the extra Will saves against that effect.</p>
<blockquote>
<p><strong>Sources</strong> <Link to="/source/inner_sea_primer">Inner Sea Primer</Link>, <Link to="/source/dwarves_of_golarion">Dwarves of Golarion</Link></p>
</blockquote>
</>};
const _pesh_addict = {title: "Pesh Addict", topLink: ["Regional Traits","main/traits_regional"], jsx: <><h2 id="trait-pesh_addict-pesh-addict">Pesh Addict</h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> Katapesh</p>
<p>You spent several years addicted to pesh, a habit that you may or may not have kicked. You start with only half of the normal starting cash, but your knowledge of the pesh lifestyle grants you a +1 trait bonus on Bluff, Knowledge (local), and Sense Motive checks. One of these skills (your choice) is always a class skill for you.</p>
<blockquote>
<p><strong>Sources</strong> <Link to="/source/inner_sea_primer">Inner Sea Primer</Link>, <Link to="/source/legacy_of_fire_players_guide">Legacy of Fire Player's Guide</Link></p>
</blockquote>
</>};
const _pesh_dealer = {title: "Pesh Dealer", topLink: ["Regional Traits","main/traits_regional"], jsx: <><h2 id="trait-pesh_dealer-pesh-dealer">Pesh Dealer</h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> Katapesh</p>
<p>You worked for a pesh dealer, either by selling the drug on the street or helping to organize shipments to other regions, which involved a certain amount of smuggling. You gain a +1 trait bonus on Sleight of Hand checks, and Sleight of Hand is always a class skill for you.</p>
<blockquote>
<p><strong>Sources</strong> <Link to="/source/legacy_of_fire_players_guide">Legacy of Fire Player's Guide</Link></p>
</blockquote>
</>};
const _pirate_duelist = {title: "Pirate Duelist", topLink: ["Regional Traits","main/traits_regional"], jsx: <><h2 id="trait-pirate_duelist-pirate-duelist">Pirate Duelist</h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> Mediogalti</p>
<p>You've rubbed elbows with pirates of all stripes in Ilizmagorti's taverns and convinced a few to show off their swordfighting skills. You gain a +1 trait bonus on attacks of opportunity made with daggers, short swords, cutlasses, rapiers, scimitars, or hook hands.</p>
<blockquote>
<p><strong>Sources</strong> <Link to="/source/pirates_of_the_inner_sea">Pirates of the Inner Sea</Link></p>
</blockquote>
</>};
const _pitaxian_improvisation = {title: "Pitaxian Improvisation", topLink: ["Regional Traits","main/traits_regional"], jsx: <><h2 id="trait-pitaxian_improvisation-pitaxian-improvisation">Pitaxian Improvisation</h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> Pitax</p>
<p>Your quick hands can salvage even the most botched performance. Once per day after you attempt a Perform check and before the results of the roll are revealed by the GM, you can attempt a Bluff check and use the result of that check in place of your Perform check. You must use the result of that Bluff check, even if it is lower.</p>
<blockquote>
<p><strong>Sources</strong> <Link to="/source/people_of_the_river">People of the River</Link></p>
</blockquote>
</>};
const _plainsman = {title: "Plainsman", topLink: ["Regional Traits","main/traits_regional"], jsx: <><h2 id="trait-plainsman-plainsman">Plainsman</h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> M'neri Plains</p>
<p>You live and work on the M'neri Plains. You gain a +1 trait bonus on all Knowledge (geography) and Survival checks regarding the M'neri Plains.</p>
<blockquote>
<p><strong>Sources</strong> <Link to="/source/sargava_the_lost_colony">Sargava, the Lost Colony</Link></p>
</blockquote>
</>};
const _planar_negotiator_dhh = {title: "Planar Negotiator (DHH)", topLink: ["Regional Traits","main/traits_regional"], jsx: <><h2 id="trait-planar_negotiator_dhh-planar-negotiator-dhh">Planar Negotiator (DHH)</h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> The Abyss</p>
<p>You are used to dealing with outsiders that would fluster a less experienced negotiator. When dealing with an outsider within one step of your alignment, you gain a +1 trait bonus on Diplomacy and Sense Motive checks. Increase these bonuses to +2 if you and the outsider worship the same deity.</p>
<blockquote>
<p><strong>Sources</strong> <Link to="/source/demon_hunters_handbook">Demon Hunter's Handbook</Link></p>
</blockquote>
</>};
const _poison_connoisseur = {title: "Poison Connoisseur", topLink: ["Regional Traits","main/traits_regional"], jsx: <><h2 id="trait-poison_connoisseur-poison-connoisseur">Poison Connoisseur</h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> Taldor</p>
<p>When the ceaseless bickering and elaborate posturing of Taldan politics proves ineffective, it is not unheard of for the nobility of Taldor to turn to poison to solve their problems, and therefore many are taught to identify the telltale signs of commonly used toxins. You gain a +2 trait bonus on saving throws against ingested poisons. Additionally, you can cast <Link to="/spell/detect_poison">detect poison</Link> as a spell-like ability once per day, using your character level as your caster level.</p>
<blockquote>
<p><strong>Sources</strong> <Link to="/source/potions_and_poisons">Potions and Poisons</Link></p>
</blockquote>
</>};
const _poisoned_blade_resistance = {title: "Poisoned Blade Resistance", topLink: ["Regional Traits","main/traits_regional"], jsx: <><h2 id="trait-poisoned_blade_resistance-poisoned-blade-resistance">Poisoned Blade Resistance</h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> River Kingdoms</p>
<p>In the River Kingdoms' Daggermark, odds are good that any given blade is coated in some kind of poison, and people there are used to both poisoning and being poisoned. You gain a +2 trait bonus on Fortitude saving throws against injury poisons. Additionally, you are immune to one specific nonmagical injury poison. You must choose this poison when you choose this trait and cannot change it.</p>
<blockquote>
<p><strong>Sources</strong> <Link to="/source/potions_and_poisons">Potions and Poisons</Link></p>
</blockquote>
</>};
const _pomp_and_pageantry = {title: "Pomp and Pageantry", topLink: ["Regional Traits","main/traits_regional"], jsx: <><h2 id="trait-pomp_and_pageantry-pomp-and-pageantry">Pomp and Pageantry</h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> Taldor<br/><strong>Requirements:</strong> Halfling</p>
<p>Though others think you merely waste time, you know that those extra flourishes and ceremonial touches actually make your work just that much better. You gain a +1 trait bonus on Acrobatics, Diplomacy, Handle Animal, Intimidate, Perform, and Ride checks with class skills if you spend twice as long as it normally takes to make that check.</p>
<blockquote>
<p><strong>Sources</strong> <Link to="/source/halflings_of_golarion">Halflings of Golarion</Link></p>
</blockquote>
</>};
const _precocious_spellcaster = {title: "Precocious Spellcaster", topLink: ["Regional Traits","main/traits_regional"], jsx: <><h2 id="trait-precocious_spellcaster-precocious-spellcaster">Precocious Spellcaster</h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> Taldor</p>
<p>Before you even began your training as a spellcaster, you spent a great deal of time studying cantrips and simple spells on your own. Because of this, you developed some innate magical abilities without any outside guidance. Select one cantrip and one 1st-level spell; when you cast these spells, they function at one caster level higher than your actual caster level.</p>
<blockquote>
<p><strong>Sources</strong> <Link to="/source/taldor_echoes_of_glory">Taldor, Echoes of Glory</Link></p>
</blockquote>
</>};
const _prestigious_healer = {title: "Prestigious Healer", topLink: ["Regional Traits","main/traits_regional"], jsx: <><h2 id="trait-prestigious_healer-prestigious-healer">Prestigious Healer</h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> Cheliax</p>
<p>Once per day as an immediate action when you cast a spell of the healing subschool, you can attempt a Diplomacy check to improve the attitude of your target or anyone within 30 feet who can see you before the end of your next turn. You gain a +2 trait bonus on this check.</p>
<blockquote>
<p><strong>Sources</strong> <Link to="/source/healers_handbook">Healer's Handbook</Link></p>
</blockquote>
</>};
const _pretend_pirate = {title: "Pretend Pirate", topLink: ["Regional Traits","main/traits_regional"], jsx: <><h2 id="trait-pretend_pirate-pretend-pirate">Pretend Pirate</h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> Andoran</p>
<p>You enjoy luring slave ships to you. Sometimes you run a pirate flag to lull criminals into a false sense of security; other times you disguise yourself as a merchant ship. You gain a +2 bonus on Disguise checks made to disguise yourself as a pirate or merchant sailor. In addition, you can take 5 minutes to alter your ship's appearance to add +2 to the DC of any check made to identify your ship's allegiance or purpose.</p>
<blockquote>
<p><strong>Sources</strong> <Link to="/source/pirates_of_the_inner_sea">Pirates of the Inner Sea</Link></p>
</blockquote>
</>};
const _prismati_player = {title: "Prismati Player", topLink: ["Regional Traits","main/traits_regional"], jsx: <><h2 id="trait-prismati_player-prismati-player">Prismati Player</h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> Andoran</p>
<p>You've grown up playing the confusing game of prismati and throw stones with accuracy and ease. You gain a +1 trait bonus on attack rolls with fist-sized rocks or similarly shaped objects, and a +1 trait bonus on <Link to="/rule/concentration">concentration</Link> checks.</p>
<blockquote>
<p><strong>Sources</strong> <Link to="/source/andoran_spirit_of_liberty">Andoran, Spirit of Liberty</Link></p>
</blockquote>
</>};
const _privileged_slave = {title: "Privileged Slave", topLink: ["Regional Traits","main/traits_regional"], jsx: <><h2 id="trait-privileged_slave-privileged-slave">Privileged Slave</h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> Kaoling</p>
<p>You were enslaved by the hobgoblins of Kaoling, and obeyed your masters dutifully, turning your back on comrades in order to find favor with your slavers-all the while plotting your escape. You gain a +1 trait bonus on Bluff checks, and Bluff becomes a class skill for you.</p>
<blockquote>
<p><strong>Sources</strong> <Link to="/source/dragon_empires_primer">Dragon Empires Primer</Link></p>
</blockquote>
</>};
const _prophet_of_burrows = {title: "Prophet of Burrows", topLink: ["Regional Traits","main/traits_regional"], jsx: <><h2 id="trait-prophet_of_burrows-prophet-of-burrows">Prophet of Burrows</h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> Druma<br/><strong>Requirements:</strong> Ratfolk</p>
<p>While you might not be a practicing follower of the <Link to="/rule/prophecies_of_kalistrade">Prophecies of Kalistrade</Link>, you value human coin more than most ratfolk do and have taken the mercantile practices of the Prophecies to heart. Whenever you roll a skill check to earn money, increase the amount of money that you earn by 5%.</p>
<blockquote>
<p><strong>Sources</strong> <Link to="/source/blood_of_the_beast">Blood of the Beast</Link></p>
</blockquote>
</>};
const _purchased_loyalty = {title: "Purchased Loyalty", topLink: ["Regional Traits","main/traits_regional"], jsx: <><h2 id="trait-purchased_loyalty-purchased-loyalty">Purchased Loyalty</h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> Druma</p>
<p>As a member of Druma's Mercenary League, you are utterly loyal to the holder of your contract-at least until it expires. Once per day, when protecting someone who has bought your services, you may roll twice when making a Will save against charm effects and take the better result.</p>
<blockquote>
<p><strong>Sources</strong> <Link to="/source/inner_sea_primer">Inner Sea Primer</Link></p>
</blockquote>
</>};
const _pure_legion_recruit = {title: "Pure Legion Recruit", topLink: ["Regional Traits","main/traits_regional"], jsx: <><h2 id="trait-pure_legion_recruit-pure-legion-recruit">Pure Legion Recruit</h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> Rahadoum</p>
<p>You have spent time among the famed Pure Legion and understand some of their techniques for spotting signs of religion and the faithful. You gain a +2 trait bonus on Perception checks to see through disguises and mundane attempts to conceal religious iconography or dress. You also gain a +2 trait bonus on Sense Motive checks to see through lies about a target's religious beliefs and to understand secret messages relating to the gods.</p>
<blockquote>
<p><strong>Sources</strong> <Link to="/source/people_of_the_sands">People of the Sands</Link></p>
</blockquote>
</>};
const _quain_martial_artist = {title: "Quain Martial Artist", topLink: ["Regional Traits","main/traits_regional"], jsx: <><h2 id="trait-quain_martial_artist-quain-martial-artist">Quain Martial Artist</h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> Quain</p>
<p>Having grown up in Quain, you were taught under various schools of martial arts, and have used all you have learned to hone your fighting prowess. You gain a +1 trait bonus on damage rolls when using unarmed strikes.</p>
<blockquote>
<p><strong>Sources</strong> <Link to="/source/dragon_empires_primer">Dragon Empires Primer</Link></p>
</blockquote>
</>};
const _quantium_university_graduate = {title: "Quantium University Graduate", topLink: ["Regional Traits","main/traits_regional"], jsx: <><h2 id="trait-quantium_university_graduate-quantium-university-graduate">Quantium University Graduate</h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> Nex</p>
<p>You graduated from one of Quantium's justly famous arcane academies, and the rigorous program of study has honed your mind. You gain a +2 trait bonus on <Link to="/rule/concentration">concentration</Link> checks when casting arcane spells.</p>
<blockquote>
<p><strong>Sources</strong> <Link to="/source/inner_sea_primer">Inner Sea Primer</Link></p>
</blockquote>
</>};
const _rabble_rebel = {title: "Rabble Rebel", topLink: ["Regional Traits","main/traits_regional"], jsx: <><h2 id="trait-rabble_rebel-rabble-rebel">Rabble Rebel</h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> Galt<br/><strong>Requirements:</strong> Halfling</p>
<p>Your time spent amid angry mobs has taught you exactly how to use crowds of people to distract your opponents. If you have at least three allies threatening your opponent, you gain a +2 bonus on Bluff checks to feint him and a +2 bonus on Sleight of Hand checks against him.</p>
<blockquote>
<p><strong>Sources</strong> <Link to="/source/halflings_of_golarion">Halflings of Golarion</Link></p>
</blockquote>
</>};
const _rahadoumi_cultist = {title: "Rahadoumi Cultist", topLink: ["Regional Traits","main/traits_regional"], jsx: <><h2 id="trait-rahadoumi_cultist-rahadoumi-cultist">Rahadoumi Cultist</h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> Rahadoum</p>
<p>You're a secret member of a forbidden faith in Rahadoum. You have learned to hide your beliefs and how to identify others of your faith. You gain a +5 trait bonus on Bluff checks to receive secret messages, and a +5 trait bonus on Sense Motive checks to intercept secret messages from others of your faith.</p>
<blockquote>
<p><strong>Sources</strong> <Link to="/source/inner_sea_primer">Inner Sea Primer</Link></p>
</blockquote>
</>};
const _rahadoumi_disbeliever = {title: "Rahadoumi Disbeliever", topLink: ["Regional Traits","main/traits_regional"], jsx: <><h2 id="trait-rahadoumi_disbeliever-rahadoumi-disbeliever">Rahadoumi Disbeliever</h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> Rahadoum</p>
<p>As a Rahadoumi who rejects covenants with gods, your belief is strong enough to repel divine spells. You gain a +2 trait bonus on saving throws against divine spells, but you must make a saving throw even when that magic is beneficial to you.</p>
<blockquote>
<p><strong>Sources</strong> <Link to="/source/inner_sea_primer">Inner Sea Primer</Link></p>
</blockquote>
</>};
const _rebel_leader = {title: "Rebel Leader", topLink: ["Regional Traits","main/traits_regional"], jsx: <><h2 id="trait-rebel_leader-rebel-leader">Rebel Leader</h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> Shokuro</p>
<p>A close relative was an important player in the rebellions that led to the independence of Shokuro, and passed on her passion to you. If you take the <Link to="/feat/leadership">Leadership</Link> feat, you receive a +1 trait bonus to your Leadership score.</p>
<blockquote>
<p><strong>Sources</strong> <Link to="/source/dragon_empires_primer">Dragon Empires Primer</Link></p>
</blockquote>
</>};
const _regional_influence = {title: "Regional Influence", topLink: ["Regional Traits","main/traits_regional"], jsx: <><h2 id="trait-regional_influence-regional-influence">Regional Influence</h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> Varisia</p>
<p>Although you live some distance from the city-state your community owes fealty to, you've been influenced by its sophisticated urban ways. Determine the city-state of which your home is a holding. You gain a +1 trait bonus on checks with one Profession skill and one of the following benefits.</p>
<p><strong>Korvosa:</strong> Gain Infernal as a bonus language. If you already have this language, gain a +1 trait bonus on Diplomacy checks.<br/><strong>Magnimar:</strong> Gain one random <Link to="/eq-misc/varisian_idol">Varisian idol</Link>.<br/><strong>Riddleport:</strong> Gain a +1 trait bonus on Swim checks.</p>
<blockquote>
<p><strong>Sources</strong> <Link to="/source/varisia_birthplace_of_legends">Varisia, Birthplace of Legends</Link></p>
</blockquote>
</>};
const _regional_recluse = {title: "Regional Recluse", topLink: ["Regional Traits","main/traits_regional"], jsx: <><h2 id="trait-regional_recluse-regional-recluse">Regional Recluse</h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> Varisia</p>
<p>Your home community prides itself on remaining independent from Varisia's city-states. Choose one of Varisia's unaffiliated settlements from this list below. You gain a +1 trait bonus on Survival checks and one of the following benefits.</p>
<p><strong>Arsmeril or Crying Leaf:</strong> Gain a +1 trait bonus on Perception checks made at night.<br/><strong>Ilsurian:</strong> Gain proficiency with light shields.<br/><strong>Sanos Forest or Whistledown:</strong> Gain Gnome as a bonus language. If you already have this language, gain a +1 trait bonus on Stealth checks made in forested areas.<br/><strong>Turtleback Ferry:</strong> Gain a +1 bonus to damage on all attacks against creatures of the giant type.<br/><strong>Urglin:</strong> Gain Orc as a bonus language. If you already know this language, gain a +1 trait bonus on Intimidate checks.</p>
<blockquote>
<p><strong>Sources</strong> <Link to="/source/varisia_birthplace_of_legends">Varisia, Birthplace of Legends</Link></p>
</blockquote>
</>};
const _resourceful_alchemy = {title: "Resourceful Alchemy", topLink: ["Regional Traits","main/traits_regional"], jsx: <><h2 id="trait-resourceful_alchemy-resourceful-alchemy">Resourceful Alchemy</h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> Thuvia</p>
<p>Alchemy is a point of national pride in Thuvia, home of the famous <Link to="/magic-artifact/sun_orchid_elixir">sun orchid elixir</Link>. But resources are often hard to come by in the blasted desert landscape, so you have found creative ways to create many of the tools you need to survive. You gain a +2 trait bonus on Craft (alchemy) skill checks. This bonus increases to +3 when you are using Craft (alchemy) to craft an alchemical item.</p>
<blockquote>
<p><strong>Sources</strong> <Link to="/source/potions_and_poisons">Potions and Poisons</Link></p>
</blockquote>
</>};
const _resourceful_scavenger = {title: "Resourceful Scavenger", topLink: ["Regional Traits","main/traits_regional"], jsx: <><h2 id="trait-resourceful_scavenger-resourceful-scavenger">Resourceful Scavenger</h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> Numeria</p>
<p>Living in Numeria required you to become an expert scavenger, searching through ruins and crash sites for valuables and sustenance. Years spent in this pursuit have given you a keen eye for finding valuables and potentially useful resources in the unlikeliest places. You gain a +2 trait bonus on Perception checks when you search a location for valuables or resources. Appraise is always a class skill for you.</p>
<blockquote>
<p><strong>Sources</strong> <Link to="/source/heroes_from_the_fringe">Heroes from the Fringe</Link></p>
</blockquote>
</>};
const _rice_runner = {title: "Rice Runner", topLink: ["Regional Traits","main/traits_regional"], jsx: <><h2 id="trait-rice_runner-rice-runner">Rice Runner</h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> Wanshou</p>
<p>You grew up as a slave in Wanshou, harvesting rice for your kraken despot, and you know how to move agilely across sodden and unsteady ground. You gain a +1 trait bonus on Acrobatics checks, and Acrobatics becomes a class skill for you.</p>
<blockquote>
<p><strong>Sources</strong> <Link to="/source/dragon_empires_primer">Dragon Empires Primer</Link></p>
</blockquote>
</>};
const _rider_of_paresh = {title: "Rider of Paresh", topLink: ["Regional Traits","main/traits_regional"], jsx: <><h2 id="trait-rider_of_paresh-rider-of-paresh">Rider of Paresh</h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> Qadira<br/><strong>Requirements:</strong> <Link to="/feat/mounted_combat">Mounted Combat</Link> feat</p>
<p>You call the Plains of Paresh home, whether you were born among the plains' tribes or in the glittering towers of Katheer. The horses are your kin. When mounted and making a charge, your mount's speed is increased by 10 feet.</p>
<blockquote>
<p><strong>Sources</strong> <Link to="/source/inner_sea_primer">Inner Sea Primer</Link>, <Link to="/source/qadira_gateway_to_the_east">Qadira, Gateway to the East</Link></p>
</blockquote>
</>};
const _river_navigator = {title: "River Navigator", topLink: ["Regional Traits","main/traits_regional"], jsx: <><h2 id="trait-river_navigator-river-navigator">River Navigator</h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> River Kingdoms</p>
<p>You grew up in the River Kingdoms and are familiar with the many winding streams that cross the land. You gain a +1 trait bonus on Survival checks or Profession (sailor) checks dealing with lakes, rivers, and their immediate surroundings, and one of these skills becomes a class skill for you.</p>
<blockquote>
<p><strong>Sources</strong> <Link to="/source/pirates_of_the_inner_sea">Pirates of the Inner Sea</Link></p>
</blockquote>
</>};
const _river_rat = {title: "River Rat", topLink: ["Regional Traits","main/traits_regional"], jsx: <><h2 id="trait-river_rat-river-rat">River Rat</h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> swamp or river</p>
<p>You learned to swim right after you learned to walk. When you were a youth, a gang of river pirates put you to work swimming in nighttime rivers and canals with a dagger between your teeth so you could sever the anchor ropes of merchant vessels. You gain a +1 trait bonus on damage rolls with a dagger and a +1 trait bonus on Swim checks. Swim is always a class skill for you.</p>
<blockquote>
<p><strong>Sources</strong> <Link to="/source/ultimate_campaign">Ultimate Campaign</Link>, <Link to="/source/advanced_players_guide">Advanced Player's Guide</Link>, <Link to="/source/taldor_echoes_of_glory">Taldor, Echoes of Glory</Link></p>
</blockquote>
</>};
const _river_sniper = {title: "River Sniper", topLink: ["Regional Traits","main/traits_regional"], jsx: <><h2 id="trait-river_sniper-river-sniper">River Sniper</h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> River Kingdoms</p>
<p>Unlike seagoing pirates, you're used to fighting most of your ship-to-ship battles at close range, and understand the value of a well-placed arrow. When on the deck of a waterborne vessel, you gain a +1 trait bonus on attacks with ranged weapons.</p>
<blockquote>
<p><strong>Sources</strong> <Link to="/source/pirates_of_the_inner_sea">Pirates of the Inner Sea</Link></p>
</blockquote>
</>};
const _riverfolk = {title: "Riverfolk", topLink: ["Regional Traits","main/traits_regional"], jsx: <><h2 id="trait-riverfolk-riverfolk">Riverfolk</h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> River Kingdoms</p>
<p>You've grown up on the tributaries of the Sellen River system, and are as comfortable on boats as on land. You gain a +2 trait bonus on Profession (sailor) checks and any skill checks involving rope use.</p>
<blockquote>
<p><strong>Sources</strong> <Link to="/source/inner_sea_primer">Inner Sea Primer</Link></p>
</blockquote>
</>};
const _roof_racer = {title: "Roof Racer", topLink: ["Regional Traits","main/traits_regional"], jsx: <><h2 id="trait-roof_racer-roof-racer">Roof Racer</h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> Korvosa</p>
<p>You've spent more than your fair share of time among the strange sloping slums that cover the rooftops of much of Old Korvosa. When using the Acrobatics skill to make a long jump, you treat the DC of the skill check as if the distance being jumped were 5 feet shorter than it actually is.</p>
<blockquote>
<p><strong>Sources</strong> <Link to="/source/varisia_birthplace_of_legends">Varisia, Birthplace of Legends</Link></p>
</blockquote>
</>};
const _runaway_slave = {title: "Runaway Slave", topLink: ["Regional Traits","main/traits_regional"], jsx: <><h2 id="trait-runaway_slave-runaway-slave">Runaway Slave</h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> Osirion, Thuvia, or Darklands-adjacent</p>
<p>Though the ghouls of Nemret Noktoria and the drow of Zirnakaynin seldom darken the surface of Golarion, both have pacts with influential slavers and warlords who periodically provide the demon worshipers with kidnapped slaves. You were once one of these unfortunate victims and were destined to become a sacrifice to a dreadful demon lord, but you managed to slip your bonds and escape back to the surface. The horrors you witnessed were beyond fathoming, and though visions of imprisoned loved ones and friends plague your dreams, you are stronger for the experience. You gain a +1 trait bonus on saves against fear effects and gain low-light vision 10 feet. If you already have low-light vision, its range extends by 10 feet.</p>
<blockquote>
<p><strong>Sources</strong> <Link to="/source/demon_hunters_handbook">Demon Hunter's Handbook</Link></p>
</blockquote>
</>};
const _sargavan_guard = {title: "Sargavan Guard", topLink: ["Regional Traits","main/traits_regional"], jsx: <><h2 id="trait-sargavan_guard-sargavan-guard">Sargavan Guard</h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> Sargava</p>
<p>You served in the Sargavan Guard, either as a colonial sub-praetor or as a native Mwangi regular, and have grown accustomed to marching in hot temperatures while wearing armor. When you wear armor of any sort, reduce the armor check penalty by 1, to a minimum penalty of 0.</p>
<blockquote>
<p><strong>Sources</strong> <Link to="/source/inner_sea_primer">Inner Sea Primer</Link></p>
</blockquote>
</>};
const _savage_breaker = {title: "Savage Breaker", topLink: ["Regional Traits","main/traits_regional"], jsx: <><h2 id="trait-savage_breaker-savage-breaker">Savage Breaker</h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> Korvosa</p>
<p>You openly despise the crude Shoanti and their backward ways. You gain a +2 trait bonus on combat maneuver checks made to sunder clubs, earth breakers, klars, hide armor, primitive armor and weapons, and any other equipment the GM deems "barbarian-made."</p>
<blockquote>
<p><strong>Sources</strong> <Link to="/source/varisia_birthplace_of_legends">Varisia, Birthplace of Legends</Link></p>
</blockquote>
</>};
const _savanna_child = {title: "Savanna Child", topLink: ["Regional Traits","main/traits_regional"], jsx: <><h2 id="trait-savanna_child-savanna-child">Savanna Child</h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> Katapesh, plains</p>
<p>You were born and raised in central Katapesh, among the rolling savannahs that dominate the nation's interior. You spent many of your youth exploring these vast reaches, and know much of the savannah's secrets. Pick one of the following skills: Handle Animal, Knowledge (nature), or Ride. You gain a +1 trait bonus on that skill, and it is always a class skill for you.</p>
<blockquote>
<p><strong>Sources</strong> <Link to="/source/ultimate_campaign">Ultimate Campaign</Link>, <Link to="/source/advanced_players_guide">Advanced Player's Guide</Link>, <Link to="/source/legacy_of_fire_players_guide">Legacy of Fire Player's Guide</Link></p>
</blockquote>
</>};
const _scion_of_goblinblood = {title: "Scion of Goblinblood", topLink: ["Regional Traits","main/traits_regional"], jsx: <><h2 id="trait-scion_of_goblinblood-scion-of-goblinblood">Scion of Goblinblood</h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> Isger<br/><strong>Requirements:</strong> Goblin</p>
<p>The fury of the Goblinblood Wars still courses through your veins. Whenever you're within 60 feet of an enemy hobgoblin, you gain a +1 trait bonus on all weapon damage rolls.</p>
<blockquote>
<p><strong>Sources</strong> <Link to="/source/goblins_of_golarion">Goblins of Golarion</Link></p>
</blockquote>
</>};
const _scion_of_the_shory = {title: "Scion of the Shory", topLink: ["Regional Traits","main/traits_regional"], jsx: <><h2 id="trait-scion_of_the_shory-scion-of-the-shory">Scion of the Shory</h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> Mwangi Expanse</p>
<p>The blood of a Shory aeromancer flows through your veins. You gain a +2 bonus on <Link to="/rule/concentration">concentration</Link> checks when casting flight spells such as <Link to="/spell/levitate">levitate</Link>, <Link to="/spell/fly">fly</Link>, or <Link to="/spell/overland_flight">overland flight</Link>. Once per day, you can use <Link to="/spell/message">message</Link> as a spell-like ability.</p>
<blockquote>
<p><strong>Sources</strong> <Link to="/source/advanced_class_origins">Advanced Class Origins</Link></p>
</blockquote>
</>};
const _scourge_of_the_seas = {title: "Scourge of the Seas", topLink: ["Regional Traits","main/traits_regional"], jsx: <><h2 id="trait-scourge_of_the_seas-scourge-of-the-seas">Scourge of the Seas</h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> The Shackles</p>
<p>You have long appreciated the flamboyance and versatility of the whip, both as a weapon and a tool for enforcing discipline. When you wield a whip or scourge, you gain a +1 trait bonus on Intimidate checks. Additionally, once per day when you use a whip or scourge to perform a successful disarm or trip combat maneuver against an opponent, you regain 1 point of grit or panache.</p>
<blockquote>
<p><strong>Sources</strong> <Link to="/source/advanced_class_origins">Advanced Class Origins</Link></p>
</blockquote>
</>};
const _scrambling_servant = {title: "Scrambling Servant", topLink: ["Regional Traits","main/traits_regional"], jsx: <><h2 id="trait-scrambling_servant-scrambling-servant">Scrambling Servant</h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> mountains</p>
<p>You were hired or captured by giants and found yourself frequently scrambling up and down giant-sized furniture or slave pit walls. As a result, you are an agile climber. You retain your Dexterity bonus to Armor Class while climbing and gain a +1 trait bonus on Climb checks.</p>
<p>Likely Regions: Osirion, Rahadoum, the Shackles, Thuvia, Varisia.</p>
<p>Likely giants: Cave, Fire, River, Slag, Storm</p>
<blockquote>
<p><strong>Sources</strong> <Link to="/source/giant_hunters_handbook">Giant Hunter's Handbook</Link></p>
</blockquote>
</>};
const _screaming_leap = {title: "Screaming Leap", topLink: ["Regional Traits","main/traits_regional"], jsx: <><h2 id="trait-screaming_leap-screaming-leap">Screaming Leap</h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> Realm of the Mammoth Lords</p>
<p>The rocky foothills of your homeland are ideal for staging leaping ambushes that leave your victims battered and routed. You gain a +1 trait bonus on melee damage rolls when you make a charge attack from higher ground. Once per day, when you make a charge attack from higher ground, you can use the Intimidate skill to demoralize your target as a swift action.</p>
<blockquote>
<p><strong>Sources</strong> <Link to="/source/advanced_class_origins">Advanced Class Origins</Link></p>
</blockquote>
</>};
const _sea_souled = {title: "Sea-Souled", topLink: ["Regional Traits","main/traits_regional"], jsx: <><h2 id="trait-sea_souled-sea-souled">Sea-Souled</h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> coastal or island</p>
<p>You are at home at sea. You receive a +1 trait bonus on Swim checks, and you can always take 10 while Swimming.</p>
<blockquote>
<p><strong>Sources</strong> <Link to="/source/ultimate_campaign">Ultimate Campaign</Link></p>
</blockquote>
</>};
const _seasoned_climber = {title: "Seasoned Climber", topLink: ["Regional Traits","main/traits_regional"], jsx: <><h2 id="trait-seasoned_climber-seasoned-climber">Seasoned Climber</h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> Wall of Heaven</p>
<p>Your time on the slopes of the Wall of Heaven has improved your ability to surmount great peaks. You gain a +1 trait bonus on Climb checks, and Climb becomes a class skill for you.</p>
<blockquote>
<p><strong>Sources</strong> <Link to="/source/dragon_empires_primer">Dragon Empires Primer</Link></p>
</blockquote>
</>};
const _secret_revolutionary = {title: "Secret Revolutionary", topLink: ["Regional Traits","main/traits_regional"], jsx: <><h2 id="trait-secret_revolutionary-secret-revolutionary">Secret Revolutionary</h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> Cheliax</p>
<p>You seek to return Cheliax to its heyday before the rise of the House of the Thrune. You have trained yourself to resist any questioning or torture should you ever be caught. You gain a +1 trait bonus on Will saves against mind-affecting effects, and on Fortitude saves against drugs or poisons.</p>
<blockquote>
<p><strong>Sources</strong> <Link to="/source/inner_sea_primer">Inner Sea Primer</Link></p>
</blockquote>
</>};
const _secret_of_the_impossible_kingdom = {title: "Secret of the Impossible Kingdom", topLink: ["Regional Traits","main/traits_regional"], jsx: <><h2 id="trait-secret_of_the_impossible_kingdom-secret-of-the-impossible-kingdom">Secret of the Impossible Kingdom</h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> Jalmeray</p>
<p>You have studied the ancient lore of Vudra at a monastery in Jalmeray, and have learned a mystical secret that empowers your spellcasting. Pick one spell when you choose this trait - from this point on, whenever you cast that spell, you do so at +1 caster level.</p>
<blockquote>
<p><strong>Sources</strong> <Link to="/source/inner_sea_primer">Inner Sea Primer</Link></p>
</blockquote>
</>};
const _servitor_of_spirits = {title: "Servitor of Spirits", topLink: ["Regional Traits","main/traits_regional"], jsx: <><h2 id="trait-servitor_of_spirits-servitor-of-spirits">Servitor of Spirits</h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> Tian Xia</p>
<p>For as long as you can remember, the spirits have always whispered into your ears and guided you-provided that you appease them. At the start of each day, you can choose one <Link to="/ability/spirits">medium spirit</Link> and accept one of its taboos for 24 hours. As long as you don't break that taboo, once during the next 24 hours, you can add a +1 trait bonus to any one roll, check, or saving throw (but not to AC) listed under your chosen spirit's spirit bonus. Using this ability is a free action that you can use even if it isn't your turn. If you are a medium, the spirit you choose with this trait must be the same as the spirit you are channeling and vice versa</p>
<blockquote>
<p><strong>Sources</strong> <Link to="/source/healers_handbook">Healer's Handbook</Link></p>
</blockquote>
</>};
const _sevenarches_seeker = {title: "Sevenarches Seeker", topLink: ["Regional Traits","main/traits_regional"], jsx: <><h2 id="trait-sevenarches_seeker-sevenarches-seeker">Sevenarches Seeker</h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> Sevenarches</p>
<p>You've long heard rumors about the mysterious archways of Sevenarches and have spent much of your life trying to unravel the mysteries behind the portals. You gain a +1 trait bonus on Knowledge (history) checks and Perception checks to notice secret doors, and Knowledge (history) becomes a class skill for you.</p>
<blockquote>
<p><strong>Sources</strong> <Link to="/source/people_of_the_river">People of the River</Link></p>
</blockquote>
</>};
const _shackles_seafarer = {title: "Shackles Seafarer", topLink: ["Regional Traits","main/traits_regional"], jsx: <><h2 id="trait-shackles_seafarer-shackles-seafarer">Shackles Seafarer</h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> The Shackles</p>
<p>You're familiar with the treacherous coastlines, currents, and tides of the Shackles, and can use that knowledge anywhere. You gain a +1 trait bonus on Knowledge (nature) and Knowledge (geography) checks while on the ocean. You also gain a +1 trait bonus on Swim checks, and Swim is always a class skill for you.</p>
<blockquote>
<p><strong>Sources</strong> <Link to="/source/inner_sea_primer">Inner Sea Primer</Link></p>
</blockquote>
</>};
const _shadow_dealer = {title: "Shadow Dealer", topLink: ["Regional Traits","main/traits_regional"], jsx: <><h2 id="trait-shadow_dealer-shadow-dealer">Shadow Dealer</h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> Ustalav</p>
<p>You have survived and thrived in the dark forests of Ustalav by knowing how to make deals with terrible things. You gain a +1 trait bonus on saving throws against fear effects and a +1 trait bonus on Bluff and Diplomacy skills checks against evil fey, monstrous humanoids, and undead.</p>
<blockquote>
<p><strong>Sources</strong> <Link to="/source/blood_of_the_coven">Blood of the Coven</Link></p>
</blockquote>
</>};
const _shadow_dissident = {title: "Shadow Dissident", topLink: ["Regional Traits","main/traits_regional"], jsx: <><h2 id="trait-shadow_dissident-shadow-dissident">Shadow Dissident</h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> Nidal</p>
<p>Lifelong encounters with conjured shadows have made you especially adept at piercing their dark veils. You gain a +2 trait bonus on saving throws against spells and effects with the shadow descriptor.</p>
<blockquote>
<p><strong>Sources</strong> <Link to="/source/monster_summoners_handbook">Monster Summoner's Handbook</Link></p>
</blockquote>
</>};
const _shadow_shaman = {title: "Shadow Shaman", topLink: ["Regional Traits","main/traits_regional"], jsx: <><h2 id="trait-shadow_shaman-shadow-shaman">Shadow Shaman</h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> Nidal</p>
<p>Shamans in the shadowy kingdom of Nidal learn to speak with the spirits that live in shadow. Add silent image and blur to your shaman spell list as 1st- and 2nd-level spells, respectively.</p>
<blockquote>
<p><strong>Sources</strong> <Link to="/source/advanced_class_origins">Advanced Class Origins</Link></p>
</blockquote>
</>};
const _shadowsight = {title: "Shadowsight", topLink: ["Regional Traits","main/traits_regional"], jsx: <><h2 id="trait-shadowsight-shadowsight">Shadowsight</h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> Nidal</p>
<p>Your people's ancient compact with Zon-Kuthon manifests strongly in you. While the darkness remains fearsome, you can at least see what lurks there. As a swift action once per day, your eyes can pierce the surrounding darkness-you gain the benefit of low-light vision for a number of rounds equal to your level.</p>
<blockquote>
<p><strong>Sources</strong> <Link to="/source/champions_of_corruption">Champions of Corruption</Link></p>
</blockquote>
</>};
const _shaer = {title: "Shaer", topLink: ["Regional Traits","main/traits_regional"], jsx: <><h2 id="trait-shaer-shaer">Shaer</h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> Qadira<br/><strong>Requirements:</strong> Kelish</p>
<p>Qadira is a land of poetry, and you have grown up immersed in the words and language of that culture. Your facility with the language is evident to all when you speak. You gain a +2 trait bonus on Bluff and Diplomacy checks when speaking with anyone fluent in Kelish.</p>
<blockquote>
<p><strong>Sources</strong> <Link to="/source/heroes_from_the_fringe">Heroes from the Fringe</Link></p>
</blockquote>
</>};
const _sharp_eyes = {title: "Sharp Eyes", topLink: ["Regional Traits","main/traits_regional"], jsx: <><h2 id="trait-sharp_eyes-sharp-eyes">Sharp Eyes</h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> tundra</p>
<p>You are immune to the dazzled condition.</p>
<blockquote>
<p><strong>Sources</strong> <Link to="/source/wilderness_origins">Wilderness Origins</Link></p>
</blockquote>
</>};
const _shenmen_prospector = {title: "Shenmen Prospector", topLink: ["Regional Traits","main/traits_regional"], jsx: <><h2 id="trait-shenmen_prospector-shenmen-prospector">Shenmen Prospector</h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> Shenmen</p>
<p>You were a talented laborer in the silver mines of Shenmen, and have seen many wonders in the haunted caverns beneath the surface of the cursed nation. You gain a +1 trait bonus on Appraise and Knowledge (dungeoneering) checks.</p>
<blockquote>
<p><strong>Sources</strong> <Link to="/source/dragon_empires_primer">Dragon Empires Primer</Link></p>
</blockquote>
</>};
const _ship_aptitude = {title: "Ship Aptitude", topLink: ["Regional Traits","main/traits_regional"], jsx: <><h2 id="trait-ship_aptitude-ship-aptitude">Ship Aptitude</h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> The Shackles</p>
<p>You are used to crewing on many of the different types of ships that sail the Shackles. As a result, you have a knack for quickly determining the weaknesses and strengths of any ship, even ones you've never set foot on before. You gain a +1 trait bonus on Profession (sailor) checks, and Profession (sailor) becomes a class skill for you.</p>
<blockquote>
<p><strong>Sources</strong> <Link to="/source/pirates_of_the_inner_sea">Pirates of the Inner Sea</Link></p>
</blockquote>
</>};
const _shipboard_caster = {title: "Shipboard Caster", topLink: ["Regional Traits","main/traits_regional"], jsx: <><h2 id="trait-shipboard_caster-shipboard-caster">Shipboard Caster</h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> Riddleport</p>
<p>You feel an affinity with ships and the sea, and the rolling rhythm of the waves helps focus your mind. When on a ship or other water-going vessel, you gain a +3 bonus on <Link to="/rule/concentration">concentration</Link> checks.</p>
<blockquote>
<p><strong>Sources</strong> <Link to="/source/pirates_of_the_inner_sea">Pirates of the Inner Sea</Link></p>
</blockquote>
</>};
const _shoanti_tribesman = {title: "Shoanti Tribesman", topLink: ["Regional Traits","main/traits_regional"], jsx: <><h2 id="trait-shoanti_tribesman-shoanti-tribesman">Shoanti Tribesman</h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> Varisia</p>
<p>You were born or adopted into a Shoanti tribe. Choose one of the following skills: Climb, Survival, or Swim. You gain a +1 trait bonus on this skill, and it is always a class skill for you.</p>
<blockquote>
<p><strong>Sources</strong> <Link to="/source/inner_sea_primer">Inner Sea Primer</Link></p>
</blockquote>
</>};
const _signaler = {title: "Signaler", topLink: ["Regional Traits","main/traits_regional"], jsx: <><h2 id="trait-signaler-signaler">Signaler</h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> Molthune</p>
<p>By watching Imperial troops, you know how to use flags, smoke signals, and other methods to send secret messages, and gain a +5 trait bonus on Bluff checks to receive secret messages and a +5 trait bonus on Sense Motive checks to intercept messages.</p>
<blockquote>
<p><strong>Sources</strong> <Link to="/source/inner_sea_primer">Inner Sea Primer</Link></p>
</blockquote>
</>};
const _silent_watcher = {title: "Silent Watcher", topLink: ["Regional Traits","main/traits_regional"], jsx: <><h2 id="trait-silent_watcher-silent-watcher">Silent Watcher</h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> Galt</p>
<p>You can sense an ugly mood brewing in a crowd, and know how to dodge wrathful mobs when they seek victims for their anger. You gain a +1 trait bonus on Sense Motive checks in crowds, and a +1 trait bonus on Stealth checks in city streets.</p>
<blockquote>
<p><strong>Sources</strong> <Link to="/source/inner_sea_primer">Inner Sea Primer</Link></p>
</blockquote>
</>};
const _silvertongued_eunuch = {title: "Silvertongued Eunuch", topLink: ["Regional Traits","main/traits_regional"], jsx: <><h2 id="trait-silvertongued_eunuch-silvertongued-eunuch">Silvertongued Eunuch</h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> Quain</p>
<p>You were brought up as part of Quain's strictly eunuch bureaucracy, trading your sexual potency for education and tact. You gain a +1 trait bonus on Knowledge (nobility) and Diplomacy checks.</p>
<blockquote>
<p><strong>Sources</strong> <Link to="/source/dragon_empires_primer">Dragon Empires Primer</Link></p>
</blockquote>
</>};
const _skilled_surgeon = {title: "Skilled Surgeon", topLink: ["Regional Traits","main/traits_regional"], jsx: <><h2 id="trait-skilled_surgeon-skilled-surgeon">Skilled Surgeon</h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> Qadira or Ustalav</p>
<p>Whenever you perform surgery or otherwise must deal damage to remove a condition or affliction, you roll the damage but use the minimum result unless you rolled the maximum result. The amount of hit points or points of ability damage restored each day when you provide long-term care is increased by 1.</p>
<blockquote>
<p><strong>Sources</strong> <Link to="/source/healers_handbook">Healer's Handbook</Link></p>
</blockquote>
</>};
const _sky_spirit_worshipper = {title: "Sky Spirit Worshipper", topLink: ["Regional Traits","main/traits_regional"], jsx: <><h2 id="trait-sky_spirit_worshipper-sky-spirit-worshipper">Sky Spirit Worshipper</h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> Mutabi-qi</p>
<p>As the child of a Mutabi-qi shaman, you have seen the sky spirits that roam above and know that the world is rife with unexplainable and terrifying mysteries. You gain a +2 trait bonus on saves against fear effects.</p>
<blockquote>
<p><strong>Sources</strong> <Link to="/source/dragon_empires_primer">Dragon Empires Primer</Link></p>
</blockquote>
</>};
const _skymetal_affinity = {title: "Skymetal Affinity", topLink: ["Regional Traits","main/traits_regional"], jsx: <><h2 id="trait-skymetal_affinity-skymetal-affinity">Skymetal Affinity</h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> Numeria</p>
<p>You gain a +2 trait bonus on Fortitude saves against the negative effects of <Link to="/eq-material/skymetal">skymetals</Link>, as well as a +2 trait bonus on Craft checks made to create weapons or armor out of skymetals.</p>
<blockquote>
<p><strong>Sources</strong> <Link to="/source/people_of_the_stars">People of the Stars</Link></p>
</blockquote>
</>};
const _slave_taker = {title: "Slave Taker", topLink: ["Regional Traits","main/traits_regional"], jsx: <><h2 id="trait-slave_taker-slave-taker">Slave Taker</h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> Okeno</p>
<p>You specialize in disabling foes without wounding them, preserving their value as slaves. Whenever you deal nonlethal damage in combat, that damage increases by +1.</p>
<blockquote>
<p><strong>Sources</strong> <Link to="/source/pirates_of_the_inner_sea">Pirates of the Inner Sea</Link></p>
</blockquote>
</>};
const _slayer_of_the_deep = {title: "Slayer of the Deep", topLink: ["Regional Traits","main/traits_regional"], jsx: <><h2 id="trait-slayer_of_the_deep-slayer-of-the-deep">Slayer of the Deep</h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> Darklands beneath Tian Xia</p>
<p>You have hunted monsters throughout the Darklands and know how to take advantage of their weaknesses. You gain a +1 trait bonus on damage rolls made against creatures of the aberration type.</p>
<blockquote>
<p><strong>Sources</strong> <Link to="/source/dragon_empires_primer">Dragon Empires Primer</Link></p>
</blockquote>
</>};
const _snake_bleeder = {title: "Snake Bleeder", topLink: ["Regional Traits","main/traits_regional"], jsx: <><h2 id="trait-snake_bleeder-snake-bleeder">Snake Bleeder</h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> Nagajor</p>
<p>You were a nagaji vassal of knowledgeable nagas, and they taught you much regarding how they concoct their various poisons. You gain a +2 trait bonus on Craft (alchemy) checks when brewing poisons, and Craft (alchemy) becomes a class skill for you.</p>
<blockquote>
<p><strong>Sources</strong> <Link to="/source/dragon_empires_primer">Dragon Empires Primer</Link></p>
</blockquote>
</>};
const _snake_handler = {title: "Snake Handler", topLink: ["Regional Traits","main/traits_regional"], jsx: <><h2 id="trait-snake_handler-snake-handler">Snake Handler</h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> Osirion<br/><strong>Religion:</strong> <Link to="/faith/apep">Apep</Link> or <Link to="/faith/wadjet">Wadjet</Link></p>
<p>You have spent time as a member of a cult of either Apep or Wadjet, the serpent gods of Osirion. Membership involved the handling of dangerous snakes during rituals, and you have learned how to keep yourself and others safe around them. You gain a +2 bonus on Fortitude saves against poison. Handle Animal is always a class skill for you.</p>
<blockquote>
<p><strong>Sources</strong> <Link to="/source/heroes_from_the_fringe">Heroes from the Fringe</Link></p>
</blockquote>
</>};
const _snowstride = {title: "Snowstride", topLink: ["Regional Traits","main/traits_regional"], jsx: <><h2 id="trait-snowstride-snowstride">Snowstride</h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> Darklands</p>
<p>The wide stance and sure footing you developed while traipsing over ice-covered rock and frozen earth provides you with a +1 trait bonus on Acrobatics checks made on slippery surfaces and enables you to trip or bull rush opponents two size categories larger than you instead of just one.</p>
<blockquote>
<p><strong>Sources</strong> <Link to="/source/kobolds_of_golarion">Kobolds of Golarion</Link></p>
</blockquote>
</>};
const _social_slaver = {title: "Social Slaver", topLink: ["Regional Traits","main/traits_regional"], jsx: <><h2 id="trait-social_slaver-social-slaver">Social Slaver</h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> Cheliax</p>
<p>Your upbringing has accustomed you to commanding those you deem inferior. You gain a +2 trait bonus on Intimidate checks against creatures one or more size categories smaller than yourself. The DC of compulsion spells cast by you against smaller creatures increases by 1.</p>
<blockquote>
<p><strong>Sources</strong> <Link to="/source/champions_of_corruption">Champions of Corruption</Link></p>
</blockquote>
</>};
const _sodden_chld = {title: "Sodden Chld", topLink: ["Regional Traits","main/traits_regional"], jsx: <><h2 id="trait-sodden_chld-sodden-chld">Sodden Chld</h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> The Sodden Lands</p>
<p>You spent most of your life moving through murky bogs and have grown acclimated to the terrain. You move normally through shallow bogs (as long as the terrain hasn't been magically manipulated) but are still affected by deep bogs as normal.</p>
<blockquote>
<p><strong>Sources</strong> <Link to="/source/people_of_the_wastes">People of the Wastes</Link></p>
</blockquote>
</>};
const _soldier_of_the_faith = {title: "Soldier of the Faith", topLink: ["Regional Traits","main/traits_regional"], jsx: <><h2 id="trait-soldier_of_the_faith-soldier-of-the-faith">Soldier of the Faith</h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> Razmiran</p>
<p>You have served Razmir as a faithful enforcer, or upon one of the "faith barges" plying the waters of Lake Encarthan, and have learned the enforcement techniques of Razmiran. You gain a +1 trait bonus on Intimidate checks, and Intimidate is always a class skill for you.</p>
<blockquote>
<p><strong>Sources</strong> <Link to="/source/inner_sea_primer">Inner Sea Primer</Link></p>
</blockquote>
</>};
const _solidarity = {title: "Solidarity", topLink: ["Regional Traits","main/traits_regional"], jsx: <><h2 id="trait-solidarity-solidarity">Solidarity</h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> City of Brass</p>
<p>While enslaved in the City of Brass, you watched too many of your friends fall victim to efreet tempers. Now, you help others avoid thorny situations whenever you are able. Any time you successfully use the aid another action to help an ally succeed at a Bluff or Escape Artist check, you add a +3 bonus to this check (rather than a +2 bonus).</p>
<blockquote>
<p><strong>Sources</strong> <Link to="/source/blood_of_the_elements">Blood of the Elements</Link></p>
</blockquote>
</>};
const _sophisticated_citizen = {title: "Sophisticated Citizen", topLink: ["Regional Traits","main/traits_regional"], jsx: <><h2 id="trait-sophisticated_citizen-sophisticated-citizen">Sophisticated Citizen</h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> Absalom</p>
<p>You grew up in Absalom, and as a child you learned trivia about people and places from all across the world. Choose Knowledge (geography), Knowledge (local), or Sense Motive; that skill is a class skill for you. In addition, you know one additional bonus language.</p>
<blockquote>
<p><strong>Sources</strong> <Link to="/source/merchants_manifest">Merchant's Manifest</Link></p>
</blockquote>
</>};
const _sound_of_mind = {title: "Sound of Mind", topLink: ["Regional Traits","main/traits_regional"], jsx: <><h2 id="trait-sound_of_mind-sound-of-mind">Sound of Mind</h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> Zi Ha</p>
<p>You have lived in the mountains of Zi Ha and found utter tranquility among the samsarans of the region. You gain a +2 trait bonus on saving throws against mind-affecting effects.</p>
<blockquote>
<p><strong>Sources</strong> <Link to="/source/dragon_empires_primer">Dragon Empires Primer</Link></p>
</blockquote>
</>};
const _spell_duel_prodigy = {title: "Spell Duel Prodigy", topLink: ["Regional Traits","main/traits_regional"], jsx: <><h2 id="trait-spell_duel_prodigy-spell-duel-prodigy">Spell Duel Prodigy</h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> Erages</p>
<p>You've participated in many spell duels during your time at Erages Academy, and You've developed a keen talent for identifying magical arts. You gain a +2 trait bonus on Spellcraft checks to identify a spell as it is being cast and on dispel checks to counterspell a spell.</p>
<blockquote>
<p><strong>Sources</strong> <Link to="/source/bastards_of_golarion">Bastards of Golarion</Link></p>
</blockquote>
</>};
const _spirit_animal = {title: "Spirit Animal", topLink: ["Regional Traits","main/traits_regional"], jsx: <><h2 id="trait-spirit_animal-spirit-animal">Spirit Animal</h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> Realm of the Mammoth Lords</p>
<p>A spirit animal watches over you. Choose one of the following spirit animals. The benefit you receive depends on which of the following spirit animals you choose.</p>
<p><strong>Mammoth:</strong> You gain a +1 trait bonus on Fortitude saves.<br/><strong>Smilodon:</strong> You gain a +1 trait bonus on Reflex saves.<br/><strong>Woolly Rhinoceros:</strong> You gain a +1 trait bonus on Will saves.</p>
<blockquote>
<p><strong>Sources</strong> <Link to="/source/people_of_the_north">People of the North</Link></p>
</blockquote>
</>};
const _spiritual_forester = {title: "Spiritual Forester", topLink: ["Regional Traits","main/traits_regional"], jsx: <><h2 id="trait-spiritual_forester-spiritual-forester">Spiritual Forester</h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> Forest of Spirits</p>
<p>You grew up in a small settlement along the outskirts of the Forest of Spirits, and have learned much about the woods as well as about their supernatural inhabitants. You gain a +1 trait bonus on Knowledge (nature) and Knowledge (planes) checks, and one of these skills becomes a class skill for you.</p>
<blockquote>
<p><strong>Sources</strong> <Link to="/source/dragon_empires_primer">Dragon Empires Primer</Link></p>
</blockquote>
</>};
const _star_reader = {title: "Star Reader", topLink: ["Regional Traits","main/traits_regional"], jsx: <><h2 id="trait-star_reader-star-reader">Star Reader</h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> The Sodden Lands</p>
<p>You are one of the few remaining descendants of the lost civilization of Lirgen. Growing up learning of your people's history has granted you a fine understanding of celestial divination as well as a deep-seated hatred of the demon-worshiping monsters that have come to rule your ancestral lands. While under starlight, the caster level of all your divination spells is increased by 1. If the target of your spell is a demon, the caster level is increased by 2.</p>
<blockquote>
<p><strong>Sources</strong> <Link to="/source/demon_hunters_handbook">Demon Hunter's Handbook</Link></p>
</blockquote>
</>};
const _stargazer_region = {title: "Stargazer (Region)", topLink: ["Regional Traits","main/traits_regional"], jsx: <><h2 id="trait-stargazer_region-stargazer-region">Stargazer (Region)</h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> Lirgen</p>
<p>Having spent your youth staring at the night sky, you gain a +1 trait bonus on Knowledge (arcana) and Knowledge (nature) checks. One of these skills becomes a class skill for you.</p>
<blockquote>
<p><strong>Sources</strong> <Link to="/source/blood_of_the_ancients">Blood of the Ancients pg. 11</Link></p>
</blockquote>
</>};
const _storm_hunter = {title: "Storm Hunter", topLink: ["Regional Traits","main/traits_regional"], jsx: <><h2 id="trait-storm_hunter-storm-hunter">Storm Hunter</h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> Hongal</p>
<p>You learned to hunt in the relentless winds of Hongal, and still make your arrows fly true. When fighting in windy weather, you treat the wind category as one level lower for the purposes of determining penalties on ranged attacks made with normal weapons.</p>
<blockquote>
<p><strong>Sources</strong> <Link to="/source/dragon_empires_primer">Dragon Empires Primer</Link></p>
</blockquote>
</>};
const _stormrunner = {title: "Stormrunner", topLink: ["Regional Traits","main/traits_regional"], jsx: <><h2 id="trait-stormrunner-stormrunner">Stormrunner</h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> The Shackles</p>
<p>You have sailed on some of the roughest seas on Golarion, and have skirted the Eye of Abendego. You're accustomed to the pitch and yaw of sailing vessels, even in a storm, and gain a +2 trait bonus on Acrobatics checks to keep your footing on uneven ground or unsteady surfaces.</p>
<blockquote>
<p><strong>Sources</strong> <Link to="/source/inner_sea_primer">Inner Sea Primer</Link></p>
</blockquote>
</>};
const _stream_nomad = {title: "Stream Nomad", topLink: ["Regional Traits","main/traits_regional"], jsx: <><h2 id="trait-stream_nomad-stream-nomad">Stream Nomad</h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> Darklands</p>
<p>Digging tunnels near a body of rushing water has taught you how to use water as a means of travel and escape. Others whisper that you must have been born with webbed feet. You gain a +1 trait bonus on Swim checks, and Swim is always a class skill for you. You increase the speed of any raft, barge, keelboat, or rowboat you pilot by 4 miles per day (1/2 mile per hour).</p>
<blockquote>
<p><strong>Sources</strong> <Link to="/source/kobolds_of_golarion">Kobolds of Golarion</Link></p>
</blockquote>
</>};
const _street_wary = {title: "Street Wary", topLink: ["Regional Traits","main/traits_regional"], jsx: <><h2 id="trait-street_wary-street-wary">Street Wary</h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> urban</p>
<p>You learned to take care of yourself on the streets and know the warning signs of hostile intent. Sense Motive is always a class skill for you, and you gain a +2 trait bonus on Sense Motive checks to get a hunch.</p>
<blockquote>
<p><strong>Sources</strong> <Link to="/source/heroes_of_the_streets">Heroes of the Streets</Link></p>
</blockquote>
</>};
const _suck_in_your_gut = {title: "Suck in Your Gut", topLink: ["Regional Traits","main/traits_regional"], jsx: <><h2 id="trait-suck_in_your_gut-suck-in-your-gut">Suck in Your Gut</h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> Darklands</p>
<p>Because of the frequent need to move through the tight tunnels and other narrow spaces surrounding your tribe's lair, you're able to move normally when squeezing and take only a -2 penalty on attack rolls and to AC.</p>
<blockquote>
<p><strong>Sources</strong> <Link to="/source/kobolds_of_golarion">Kobolds of Golarion</Link></p>
</blockquote>
</>};
const _sun_orchid_harvester = {title: "Sun Orchid Harvester", topLink: ["Regional Traits","main/traits_regional"], jsx: <><h2 id="trait-sun_orchid_harvester-sun-orchid-harvester">Sun Orchid Harvester</h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> Thuvia</p>
<p>You were employed briefly by the blue dragon Deyrubrujuan's alchemist cabal to harvest sun orchids deep in the Thuvian desert. Though you never worked your way deeper into the cabal, you retain the knowledge gained during your employment. You gain a +1 bonus on Knowledge (nature) and Survival checks made in desert environments.</p>
<blockquote>
<p><strong>Sources</strong> <Link to="/source/dragonslayers_handbook">Dragonslayer's Handbook</Link></p>
</blockquote>
</>};
const _sun_blasted = {title: "Sun-Blasted", topLink: ["Regional Traits","main/traits_regional"], jsx: <><h2 id="trait-sun_blasted-sun-blasted">Sun-Blasted</h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> desert</p>
<p>Desert orcs have learnt to survive with practically nothing in the desert. You receive a +2 trait bonus on Survival checks made in a desert, and resolve all checks at becoming lost in deserts as though you had proper navigational tools (a +4 bonus). The presence of such tools does not increase your ability, however.</p>
<blockquote>
<p><strong>Sources</strong> <Link to="/source/orcs_of_golarion">Orcs of Golarion</Link></p>
</blockquote>
</>};
const _superstitious_isp = {title: "Superstitious (ISP)", topLink: ["Regional Traits","main/traits_regional"], jsx: <><h2 id="trait-superstitious_isp-superstitious-isp">Superstitious (ISP)</h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> Realm of the Mammoth Lords</p>
<p>You are distrustful of any magic that goes beyond your native shamanic ways. As long as you do not possess any levels in a class that grants arcane spellcasting power, you gain a +1 trait bonus on all saving throws against arcane spells.</p>
<blockquote>
<p><strong>Sources</strong> <Link to="/source/inner_sea_primer">Inner Sea Primer</Link></p>
</blockquote>
</>};
const _superstitious_ward = {title: "Superstitious Ward", topLink: ["Regional Traits","main/traits_regional"], jsx: <><h2 id="trait-superstitious_ward-superstitious-ward">Superstitious Ward</h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> Ustalav</p>
<p>You're not frightened of the old wives' tales of vampires and ghosts, and though you try to avoid the undead, you've learned how to deal with them. You may cast <Link to="/spell/disrupt_undead">disrupt undead</Link> once per day as a spell-like ability. This is cast at your highest caster level gained; if you have no caster level, it functions at CL 1st.</p>
<blockquote>
<p><strong>Sources</strong> <Link to="/source/inner_sea_primer">Inner Sea Primer</Link></p>
</blockquote>
</>};
const _surefooted_ascent = {title: "Surefooted Ascent", topLink: ["Regional Traits","main/traits_regional"], jsx: <><h2 id="trait-surefooted_ascent-surefooted-ascent">Surefooted Ascent</h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> hills or mountains</p>
<p>You gain a +1 trait bonus on Acrobatics and Climb checks.</p>
<blockquote>
<p><strong>Sources</strong> <Link to="/source/wilderness_origins">Wilderness Origins</Link></p>
</blockquote>
</>};
const _surface_stranger = {title: "Surface Stranger", topLink: ["Regional Traits","main/traits_regional"], jsx: <><h2 id="trait-surface_stranger-surface-stranger">Surface Stranger</h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> underground</p>
<p>You were born and raised in a subterranean home with little or no bright light. Your miss chance for <Link to="/rule/concealment">concealment</Link> or total concealment due to either mundane or magical darkness decreases by 10%. You are dazzled for 1 round when you are suddenly exposed to bright light.</p>
<blockquote>
<p><strong>Sources</strong> <Link to="/source/ultimate_campaign">Ultimate Campaign</Link></p>
</blockquote>
</>};
const _sustaining_performance = {title: "Sustaining Performance", topLink: ["Regional Traits","main/traits_regional"], jsx: <><h2 id="trait-sustaining_performance-sustaining-performance">Sustaining Performance</h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> The Shackles</p>
<p>Abandoned by a traditional healer at a critical time, you improvised a tale or jokes to keep up the spirits of someone in dire health. Once per day as a standard action, you can attempt a DC 15 Perform check with an audible component (such as comedy, oratory, sing, or with any instrument) to stabilize a dying creature that can hear you within 30 feet. You can also attempt Perform checks instead of Heal checks to provide long-term care.</p>
<blockquote>
<p><strong>Sources</strong> <Link to="/source/healers_handbook">Healer's Handbook</Link></p>
</blockquote>
</>};
const _swamp_rebel = {title: "Swamp Rebel", topLink: ["Regional Traits","main/traits_regional"], jsx: <><h2 id="trait-swamp_rebel-swamp-rebel">Swamp Rebel</h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> Wanshou</p>
<p>You grew up hiding in the swamps from the monstrous overlords who enslaved you and your people. You gain a +2 trait bonus on Stealth checks in swampy terrain, and Stealth becomes a class skill for you.</p>
<blockquote>
<p><strong>Sources</strong> <Link to="/source/dragon_empires_primer">Dragon Empires Primer</Link></p>
</blockquote>
</>};
const _swamp_recluse = {title: "Swamp Recluse", topLink: ["Regional Traits","main/traits_regional"], jsx: <><h2 id="trait-swamp_recluse-swamp-recluse">Swamp Recluse</h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> swamp</p>
<p>You gain a +2 trait bonus on saving throws against poison, and you can safely eat raw fish and game without any effort spent cooking or cleaning them.</p>
<blockquote>
<p><strong>Sources</strong> <Link to="/source/wilderness_origins">Wilderness Origins</Link></p>
</blockquote>
</>};
const _swamp_skulker = {title: "Swamp Skulker", topLink: ["Regional Traits","main/traits_regional"], jsx: <><h2 id="trait-swamp_skulker-swamp-skulker">Swamp Skulker</h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> River Kingdoms</p>
<p>Terrible things prowl the moors of your homeland, and you are all too familiar with hiding or fleeing from them. You gain a +1 trait bonus on Stealth checks when you are in bog, marsh, or swamp terrain, and you treat shallow bogs and swamp undergrowth as normal terrain for the purposes of movement.</p>
<blockquote>
<p><strong>Sources</strong> <Link to="/source/blood_of_the_coven">Blood of the Coven</Link></p>
</blockquote>
</>};
const _swamp_survivor = {title: "Swamp Survivor", topLink: ["Regional Traits","main/traits_regional"], jsx: <><h2 id="trait-swamp_survivor-swamp-survivor">Swamp Survivor</h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> Ustalav</p>
<p>Leaving Graidmere Swamp is forbidden, and to flee the mire is to court the black dragon Seryzilian's wrath. However, you are one of the few to successfully make it out of the swamp alive. Now, you're resolved to liberate your kinfolk. You gain a +2 bonus on Survival checks to find fresh water, and magical liquids in your possession gain a +2 bonus on Will saves to avoid being corrupted or otherwise spoiled.</p>
<blockquote>
<p><strong>Sources</strong> <Link to="/source/dragonslayers_handbook">Dragonslayer's Handbook</Link></p>
</blockquote>
</>};
const _swordlords_page = {title: "Swordlord's Page", topLink: ["Regional Traits","main/traits_regional"], jsx: <><h2 id="trait-swordlords_page-swordlords-page">Swordlord's Page</h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> Brevoy</p>
<p>You have trained under the Aldori swordlords, and though not yet a swordlord yourself, you have learned how to strike hard with your weapon. You gain a +1 attack bonus to confirm critical hits when using an edged weapon you are proficient with.</p>
<blockquote>
<p><strong>Sources</strong> <Link to="/source/inner_sea_primer">Inner Sea Primer</Link></p>
</blockquote>
</>};
const _szaezan_crags_miner = {title: "Szaezan Crags Miner", topLink: ["Regional Traits","main/traits_regional"], jsx: <><h2 id="trait-szaezan_crags_miner-szaezan-crags-miner">Szaezan Crags Miner</h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> Bachuan</p>
<p>You were a miner of the now-scarce ores of the Szaezan Crags, and have become adept at identifying minerals and gems. You gain a +1 trait bonus on Appraise checks, and Appraise becomes a class skill for you.</p>
<blockquote>
<p><strong>Sources</strong> <Link to="/source/dragon_empires_primer">Dragon Empires Primer</Link></p>
</blockquote>
</>};
const _tanglebriar_guerrilla = {title: "Tanglebriar Guerrilla", topLink: ["Regional Traits","main/traits_regional"], jsx: <><h2 id="trait-tanglebriar_guerrilla-tanglebriar-guerrilla">Tanglebriar Guerrilla</h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> Kyonin</p>
<p>Your campaign against Treerazer has endeared you to Kyonin's rangers, who have taught you their ways. When you gain this trait, select one ranger trap that doesn't deal ability or hit point damage. You can use this trap once per day within a forest. The DC for your trap is equal to 10 + half your character level + your Wisdom modifier (minimum +0), and it lasts for 1 day. If you are not a ranger, you can set only extraordinary traps with this feat; like all extraordinary ranger traps, this decreases the trap DC by 2.</p>
<blockquote>
<p><strong>Sources</strong> <Link to="/source/people_of_the_wastes">People of the Wastes</Link></p>
</blockquote>
</>};
const _technic_tinkerer = {title: "Technic Tinkerer", topLink: ["Regional Traits","main/traits_regional"], jsx: <><h2 id="trait-technic_tinkerer-technic-tinkerer">Technic Tinkerer</h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> Numeria</p>
<p>You managed to uncover some lesser secrets of the Technic League, and have mastered a minor bit of magic. Choose a 0-level spell. You may cast that spell once per day as a spell-like ability. This is cast at your highest caster level gained; if you have no caster level, it functions at CL 1st.</p>
<blockquote>
<p><strong>Sources</strong> <Link to="/source/inner_sea_primer">Inner Sea Primer</Link></p>
</blockquote>
</>};
const _technological_brewmaster = {title: "Technological Brewmaster", topLink: ["Regional Traits","main/traits_regional"], jsx: <><h2 id="trait-technological_brewmaster-technological-brewmaster">Technological Brewmaster</h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> Numeria</p>
<p>You have learned the secret of creating potions using advanced scientific techniques so strange that some might consider them alien. When brewing a potion, you can increase its base creation cost by 10% to brew it in half the normal amount of time. This trait does not grant the ability to brew potions.</p>
<blockquote>
<p><strong>Sources</strong> <Link to="/source/potions_and_poisons">Potions and Poisons</Link></p>
</blockquote>
</>};
const _the_vessel_between = {title: "The Vessel Between", topLink: ["Regional Traits","main/traits_regional"], jsx: <><h2 id="trait-the_vessel_between-the-vessel-between">The Vessel Between</h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> Daggermark</p>
<p>The assassin ushers her victims from the kingdoms of the living to the kingdom of the dead. You gain a +1 trait bonus on attack rolls that would deal sneak attack damage on a hit.</p>
<blockquote>
<p><strong>Sources</strong> <Link to="/source/people_of_the_river">People of the River</Link></p>
</blockquote>
</>};
const _thoughtful_wish_maker = {title: "Thoughtful Wish-Maker", topLink: ["Regional Traits","main/traits_regional"], jsx: <><h2 id="trait-thoughtful_wish_maker-thoughtful-wish-maker">Thoughtful Wish-Maker</h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> Plane of Fire</p>
<p>You are well acquainted with the many ways words can be twisted. You gain a +2 trait bonus on Sense Motive checks. Furthermore, if you succeed at a DC 25 Sense Motive check prior to making any wish granted by an outsider, you become aware of your wish's potential pitfalls. If you succeed at this check by 5 or more, you figure out how to word your wish in such a way that your words are not twisted.</p>
<blockquote>
<p><strong>Sources</strong> <Link to="/source/blood_of_the_elements">Blood of the Elements</Link></p>
</blockquote>
</>};
const _thuvian_merchant = {title: "Thuvian Merchant", topLink: ["Regional Traits","main/traits_regional"], jsx: <><h2 id="trait-thuvian_merchant-thuvian-merchant">Thuvian Merchant</h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> Thuvia</p>
<p>You have traveled the great circular trade route around Thuvia, following the sale of the <Link to="/magic-artifact/sun_orchid_elixir">sun orchid elixir</Link> from city to city, and are used to haggling with foreigners. You gain a +1 trait bonus on Appraise, Bluff, and Sense Motive checks made for business deals and transactions.</p>
<blockquote>
<p><strong>Sources</strong> <Link to="/source/inner_sea_primer">Inner Sea Primer</Link></p>
</blockquote>
</>};
const _tianjing_temple_guard = {title: "Tianjing Temple Guard", topLink: ["Regional Traits","main/traits_regional"], jsx: <><h2 id="trait-tianjing_temple_guard-tianjing-temple-guard">Tianjing Temple Guard</h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> Tianjing</p>
<p>You were a stalwart guard of one of Tianjing's magnificent temple cities, and your resolve proved to be of great use during bandit raids. You gain a +1 trait bonus on attacks of opportunity made with polearm weapons.</p>
<blockquote>
<p><strong>Sources</strong> <Link to="/source/dragon_empires_primer">Dragon Empires Primer</Link></p>
</blockquote>
</>};
const _tiger_brigadier = {title: "Tiger Brigadier", topLink: ["Regional Traits","main/traits_regional"], jsx: <><h2 id="trait-tiger_brigadier-tiger-brigadier">Tiger Brigadier</h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> Bachuan</p>
<p>As a member of the Tiger Brigade, you are ready to guide the people of Bachuan and other nations. You gain a +2 trait bonus on Intimidate checks made against anyone whose age is one or more aging steps above yours, and Intimidate becomes a class skill for you.</p>
<blockquote>
<p><strong>Sources</strong> <Link to="/source/dragon_empires_primer">Dragon Empires Primer</Link></p>
</blockquote>
</>};
const _touched_by_the_sky = {title: "Touched by the Sky", topLink: ["Regional Traits","main/traits_regional"], jsx: <><h2 id="trait-touched_by_the_sky-touched-by-the-sky">Touched by the Sky</h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> Numeria</p>
<p>Somehow, you managed to retrieve a rare vial of fluid from a piece of crashed wreckage on the plains of Numeria. Before you could be caught with the contraband, you drank it. You now have the ability to stabilize a dying creature with a touch as a standard action.</p>
<blockquote>
<p><strong>Sources</strong> <Link to="/source/inner_sea_primer">Inner Sea Primer</Link></p>
</blockquote>
</>};
const _town_gossip = {title: "Town Gossip", topLink: ["Regional Traits","main/traits_regional"], jsx: <><h2 id="trait-town_gossip-town-gossip">Town Gossip</h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> Varisia</p>
<p>Choose a community that you've lived in for at least 5 years. You gain a +2 trait bonus on Diplomacy checks while in that community.</p>
<blockquote>
<p><strong>Sources</strong> <Link to="/source/varisia_birthplace_of_legends">Varisia, Birthplace of Legends</Link></p>
</blockquote>
</>};
const _trap_savvy = {title: "Trap Savvy", topLink: ["Regional Traits","main/traits_regional"], jsx: <><h2 id="trait-trap_savvy-trap-savvy">Trap Savvy</h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> Darklands</p>
<p>Growing up in a dangerous area, you were constantly surrounded by traps that had been set up to defend your lair from intruders. Sometimes these dangers were so densely packed that you couldn't go more than a couple feet down a tunnel without encountering a new way to die. You gain a +1 trait bonus on Craft (traps) checks, and gain a +1 bonus to AC against attacks by traps or on saving throws against effects created by traps.</p>
<blockquote>
<p><strong>Sources</strong> <Link to="/source/kobolds_of_golarion">Kobolds of Golarion</Link></p>
</blockquote>
</>};
const _treasure_mapper = {title: "Treasure Mapper", topLink: ["Regional Traits","main/traits_regional"], jsx: <><h2 id="trait-treasure_mapper-treasure-mapper">Treasure Mapper</h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> Mediogalti</p>
<p>You've spent a great deal of time hunting down and following treasure maps-most false, but a few with legitimate information. You gain a +2 bonus on Survival or Profession (sailor) checks made to navigate using a map or chart, and one of them becomes a class skill for you.</p>
<blockquote>
<p><strong>Sources</strong> <Link to="/source/pirates_of_the_inner_sea">Pirates of the Inner Sea</Link></p>
</blockquote>
</>};
const _treerazers_bane = {title: "Treerazer's Bane", topLink: ["Regional Traits","main/traits_regional"], jsx: <><h2 id="trait-treerazers_bane-treerazers-bane">Treerazer's Bane</h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> Kyonin</p>
<p>Having fought in many battles against the demon Treerazer, you have learned the best ways to kill the various creatures under his control. You gain a +2 trait bonus on weapon damage against demons, evil fey, and plants and animals corrupted by evil.</p>
<blockquote>
<p><strong>Sources</strong> <Link to="/source/inner_sea_primer">Inner Sea Primer</Link>, <Link to="/source/elves_of_golarion">Elves of Golarion</Link></p>
</blockquote>
</>};
const _trench_navigator = {title: "Trench Navigator", topLink: ["Regional Traits","main/traits_regional"], jsx: <><h2 id="trait-trench_navigator-trench-navigator">Trench Navigator</h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> Xidao</p>
<p>You've sailed the treacherous waters of the Xidao Gulf in your past, and you can navigate their dangers adroitly. You gain a +1 trait bonus on Knowledge (geography) checks, and a +1 trait bonus on Profession (sailor) checks. One of these skills becomes a class skill for you.</p>
<blockquote>
<p><strong>Sources</strong> <Link to="/source/dragon_empires_primer">Dragon Empires Primer</Link></p>
</blockquote>
</>};
const _triaxian_tradition = {title: "Triaxian Tradition", topLink: ["Regional Traits","main/traits_regional"], jsx: <><h2 id="trait-triaxian_tradition-triaxian-tradition">Triaxian Tradition</h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> Triaxus</p>
<p>Your experience with one of the long Triaxian seasons has taught you much about the dangers of a long summer or winter. Choose disease or cold. You gain a +2 trait bonus on saves against spells and spell-like abilities with the chosen descriptor. If you choose disease, you gain the bonus on Fortitude saves against nonmagical diseases as well.</p>
<blockquote>
<p><strong>Sources</strong> <Link to="/source/people_of_the_stars">People of the Stars</Link></p>
</blockquote>
</>};
const _true_name_caller = {title: "True Name Caller", topLink: ["Regional Traits","main/traits_regional"], jsx: <><h2 id="trait-true_name_caller-true-name-caller">True Name Caller</h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> The Abyss</p>
<p>You are skilled at discovering the true names of outsiders. Choose a plane other than the Material Plane. When attempting to discover the true name of an outsider from the chosen plane, you halve the amount of research time required and gain a +4 trait bonus on the Knowledge (planes) check made to learn the outsider's name.</p>
<blockquote>
<p><strong>Sources</strong> <Link to="/source/demon_hunters_handbook">Demon Hunter's Handbook</Link></p>
</blockquote>
</>};
const _tundra_child = {title: "Tundra Child", topLink: ["Regional Traits","main/traits_regional"], jsx: <><h2 id="trait-tundra_child-tundra-child">Tundra Child</h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> tundra or other cold regions</p>
<p>You were born and raised in the cold wastes of the far north or far south, and are accustomed to low temperatures. You gain a +4 trait bonus on saving throws made to resist the effects of being in cold conditions and a +1 trait bonus on saving throws against cold effects.</p>
<blockquote>
<p><strong>Sources</strong> <Link to="/source/ultimate_campaign">Ultimate Campaign</Link></p>
</blockquote>
</>};
const _unafraid = {title: "Unafraid", topLink: ["Regional Traits","main/traits_regional"], jsx: <><h2 id="trait-unafraid-unafraid">Unafraid</h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> Ustalav</p>
<p>The horrors of the fog-shrouded land of terror have hardened you. You receive a +2 bonus on all saving throws made against fear affects.</p>
<blockquote>
<p><strong>Sources</strong> <Link to="/source/orcs_of_golarion">Orcs of Golarion</Link></p>
</blockquote>
</>};
const _underbridge_dweller = {title: "Underbridge Dweller", topLink: ["Regional Traits","main/traits_regional"], jsx: <><h2 id="trait-underbridge_dweller-underbridge-dweller">Underbridge Dweller</h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> Magnimar</p>
<p>You were raised in the Shadow district of Magnimar beneath the Irespan, a veiled place the light of the sun touches for only 3 hours per day. Your well-founded suspicions grant you a +2 trait bonus on Perception checks in dim light, and Perception is always a class skill for you.</p>
<blockquote>
<p><strong>Sources</strong> <Link to="/source/varisia_birthplace_of_legends">Varisia, Birthplace of Legends</Link></p>
</blockquote>
</>};
const _undermarket_smuggler = {title: "Undermarket Smuggler", topLink: ["Regional Traits","main/traits_regional"], jsx: <><h2 id="trait-undermarket_smuggler-undermarket-smuggler">Undermarket Smuggler</h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> Goka</p>
<p>You worked in Goka's Undermarket for a time, and have learned how to dodge the city's tax collectors and the port inspectors. You gain a +1 trait bonus on Bluff and Sleight of Hand checks.</p>
<blockquote>
<p><strong>Sources</strong> <Link to="/source/dragon_empires_primer">Dragon Empires Primer</Link></p>
</blockquote>
</>};
const _unflinching_faith = {title: "Unflinching Faith", topLink: ["Regional Traits","main/traits_regional"], jsx: <><h2 id="trait-unflinching_faith-unflinching-faith">Unflinching Faith</h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> Nidal</p>
<p>Numerous expeditions to accursed regions like Nidal's Finder's Gulch have reinforced your already steadfast faith. Once per day, you may reroll a Will saving throw made against an attack or effect that originates from an undead creature. You must decide to use this trait after the first saving throw is rolled, but before the results are revealed. You must take the result of the second roll, even if it is lower.</p>
<blockquote>
<p><strong>Sources</strong> <Link to="/source/undead_slayers_handbook">Undead Slayer's Handbook</Link></p>
</blockquote>
</>};
const _unstuck = {title: "Unstuck", topLink: ["Regional Traits","main/traits_regional"], jsx: <><h2 id="trait-unstuck-unstuck">Unstuck</h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> Uringen</p>
<p>Spending time in the "unstuck" part of Uringen has made you more adept at using warps in time and space. Increase your caster level by 2 when casting spells with the teleportation descriptor.</p>
<blockquote>
<p><strong>Sources</strong> <Link to="/source/legacy_of_the_first_world">Legacy of the First World</Link></p>
</blockquote>
</>};
const _uskwood_hunter = {title: "Uskwood Hunter", topLink: ["Regional Traits","main/traits_regional"], jsx: <><h2 id="trait-uskwood_hunter-uskwood-hunter">Uskwood Hunter</h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> Nidal</p>
<p>You have served the Umbral Court, discreetly following interlopers through the twilit city streets of Pangolais to pinpoint their locations for the authorities. You gain a +1 trait bonus on Stealth checks, and Stealth is always a class skill for you.</p>
<blockquote>
<p><strong>Sources</strong> <Link to="/source/inner_sea_primer">Inner Sea Primer</Link></p>
</blockquote>
</>};
const _ustalavic_noble = {title: "Ustalavic Noble", topLink: ["Regional Traits","main/traits_regional"], jsx: <><h2 id="trait-ustalavic_noble-ustalavic-noble">Ustalavic Noble</h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> Ustalav</p>
<p>You come from an aristocratic family, though your family has long since lost any power or prestige it once had. You gain a +1 trait bonus on Diplomacy and Knowledge (nobility) checks. In addition, your starting money is increased by 100 gp: your "birthright," such as it is.</p>
<blockquote>
<p><strong>Sources</strong> <Link to="/source/inner_sea_primer">Inner Sea Primer</Link></p>
</blockquote>
</>};
const _uwaga_highlander = {title: "Uwaga Highlander", topLink: ["Regional Traits","main/traits_regional"], jsx: <><h2 id="trait-uwaga_highlander-uwaga-highlander">Uwaga Highlander</h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> Katapesh</p>
<p>You were born and raised in western Katapesh, in the rugged badlands and hills of the Uwaga Highlands. Even if you were born in a city like Solku, you often had to travel the dangerous trails with your family. Predators, gnolls, and worse haunt the Uwaga Highlands, and you've become something of an expert at evading them. You gain a +1 trait bonus on Stealth checks. This trait bonus increases to +2 in hilly or rocky areas.</p>
<blockquote>
<p><strong>Sources</strong> <Link to="/source/legacy_of_fire_players_guide">Legacy of Fire Player's Guide</Link></p>
</blockquote>
</>};
const _vagabond_child = {title: "Vagabond Child", topLink: ["Regional Traits","main/traits_regional"], jsx: <><h2 id="trait-vagabond_child-vagabond-child">Vagabond Child</h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> urban</p>
<p>You grew up among the outcasts and outlaws of your society, learning to forage and survive in an urban environment. Select one of the following skills: Disable Device, Escape Artist, or Sleight of Hand. You gain a +1 trait bonus on checks with that skill, and it is always a class skill for you.</p>
<blockquote>
<p><strong>Sources</strong> <Link to="/source/ultimate_campaign">Ultimate Campaign</Link>, <Link to="/source/taldor_echoes_of_glory">Taldor, Echoes of Glory</Link>, <Link to="/source/advanced_players_guide">Advanced Player's Guide</Link></p>
</blockquote>
</>};
const _valashmai_veteran = {title: "Valashmai Veteran", topLink: ["Regional Traits","main/traits_regional"], jsx: <><h2 id="trait-valashmai_veteran-valashmai-veteran">Valashmai Veteran</h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> Valashmai Jungle</p>
<p>You have traveled to the Valashmai Jungle on numerous occasions, and your prowess in traversing the jungle wilderness makes you a formidable guide and explorer. You gain a +1 trait bonus on Perception checks, and a +1 trait bonus on Survival checks in jungle terrain. One of these skills becomes a class skill for you.</p>
<blockquote>
<p><strong>Sources</strong> <Link to="/source/dragon_empires_primer">Dragon Empires Primer</Link></p>
</blockquote>
</>};
const _valknar_alumnus = {title: "Valknar Alumnus", topLink: ["Regional Traits","main/traits_regional"], jsx: <><h2 id="trait-valknar_alumnus-valknar-alumnus">Valknar Alumnus</h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> Tymon</p>
<p>You trained at the exclusive Valknar Gladiatorial College. Select one combat maneuver when you take this trait. You gain a +1 trait bonus on performance combat checks and a +1 trait bonus on combat maneuver checks to perform the selected maneuver.</p>
<blockquote>
<p><strong>Sources</strong> <Link to="/source/people_of_the_river">People of the River</Link></p>
</blockquote>
</>};
const _varisian_wanderer = {title: "Varisian Wanderer", topLink: ["Regional Traits","main/traits_regional"], jsx: <><h2 id="trait-varisian_wanderer-varisian-wanderer">Varisian Wanderer</h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> Varisia</p>
<p>You were raised among or have spent time with a group of Varisian nomads, whether travelers, Sczarni criminals, or entertainers, and have learned their ways. Choose one of the following skills: Perform (choose one type), Profession (fortune-teller), or Sleight of Hand. You gain a +1 trait bonus on this skill, and it is always a class skill for you.</p>
<blockquote>
<p><strong>Sources</strong> <Link to="/source/inner_sea_primer">Inner Sea Primer</Link></p>
</blockquote>
</>};
const _venicaan_medic = {title: "Venicaan Medic", topLink: ["Regional Traits","main/traits_regional"], jsx: <><h2 id="trait-venicaan_medic-venicaan-medic">Venicaan Medic</h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> Qadira</p>
<p>You have studied at the College of Medicaments and Chirurgery, and know by sight the signs of ailments and toxins you might encounter. You gain a +2 trait bonus to Heal checks to treat diseases or poisons, and Heal is always a class skill for you.</p>
<blockquote>
<p><strong>Sources</strong> <Link to="/source/qadira_gateway_to_the_east">Qadira, Gateway to the East</Link></p>
</blockquote>
</>};
const _vialesk_historian = {title: "Vialesk Historian", topLink: ["Regional Traits","main/traits_regional"], jsx: <><h2 id="trait-vialesk_historian-vialesk-historian">Vialesk Historian</h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> Plane of Water</p>
<p>Your long years of studious research into the drifting trade city of Vialesk, a neutral ground for planar travelers on the Elemental Plane of Water, has made you an expert on all manner of aquatic creatures. You gain a +2 trait bonus on Knowledge (planes) checks to identify outsiders with the water subtype. In addition, you treat your caster level as 1 higher when casting conjuration (summoning) spells to summon outsiders with the water subtype.</p>
<blockquote>
<p><strong>Sources</strong> <Link to="/source/blood_of_the_elements">Blood of the Elements</Link></p>
</blockquote>
</>};
const _viking_blood = {title: "Viking Blood", topLink: ["Regional Traits","main/traits_regional"], jsx: <><h2 id="trait-viking_blood-viking-blood">Viking Blood</h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> Lands of the Linnorm Kings</p>
<p>You have the imposing build of a Viking, and people of the south fear your unpredictable nature. You gain a +1 trait bonus on Intimidate checks, and Intimidate is always a class skill for you.</p>
<blockquote>
<p><strong>Sources</strong> <Link to="/source/inner_sea_primer">Inner Sea Primer</Link></p>
</blockquote>
</>};
const _voices_of_solid_things = {title: "Voices of Solid Things", topLink: ["Regional Traits","main/traits_regional"], jsx: <><h2 id="trait-voices_of_solid_things-voices-of-solid-things">Voices of Solid Things</h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> Witchmarket</p>
<p>You traveled with the Witchmarket for a time, either willingly or as a result of a bargain made by some other buyer. In your time in the Witchmarket, you learned to listen to the whispers of items as though they were living creatures, giving you clues as to their function. Choose Appraise, Craft, Disable Device, or Spellcraft. You apply your Charisma modifier on checks with that skill instead of the skill's normal ability score. That skill is a class skill for you.</p>
<blockquote>
<p><strong>Sources</strong> <Link to="/source/legacy_of_the_first_world">Legacy of the First World</Link></p>
</blockquote>
</>};
const _void_child = {title: "Void Child", topLink: ["Regional Traits","main/traits_regional"], jsx: <><h2 id="trait-void_child-void-child">Void Child</h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> Diaspora</p>
<p>You were raised in the Diaspora and are accustomed to being isolated from most other life in the vast void of space. You gain a +1 trait bonus on saves against fear; this bonus increases to +2 whenever you are 30 feet or farther from your nearest ally.</p>
<blockquote>
<p><strong>Sources</strong> <Link to="/source/people_of_the_stars">People of the Stars</Link></p>
</blockquote>
</>};
const _walking_ward = {title: "Walking Ward", topLink: ["Regional Traits","main/traits_regional"], jsx: <><h2 id="trait-walking_ward-walking-ward">Walking Ward</h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> Qadira</p>
<p>Your training included constant exposure to elemental forces. Choose one of the following energy types: acid, cold, electricity, or fire; you gain a +1 bonus on saving throws against spells that deal damage of this type or have this subtype.</p>
<blockquote>
<p><strong>Sources</strong> <Link to="/source/qadira_gateway_to_the_east">Qadira, Gateway to the East</Link></p>
</blockquote>
</>};
const _wardbreaker = {title: "Wardbreaker", topLink: ["Regional Traits","main/traits_regional"], jsx: <><h2 id="trait-wardbreaker-wardbreaker">Wardbreaker</h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> The Worldwound</p>
<p>You have studied techniques designed to pierce magical protections, with the goal of assisting your Abyssal masters in bringing down the wardstones that guard the borders of Mendev. Once per day, you can attempt a melee touch attack against an opponent that you believe has a deflection bonus to AC. If your attack is successful, your foe's deflection bonus to AC is halved (to a minimum of +0) for a number of rounds equal to your Charisma modifier. You can use this ability twice per day at 10th level and three times per day at 20th level.</p>
<blockquote>
<p><strong>Sources</strong> <Link to="/source/champions_of_corruption">Champions of Corruption</Link></p>
</blockquote>
</>};
const _warrior_poet = {title: "Warrior Poet", topLink: ["Regional Traits","main/traits_regional"], jsx: <><h2 id="trait-warrior_poet-warrior-poet">Warrior Poet</h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> Lands of the Linnorm Kings</p>
<p>You were trained by the skalds, keepers of the oral tradition of Kalsgard. You gain a +1 trait bonus on Knowledge checks related to dwarves (dwarven history, dwarven construction, and so on) and a +1 trait bonus on Fortitude saves in any round in which you use a bardic performance ability.</p>
<blockquote>
<p><strong>Sources</strong> <Link to="/source/dwarves_of_golarion">Dwarves of Golarion</Link></p>
</blockquote>
</>};
const _wary_potr = {title: "Wary (PotR)", topLink: ["Regional Traits","main/traits_regional"], jsx: <><h2 id="trait-wary_potr-wary-potr">Wary (PotR)</h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> Daggermark</p>
<p>You survived an assassination attempt once. You gain a +1 trait bonus on opposed Perception and Sense Motive checks. One of these skills is always a class skill for you.</p>
<blockquote>
<p><strong>Sources</strong> <Link to="/source/people_of_the_river">People of the River</Link></p>
</blockquote>
</>};
const _watching_taldor = {title: "Watching Taldor", topLink: ["Regional Traits","main/traits_regional"], jsx: <><h2 id="trait-watching_taldor-watching-taldor">Watching Taldor</h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> Qadira<br/><strong>Requirements:</strong> Characters from Qadira who have had family members, neighbors, or friends affected by Taldan aggression or who have fallen victim to this hatred themselves.</p>
<p>You have spent your adult life waiting for Taldor to give you an excuse to fight. You gain a +1 trait bonus on initiative checks, and if you are able to act during the surprise round of an encounter, you can draw a weapon (but not a potion or magic item) as a free action during that round.</p>
<blockquote>
<p><strong>Sources</strong> <Link to="/source/qadira_jewel_of_the_east">Qadira, Jewel of the East</Link>, <Link to="/source/qadira_gateway_to_the_east">Qadira, Gateway to the East</Link></p>
</blockquote>
</>};
const _water_brave = {title: "Water Brave", topLink: ["Regional Traits","main/traits_regional"], jsx: <><h2 id="trait-water_brave-water-brave">Water Brave</h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> River Kingdoms</p>
<p>Travel through the dangerous waters of the River Kingdoms has given your tribe special skills in relation to them. You receive a +1 trait bonus on Swim checks, and it becomes a class skill.</p>
<blockquote>
<p><strong>Sources</strong> <Link to="/source/orcs_of_golarion">Orcs of Golarion</Link></p>
</blockquote>
</>};
const _wayang_spellhunter = {title: "Wayang Spellhunter", topLink: ["Regional Traits","main/traits_regional"], jsx: <><h2 id="trait-wayang_spellhunter-wayang-spellhunter">Wayang Spellhunter</h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> Minata</p>
<p>You grew up on one of the wayang-populated islands of Minata, and your use of magic while hunting has been a boon to you. Select a spell of 3rd level or below. When you use this spell with a metamagic feat, it uses up a spell slot one level lower than it normally would.</p>
<blockquote>
<p><strong>Sources</strong> <Link to="/source/dragon_empires_primer">Dragon Empires Primer</Link></p>
</blockquote>
</>};
const _wealthy_dabbler = {title: "Wealthy Dabbler", topLink: ["Regional Traits","main/traits_regional"], jsx: <><h2 id="trait-wealthy_dabbler-wealthy-dabbler">Wealthy Dabbler</h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> Taldor</p>
<p>You study magic at one of Taldor's many social clubs, wowing your friends with your expertise in the simplest of magical exploits. Select two non-harmful arcane cantrips. You can cast these two cantrips once per day each (caster level 1st). If you have levels in a class that can cast these cantrips, your caster level for these cantrips is equal to that class level.</p>
<blockquote>
<p><strong>Sources</strong> <Link to="/source/inner_sea_primer">Inner Sea Primer</Link>, <Link to="/source/taldor_echoes_of_glory">Taldor, Echoes of Glory</Link></p>
</blockquote>
</>};
const _weed_resistance = {title: "Weed Resistance", topLink: ["Regional Traits","main/traits_regional"], jsx: <><h2 id="trait-weed_resistance-weed-resistance">Weed Resistance</h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> Kyonin</p>
<p>You have learned how to keep your flesh out of the way of the toxic thorns and vines that are often prevalent in verdant lands. You gain a +3 trait bonus on saving throws against poison and disease abilities and effects inflicted by creatures of the plant type (such as a basidirond's spores).</p>
<blockquote>
<p><strong>Sources</strong> <Link to="/source/potions_and_poisons">Potions and Poisons</Link></p>
</blockquote>
</>};
const _well_bred = {title: "Well Bred", topLink: ["Regional Traits","main/traits_regional"], jsx: <><h2 id="trait-well_bred-well-bred">Well Bred</h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> Hermea</p>
<p>You are the product of generations of selective breeding, organized by the gold dragon Mengkare. Your education is top-notch, and you have a broad base of knowledge. Unfortunately, the isolation of Hermea has also made you slightly naive. You gain a +1 trait bonus on Knowledge (history) and Knowledge (religion) checks but take a -1 penalty on all Sense Motive checks.</p>
<blockquote>
<p><strong>Sources</strong> <Link to="/source/dragonslayers_handbook">Dragonslayer's Handbook</Link></p>
</blockquote>
</>};
const _wharf_rat = {title: "Wharf Rat", topLink: ["Regional Traits","main/traits_regional"], jsx: <><h2 id="trait-wharf_rat-wharf-rat">Wharf Rat</h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> Ostenso</p>
<p>You may never have been on a boat larger than a garbage scow, but you've been helping them dock all your life. You gain a +2 trait bonus on skill checks involving climbing and rope use, and a +4 trait bonus on Appraise checks to determine the value of large quantities of bulk goods without opening their containers.</p>
<blockquote>
<p><strong>Sources</strong> <Link to="/source/cheliax_empire_of_devils">Cheliax, Empire of Devils</Link></p>
</blockquote>
</>};
const _whip_specialist = {title: "Whip Specialist", topLink: ["Regional Traits","main/traits_regional"], jsx: <><h2 id="trait-whip_specialist-whip-specialist">Whip Specialist</h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> Okeno</p>
<p>Your time spent lashing slaves has taught you how to get the most out of a whip. You deal +1 point of damage on all attacks made with a whip.</p>
<blockquote>
<p><strong>Sources</strong> <Link to="/source/pirates_of_the_inner_sea">Pirates of the Inner Sea</Link></p>
</blockquote>
</>};
const _whisper_woods_hunter = {title: "Whisper Woods Hunter", topLink: ["Regional Traits","main/traits_regional"], jsx: <><h2 id="trait-whisper_woods_hunter-whisper-woods-hunter">Whisper Woods Hunter</h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> Whisper Woods</p>
<p>Your family prepared you for a life of evading or destroying fiendish creatures. You gain a +2 trait bonus on Survival checks to track evil outsiders and a +2 trait bonus on initiative checks when you know your opponent is an evil outsider.</p>
<blockquote>
<p><strong>Sources</strong> <Link to="/source/cheliax_empire_of_devils">Cheliax, Empire of Devils</Link></p>
</blockquote>
</>};
const _whitethrone_gourmand = {title: "Whitethrone Gourmand", topLink: ["Regional Traits","main/traits_regional"], jsx: <><h2 id="trait-whitethrone_gourmand-whitethrone-gourmand">Whitethrone Gourmand</h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> Irrisen</p>
<p>You grew up privileged in the city of Whitethrone, and indulged in many exotic and unnerving pleasures. You gain a +1 trait bonus on saves against any effect causing the nauseated or sickened condition and against all ingested poisons.</p>
<blockquote>
<p><strong>Sources</strong> <Link to="/source/people_of_the_north">People of the North</Link></p>
</blockquote>
</>};
const _whole_hearted = {title: "Whole-Hearted", topLink: ["Regional Traits","main/traits_regional"], jsx: <><h2 id="trait-whole_hearted-whole-hearted">Whole-Hearted</h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> Averaka</p>
<p>Though most outsiders expect your mind to be conflicted, full of self-doubt, and mired in resentment and suspicion, you're truly comfortable in your skin. You gain a +2 trait bonus on saving throws against charms and compulsions.</p>
<blockquote>
<p><strong>Sources</strong> <Link to="/source/bastards_of_golarion">Bastards of Golarion</Link></p>
</blockquote>
</>};
const _wild_wanderer = {title: "Wild Wanderer", topLink: ["Regional Traits","main/traits_regional"], jsx: <><h2 id="trait-wild_wanderer-wild-wanderer">Wild Wanderer</h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> Mwangi Expanse</p>
<p>You're a child of the wild, living on your own without need of others. Each time you attempt a Survival check to get along in the wild or resist severe weather, you can choose to gain a +4 trait bonus on that check. If you do so, you can't use that check to provide assistance to others, even if your result exceeds the DC.</p>
<blockquote>
<p><strong>Sources</strong> <Link to="/source/advanced_class_origins">Advanced Class Origins</Link></p>
</blockquote>
</>};
const _windspeaker = {title: "Windspeaker", topLink: ["Regional Traits","main/traits_regional"], jsx: <><h2 id="trait-windspeaker-windspeaker">Windspeaker</h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> desert</p>
<p>You have a keen sense for weather patterns, and you always know 8 hours in advance when naturally occurring winds will reach high speeds.</p>
<blockquote>
<p><strong>Sources</strong> <Link to="/source/wilderness_origins">Wilderness Origins</Link></p>
</blockquote>
</>};
const _winners_luck = {title: "Winner's Luck", topLink: ["Regional Traits","main/traits_regional"], jsx: <><h2 id="trait-winners_luck-winners-luck">Winner's Luck</h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> Riddleport</p>
<p>Winning at the tables in Riddleport's gambling houses can be as devastating as losing. Years of dodging the jealous blows of card table patrons have given you a sixth sense for when your luck is about to run out. Whenever you succeed at a Reflex saving throw, you may draw a weapon as an immediate action, or a hidden weapon as a move action.</p>
<blockquote>
<p><strong>Sources</strong> <Link to="/source/varisia_birthplace_of_legends">Varisia, Birthplace of Legends</Link></p>
</blockquote>
</>};
const _winter_warrior = {title: "Winter Warrior", topLink: ["Regional Traits","main/traits_regional"], jsx: <><h2 id="trait-winter_warrior-winter-warrior">Winter Warrior</h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> Irrisen</p>
<p>You grew up in the icy lands of Irrisen, and surviving in the cold snows of winter is second nature to you. You gain a +1 trait bonus on Stealth and Survival checks in ice- or snow-covered terrain.</p>
<blockquote>
<p><strong>Sources</strong> <Link to="/source/inner_sea_primer">Inner Sea Primer</Link></p>
</blockquote>
</>};
const _winters_soul = {title: "Winter's Soul", topLink: ["Regional Traits","main/traits_regional"], jsx: <><h2 id="trait-winters_soul-winters-soul">Winter's Soul</h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> Irrisen</p>
<p>The eternal winter of Irrisen is as much a part of you as it is the land. You may cast <Link to="/spell/ray_of_frost">ray of frost</Link> once per day as a spell-like ability. This is cast at your highest caster level gained; if you have no caster level, it functions at CL 1st.</p>
<blockquote>
<p><strong>Sources</strong> <Link to="/source/inner_sea_primer">Inner Sea Primer</Link></p>
</blockquote>
</>};
const _witch_tongued = {title: "Witch-Tongued", topLink: ["Regional Traits","main/traits_regional"], jsx: <><h2 id="trait-witch_tongued-witch-tongued">Witch-Tongued</h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> Irrisen</p>
<p>Hailing from frozen Irrisen, where witches rule the land, you deal with others in a cool, calculated way. You gain a +1 trait bonus on Diplomacy checks, and you gain a +1 trait bonus on Intimidate checks against non-witches.</p>
<blockquote>
<p><strong>Sources</strong> <Link to="/source/blood_of_the_coven">Blood of the Coven</Link></p>
</blockquote>
</>};
const _xa_hoi_soldier = {title: "Xa Hoi Soldier", topLink: ["Regional Traits","main/traits_regional"], jsx: <><h2 id="trait-xa_hoi_soldier-xa-hoi-soldier">Xa Hoi Soldier</h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> Xa Hoi</p>
<p>You were a soldier in one of Xa Hoi's extensive armies, trained under the oversight of one of Pham Duc Quan's draconic brethren. You gain a +1 trait bonus on Reflex saves.</p>
<blockquote>
<p><strong>Sources</strong> <Link to="/source/dragon_empires_primer">Dragon Empires Primer</Link></p>
</blockquote>
</>};
